import type { BibleItem } from '../bible-content';

export const genesis: Record<string, BibleItem[]> = {
  "1": [
    { type: "section", text: "सृष्टीची कथा" },
    { type: "verse", num: 1, text: "सुरवातेक देवान ससर्ग आनी पृथ्वी घडयली." },
    { type: "verse", num: 2, text: "आनी पृथ्वी रुपा बगर आनी रिती आसली; आनी अंधकार खोल जाग्याचेर आसलो. आनी देवाचो आत्मो उदकांचेर वावुरतालो." },
    { type: "verse", num: 3, text: "आनी देवान म्हणलें, 'उजवाड जांव'; आनी उजवाड जालो." },
    { type: "verse", num: 4, text: "आनी देवान उजवाड पळयलो, तो बरो म्हूण; आनी देवान उजवाडाक काळखापसून वेगळो केलो." },
    { type: "verse", num: 5, text: "आनी देवान उजवाडाक 'दीस' म्हणलें, आनी काळखाक 'रात' म्हणलें. आनी सांज जाली आनी सकाळ जाली — पयलो दीस." },
    { type: "verse", num: 6, text: "आनी देवान म्हणलें, 'उदकांमदीं एक अंतरीक्ष जांव, आनी उदकांक उदकांपसून वेगळें करूं.'" },
    { type: "verse", num: 7, text: "आनी देवान अंतरीक्ष केलें, आनी अंतरीक्षासकयलीं उदकां अंतरीक्षावयलीं उदकांपसून वेगळीं केलीं; आनी तशें जालें." },
    { type: "verse", num: 8, text: "आनी देवान अंतरीक्षाक 'मळब' म्हणलें. आनी सांज जाली आनी सकाळ जाली — दुसरो दीस." },
    { type: "verse", num: 9, text: "आनी देवान म्हणलें, 'मळबासकयलीं उदकां एका जाग्यार एकठांय जांवदीत, आनी सुकी धरण दिसूंदी'; आनी तशें जालें." },
    { type: "verse", num: 10, text: "आनी देवान सुक्या धरणीक 'पृथ्वी' म्हणलें, आनी उदकांच्या एकठांयपणाक 'दर्या' म्हणलें; आनी देवान पळयलें की तें बरें." },
    { type: "verse", num: 11, text: "आनी देवान म्हणलें, 'पृथ्वीन तण, बियो दिवपी वखद आनी फळझाडां तांच्या जातीप्रमाणें फळ दिवपी, ज्यांचें बीय तांचेच थंय आसा, पृथ्वीचेर उगोवंदीत'; आनी तशें जालें." },
    { type: "verse", num: 12, text: "आनी पृथ्वीन तण, बियो दिवपी वखद ताच्या जातीप्रमाणें, आनी फळ दिवपी झाडां, ज्यांचें बीय तांचेच थंय ताच्या जातीप्रमाणें आसा, उगयलीं; आनी देवान पळयलें की तें बरें." },
    { type: "verse", num: 13, text: "आनी सांज जाली आनी सकाळ जाली — तिसरो दीस." },
    { type: "verse", num: 14, text: "आनी देवान म्हणलें, 'दिसाक रातीपसून वेगळो करपाक मळबाच्या अंतरीक्षांत उजवाड जांवदीत; आनी ते चिन्नां आनी ऋतू आनी दीस आनी वर्सां हांचे खातीर आसूंदीत.'" },
    { type: "verse", num: 15, text: "आनी ते मळबाच्या अंतरीक्षांत पृथ्वीचेर उजवाड दिवपाक उजवाड आसूंदीत; आनी तशें जालें." },
    { type: "verse", num: 16, text: "आनी देवान दोन व्हड उजवाड केले; व्हड उजवाड दिसाचेर राज करपाक, आनी ल्हान उजवाड रातीचेर राज करपाक; आनी नखेत्रांय केलीं." },
    { type: "verse", num: 17, text: "आनी देवान तांकां मळबाच्या अंतरीक्षांत दवरलीं, पृथ्वीचेर उजवाड दिवपाक." },
    { type: "verse", num: 18, text: "आनी दिसाचेर आनी रातीचेर राज करपाक, आनी उजवाडाक काळखापसून वेगळो करपाक; आनी देवान पळयलें की तें बरें." },
    { type: "verse", num: 19, text: "आनी सांज जाली आनी सकाळ जाली — चवथो दीस." },
    { type: "verse", num: 20, text: "आनी देवान म्हणलें, 'उदकांनी जिवीत जीव भरपूर उगोवंदीत, आनी सुकणीं पृथ्वीचेर मळबाच्या अंतरीक्षांत उडूंदीत.'" },
    { type: "verse", num: 21, text: "आनी देवान व्हड दर्यांतलीं जनावरां आनी उदकांनी भरपूर जाल्लो दरेक जिवो जंतू ताच्या जातीप्रमाणें, आनी दरेक पाखां आशिल्लें सुकणें ताच्या जातीप्रमाणें रचलें; आनी देवान पळयलें की तें बरें." },
    { type: "verse", num: 22, text: "आनी देवान तांकां आशीर्वाद दिलो आनी म्हणलें, 'फळां दियात आनी वाडात आनी दर्यांतलीं उदकां भरात, आनी सुकण्यांनी पृथ्वीचेर वाडचें.'" },
    { type: "verse", num: 23, text: "आनी सांज जाली आनी सकाळ जाली — पांचवो दीस." },
    { type: "verse", num: 24, text: "आनी देवान म्हणलें, 'पृथ्वीन जिवी जीव ताच्या जातीप्रमाणें, गोरवां, सरपटपी जीव आनी रानवटीं जनावरां ताच्या जातीप्रमाणें उगोवंदीत'; आनी तशें जालें." },
    { type: "verse", num: 25, text: "आनी देवान रानवटीं जनावरां ताच्या जातीप्रमाणें, आनी गोरवां ताच्या जातीप्रमाणें, आनी पृथ्वीचेर सरपटपी सगळें ताच्या जातीप्रमाणें केलें; आनी देवान पळयलें की तें बरें." },
    { type: "section", text: "मनशाची रचणूक" },
    { type: "verse", num: 26, text: "आनी देवान म्हणलें, 'आमी मनशाक आमच्या प्रतिमेप्रमाणें, आमच्या सारकेपणान रचूया; आनी तांणीं दर्यांतल्या मासळ्यांचेर आनी मळबांतल्या सुकण्यांचेर आनी गोरवांचेर आनी सगळ्या पृथ्वीचेर आनी पृथ्वीचेर सरपटपी सगळ्या जिवांचेर राज करचें.'" },
    { type: "verse", num: 27, text: "देवान मनशाक आपल्या प्रतिमेप्रमाणें रचलो; देवाच्या प्रतिमेप्रमाणें ताणें ताका रचलो; दादलो आनी बायल ताणें तांकां रचलीं." },
    { type: "verse", num: 28, text: "आनी देवान तांकां आशीर्वाद दिलो, आनी देवान तांकां म्हणलें, 'फळां दियात आनी वाडात, आनी पृथ्वी भरात आनी ती आपल्या हाताखाला हाडात; आनी दर्यांतल्या मासळ्यांचेर आनी मळबांतल्या सुकण्यांचेर आनी पृथ्वीचेर चलपी दरेक जिवाचेर राज करात.'" },
    { type: "verse", num: 29, text: "आनी देवान म्हणलें, 'पळयात, सगळ्या पृथ्वीचेर आशिल्लें बियो दिवपी दरेक वखद, आनी बियो दिवपी फळ आशिल्लें दरेक झाड हांव तुमकां दिलां; तें तुमकां खावपाक आसतलें.'" },
    { type: "verse", num: 30, text: "आनी पृथ्वीच्या सगळ्या जनावरांक, आनी मळबांतल्या सगळ्या सुकण्यांक, आनी पृथ्वीचेर सरपटपी सगळ्या जिवांक, ज्यांचे थंय जिविताचो स्वास आसा, खावपाक दरेक पाचवें वखद दिलां; आनी तशें जालें." },
    { type: "verse", num: 31, text: "आनी देवान आपणें केल्लें सगळें पळयलें, आनी पळय, तें खूब बरें आसलें. आनी सांज जाली आनी सकाळ जाली — सवो दीस." },
  ],
  "2": [
    { type: "section", text: "विसव घेवपाचो दीस" },
    { type: "verse", num: 1, text: "अशें ससर्ग आनी पृथ्वी आनी तांचें सगळें सैन्य पुरें जालें." },
    { type: "verse", num: 2, text: "आनी सातव्या दिसा देवान आपलें काम, जें ताणें केल्लें, पुरें केलें; आनी सातव्या दिसा आपल्या सगळ्या कामापसून विसव घेतलो." },
    { type: "verse", num: 3, text: "आनी देवान सातव्या दिसाक आशीर्वाद दिलो आनी ताका पवित्र केलो; कारण ताचे थंय देवान आपल्या सगळ्या कामापसून विसव घेतलो, जें ताणें रचून केल्लें." },
    { type: "section", text: "एदेन बागेंत आदांव आनी एवा" },
    { type: "verse", num: 4, text: "ससर्ग आनी पृथ्वीच्या उत्पत्तीची गजाल अशी: ज्या दिसा सर्वेस्पर देवान पृथ्वी आनी ससर्ग केलो." },
    { type: "verse", num: 5, text: "आनी शेतांतलें कसलेंच वखद अजून पृथ्वीचेर नासलें, आनी शेतांतलें कसलेंच तण अजून उगवूंक नासलें; कारण सर्वेस्पर देवान पृथ्वीचेर पावस धाडूंक नासलो, आनी भुंय लागवड करपाक मनीस नासलो." },
    { type: "verse", num: 6, text: "पूण पृथ्वीतल्यान धुवर वयर यातालो आनी सगळी भुंय भिजयतालो." },
    { type: "verse", num: 7, text: "आनी सर्वेस्पर देवान भुंयच्या मातयेपसून मनशाक घडयलो, आनी ताच्या नाकांत जिविताचो स्वास फुंकलो; आनी मनीस जिवो प्राणी जालो." },
    { type: "verse", num: 8, text: "आनी सर्वेस्पर देवान उदेंतेक एदेनांत एक बाग लायली; आनी थंय ताणें आपणें घडयिल्ल्या मनशाक दवरलो." },
    { type: "verse", num: 9, text: "आनी सर्वेस्पर देवान भुंयेतल्यान दरेक झाड उगयलें, जें दिसपाक सोबीत आनी खावपाक बरें; आनी बागेच्या मदीं जिविताचें झाड आनी बऱ्या आनी वायटाच्या गिन्यानाचें झाड." },
    { type: "verse", num: 10, text: "आनी एदेनांतल्यान एक न्हंय बागेक भिजोवपाक व्हांवतालो; आनी थंयसून ती चार फांट्यांनी वांटली गेली." },
    { type: "verse", num: 11, text: "पयल्याचें नांव पीशोन; तो सगळो हवीला देस भोंवता, जंय भांगर आसा." },
    { type: "verse", num: 12, text: "आनी त्या देसांतलें भांगर बरें आसा; थंय गोमेद फातर आनी बदोलख आसा." },
    { type: "verse", num: 13, text: "आनी दुसऱ्या न्हंयेचें नांव गीहोन; तो सगळो कूश देस भोंवता." },
    { type: "verse", num: 14, text: "आनी तिसऱ्या न्हंयेचें नांव हिद्देकेल; ती अश्शूर देसाच्या उदेंतेक व्हांवता. आनी चवथी न्हंय फरात." },
    { type: "verse", num: 15, text: "आनी सर्वेस्पर देवान मनशाक घेतलो आनी एदेन बागेंत ताका दवरलो, ती लागवड करपाक आनी तिची राखण करपाक." },
    { type: "verse", num: 16, text: "आनी सर्वेस्पर देवान मनशाक आज्ञा दिली, 'बागेंतल्या दरेक झाडाचें फळ तूं खुशाल खा;'" },
    { type: "verse", num: 17, text: "'पूण बऱ्या आनी वायटाच्या गिन्यानाच्या झाडाचें तूं खावंका नाका; कारण ज्या दिसा तूं ताचें खातलो त्या दिसा तूं खात्रीन मरतलो.'" },
    { type: "verse", num: 18, text: "आनी सर्वेस्पर देवान म्हणलें, 'मनीस एकलो आसचो तें बरें न्हय; हांव ताका ताचे सारको आदार करतलों.'" },
    { type: "verse", num: 19, text: "आनी सर्वेस्पर देवान भुंयेपसून शेतांतलें दरेक जनावर आनी मळबांतलें दरेक सुकणें घडयलें; आनी मनशान तांकां कसलें नांव दिवचें तें पळोवपाक तांकां ताचेकडेन हाडलें; आनी मनशान दरेक जिव्या प्राण्याक जें नांव दिलें तें ताचें नांव." },
    { type: "verse", num: 20, text: "आनी मनशान सगळ्या गोरवांक, आनी मळबांतल्या सुकण्यांक, आनी सगळ्या रानवटीं जनावरांक नांवां दिलीं; पूण आदांवाक ताचे सारको आदार मेळूंक ना." },
    { type: "verse", num: 21, text: "आनी सर्वेस्पर देवान मनशाचेर गाढ न्हीद हाडली, आनी तो न्हिदलो; आनी ताणें ताची एक बरगडी काडली आनी तिचे सुवातेर मांस भरलें." },
    { type: "verse", num: 22, text: "आनी मनशापसून काडिल्ल्या बरगडीपसून सर्वेस्पर देवान एक बायल घडयली, आनी तिका मनशाकडेन हाडली." },
    { type: "verse", num: 23, text: "आनी मनशान म्हणलें, 'ही आतां म्हज्या हाडांचें हाड आनी म्हज्या मांसाचें मांस; हिका 'नारी' म्हणतले, कारण ती 'नरा'पसून काडली.'" },
    { type: "verse", num: 24, text: "देखून मनीस आपल्या बापायक आनी आवयक सोडटलो आनी आपल्या बायलेक चिकटून रावतलो; आनी ते एक मांस जातले." },
    { type: "verse", num: 25, text: "आनी ते दोगूय, मनीस आनी ताची बायल, उघडे आसले आनी तांकां लज नासली." },
  ],
  "3": [
    { type: "section", text: "मनशाचें पतन" },
    { type: "verse", num: 1, text: "सर्वेस्पर देवान केल्ल्या सगळ्या रानवटीं जनावरांमदीं सोरोप सगळ्यांत चतुर आसलो. ताणें बायलेक म्हणलें, 'देवान खरेंच म्हणलां, बागेंतल्या कसल्याच झाडाचें फळ तुमी खावंका नाका?'" },
    { type: "verse", num: 2, text: "आनी बायलेन सोरपाक म्हणलें, 'बागेंतल्या झाडांचीं फळां आमी खावंक शकतात;'" },
    { type: "verse", num: 3, text: "'पूण बागेच्या मदल्या झाडाच्या फळाविशीं देवान म्हणलां, ताचें खावंका नाका, ताका लागूंकय नाका, नाजाल्यार तुमी मरतलात.'" },
    { type: "verse", num: 4, text: "आनी सोरपान बायलेक म्हणलें, 'तुमी खात्रीन मरचीं ना;'" },
    { type: "verse", num: 5, text: "'कारण देव जाणा, ज्या दिसा तुमी ताचें खातलात, त्या दिसा तुमचे दोळे उगते जातले, आनी तुमी देवांसारके जातलात, बरें आनी वायट जाणटले.'" },
    { type: "verse", num: 6, text: "आनी बायलेन पळयलें की झाड खावपाक बरें, आनी दोळ्यांक सोबीत, आनी शाणेपण दिवपाक मोहक; आनी तिणें ताचें फळ काडलें आनी खालें, आनी आपल्या घोवाकूय दिलें जो तिचेकडेन आसलो; आनी ताणेंय खालें." },
    { type: "verse", num: 7, text: "आनी तांच्या दोगांयच्या दोळ्यांक दिसलें, आनी ते उघडे आसात म्हूण तांकां कळलें; आनी तांणीं अंजुराचीं पानां शिवून आपल्याक आवरणां केलीं." },
    { type: "verse", num: 8, text: "आनी दिसाच्या थंड वाऱ्यांत सर्वेस्पर देवाचो आवाज तांणीं बागेंत चलतना आयकलो; आनी मनीस आनी ताची बायल बागेंतल्या झाडांमदीं सर्वेस्पर देवाच्या मुखापसून लिपलीं." },
    { type: "verse", num: 9, text: "आनी सर्वेस्पर देवान मनशाक आपयलो आनी ताका म्हणलें, 'तूं खंय आसा?'" },
    { type: "verse", num: 10, text: "आनी ताणें म्हणलें, 'बागेंत तुजो आवाज हांवें आयकलो, आनी हांव भियेलों, कारण हांव उघडो आसां; आनी हांव लिपलों.'" },
    { type: "verse", num: 11, text: "आनी ताणें म्हणलें, 'तूं उघडो आसा म्हूण तुका कोणें सांगलें? जें खावंका नाका म्हूण हांवें तुका आज्ञा दिल्ली, त्या झाडाचें तूं खालें?'" },
    { type: "verse", num: 12, text: "आनी मनशान म्हणलें, 'जी बायल तूं म्हजेकडेन दवरली, तिणें म्हाका झाडाचें फळ दिलें, आनी हांवें खालें.'" },
    { type: "verse", num: 13, text: "आनी सर्वेस्पर देवान बायलेक म्हणलें, 'तूं हें कितें केलें?' आनी बायलेन म्हणलें, 'सोरपान म्हाका फटयलें, आनी हांवें खालें.'" },
    { type: "section", text: "शिक्षा" },
    { type: "verse", num: 14, text: "आनी सर्वेस्पर देवान सोरपाक म्हणलें, 'तूं हें केल्लें देखून, सगळ्या गोरवांमदीं आनी सगळ्या रानवटीं जनावरांमदीं तूं शापित; तुज्या पोटार तूं सरपटतलो, आनी तुज्या जिविताच्या सगळ्या दिसांनी धुल्ल खातलो.'" },
    { type: "verse", num: 15, text: "'आनी हांव तुजेमदीं आनी बायलेमदीं, आनी तुज्या संततीमदीं आनी तिच्या संततीमदीं दुस्मानकाय दवरतलों; तो तुजें तकलें चिरडटलो, आनी तूं ताची तकली चावतलो.'" },
    { type: "verse", num: 16, text: "बायलेक ताणें म्हणलें, 'तुज्या दुखाक हांव खूब वाडयतलों; दुखान तूं भुरगीं जल्मतली; आनी तुजी ओड तुज्या घोवाकडेन आसतली, आनी तो तुजेचेर राज करतलो.'" },
    { type: "verse", num: 17, text: "आनी आदांवाक ताणें म्हणलें, 'तुज्या बायलेचें उतर तूं आयकलें आनी जें खावंका नाका म्हूण हांवें तुका आज्ञा दिल्ली त्या झाडाचें तूं खालें देखून, तुजे खातीर भुंय शापित; तुज्या जिविताच्या सगळ्या दिसांनी कश्टान तूं तिचें खातलो.'" },
    { type: "verse", num: 18, text: "'काटे आनी कुडें ती तुका उगयतली; आनी शेतांतलें वखद तूं खातलो.'" },
    { type: "verse", num: 19, text: "'तुज्या तोंडाच्या घामान तूं भाकर खातलो, मेरेन तूं भुंयेक परत वतलो; कारण तिचेपसून तुका काडिल्लो; कारण तूं धुल्ल, आनी धुल्लेक तूं परत वतलो.'" },
    { type: "verse", num: 20, text: "आनी मनशान आपल्या बायलेचें नांव एवा दवरलें; कारण ती सगळ्या जिव्यांची आवय जाली." },
    { type: "verse", num: 21, text: "आनी सर्वेस्पर देवान आदांव आनी ताचे बायले खातीर कातड्यांचीं वस्त्रां केलीं, आनी तांकां न्हेसयलीं." },
    { type: "verse", num: 22, text: "आनी सर्वेस्पर देवान म्हणलें, 'पळय, मनीस आमच्यांतल्या एकल्यासारको जालो, बरें आनी वायट जाणपाक; आनी आतां ताणें हात लांब करून जिविताच्या झाडाचेंय फळ काडून खावचें ना आनी सदांकाळ जगचें ना.'" },
    { type: "verse", num: 23, text: "देखून सर्वेस्पर देवान ताका एदेन बागेंतल्यान भायर धाडलो, जे भुंयेपसून ताका काडिल्लो ती लागवड करपाक." },
    { type: "verse", num: 24, text: "ताणें मनशाक भायर घालो; आनी एदेन बागेच्या उदेंतेक करूबीम आनी जिविताच्या झाडाच्या वाटेची राखण करपाक भोंवपी उज्याची तरवार दवरली." },
  ],
  "4": [
    { type: "section", text: "कायन आनी आबेल" },
    { type: "verse", num: 1, text: "आनी मनशान आपली बायल एवा हिका वळखली; आनी ती गुरवार जाली आनी कायनाक जल्म दिलो, आनी म्हणलें, 'सर्वेस्पराच्या आदारान हांवें एक मनीस मेळयलो.'" },
    { type: "verse", num: 2, text: "आनी ती परत ताच्या भावाक आबेलाक जल्म दिली. आनी आबेल मेंढरांचो गोवळी जालो, पूण कायन भुंयेचो लागवडकार जालो." },
    { type: "verse", num: 3, text: "आनी कांय दिसांउपरांत कायनान भुंयेच्या फळांतलें सर्वेस्पराक अर्पण हाडलें." },
    { type: "verse", num: 4, text: "आनी आबेलानूय आपल्या कळपांतल्या पयल्या जल्मिल्ल्यांतलें आनी तांच्या चरबेंतलें हाडलें. आनी सर्वेस्परान आबेलाक आनी ताच्या अर्पणाक मान दिलो." },
    { type: "verse", num: 5, text: "पूण कायनाक आनी ताच्या अर्पणाक ताणें मान दिलो ना. आनी कायन खूब रागावलो, आनी ताचें तोंड पडलें." },
    { type: "verse", num: 6, text: "आनी सर्वेस्परान कायनाक म्हणलें, 'तूं कित्याक रागावला? आनी तुजें तोंड कित्याक पडलें?'" },
    { type: "verse", num: 7, text: "'तूं बरें करता जाल्यार, मान मेळचो ना? आनी तूं बरें करीना जाल्यार, पातक दारांत लपून बसलां; आनी ताची ओड तुजेकडेन आसतली, पूण तूं ताचेर राज करूंक जाय.'" },
    { type: "verse", num: 8, text: "आनी कायनान आपल्या भावा आबेलाक सांगलें. आनी ते शेतांत आसताना कायन आपल्या भावा आबेलाचेर उठलो आनी ताका मारलो." },
    { type: "verse", num: 9, text: "आनी सर्वेस्परान कायनाक म्हणलें, 'तुजो भाव आबेल खंय आसा?' आनी ताणें म्हणलें, 'म्हाका खबर ना; हांव म्हज्या भावाचो राखणदार?' " },
    { type: "verse", num: 10, text: "आनी ताणें म्हणलें, 'तूं कितें केलें? तुज्या भावाच्या रगताचो आवाज भुंयेपसून म्हजेकडेन बोबाटता.'" },
    { type: "verse", num: 11, text: "'आनी आतां तूं भुंयेपसून शापित, जिणें आपलें तोंड उगडून तुज्या हातांतलें तुज्या भावाचें रगत घेतलें.'" },
    { type: "verse", num: 12, text: "'तूं भुंय लागवड करता तेन्ना ती तुका आपलें बळ दिवची ना; तूं पृथ्वीचेर भटक्या आनी भोंवती जातलो.'" },
    { type: "verse", num: 13, text: "आनी कायनान सर्वेस्पराक म्हणलें, 'म्हजी शिक्षा सोसपाक जाय तेपरस चड व्हड.'" },
    { type: "verse", num: 14, text: "'पळय, तूं म्हाका आज ह्या भुंयेचेर आड घाला; आनी तुज्या मुखापसून हांव लिपतलों; आनी हांव पृथ्वीचेर भटक्या आनी भोंवती जातलों; आनी जो कोण म्हाका मेळटलो तो म्हाका मारतलो.'" },
    { type: "verse", num: 15, text: "आनी सर्वेस्परान ताका म्हणलें, 'देखून जो कोण कायनाक मारतलो, ताचेर सात पटीन सूड घेतलो जातलो.' आनी सर्वेस्परान कायनाचेर एक चिन्न दवरलें, म्हणचे जो कोण ताका मेळटलो तो ताका मारचो ना." },
    { type: "verse", num: 16, text: "आनी कायन सर्वेस्पराच्या मुखापसून गेलो आनी एदेनाच्या उदेंतेक नोद देसांत रावलो." },
    { type: "section", text: "कायनाची वंशावळ" },
    { type: "verse", num: 17, text: "आनी कायनान आपली बायल वळखली; आनी ती गुरवार जाली आनी हनोखाक जल्म दिलो. आनी ताणें एक शार बांदलें आनी त्या शाराचें नांव आपल्या पुताच्या नांवान हनोख दवरलें." },
    { type: "verse", num: 18, text: "आनी हनोखाक ईराद जल्मलो; आनी ईरादान महूयाएलाक जल्म दिलो; आनी महूयाएलान मथूशाएलाक जल्म दिलो; आनी मथूशाएलान लामेखाक जल्म दिलो." },
    { type: "verse", num: 19, text: "आनी लामेखान दोन बायलो घेतल्यो; एकेचें नांव आदा आनी दुसरेचें नांव सिल्ला." },
    { type: "verse", num: 20, text: "आनी आदान याबालाक जल्म दिलो; तो तंबूंत रावतात आनी गोरवां पोसतात तांचो बापूय जालो." },
    { type: "verse", num: 21, text: "आनी ताच्या भावाचें नांव यूबाल; तो वीणा आनी बांसरी वाजयतात त्या सगळ्यांचो बापूय जालो." },
    { type: "verse", num: 22, text: "आनी सिल्लान तूबल-कायनाक जल्म दिलो, जो पितूळ आनी लोखणाच्या सगळ्या हत्यारांचो घडयणार; आनी तूबल-कायनाची भयण नामा." },
    { type: "verse", num: 23, text: "आनी लामेखान आपल्या बायलांक म्हणलें, 'आदा आनी सिल्ला, म्हजो आवाज आयकात; लामेखाच्या बायलांनो, म्हजें उतर कान दियात; कारण म्हाका घाय केल्ल्या मनशाक हांवें मारलो, आनी म्हाका लागिल्ल्या भुरग्याक.'" },
    { type: "verse", num: 24, text: "'कायना खातीर सात पटीन सूड जाल्यार, लामेखा खातीर सत्तर सात पटीन.'" },
    { type: "section", text: "शेथ आनी ताचे वंशज" },
    { type: "verse", num: 25, text: "आनी आदांवान आपली बायल परत वळखली; आनी तिणें एका पुताक जल्म दिलो आनी ताचें नांव शेथ दवरलें; कारण तिणें म्हणलें, 'कायनान मारिल्ल्या आबेला बदला देवान म्हाका आनीक एक संतान दिलां.'" },
    { type: "verse", num: 26, text: "आनी शेथाकूय एक पूत जल्मलो; आनी ताणें ताचें नांव एनोश दवरलें. त्या काळार मनशांनी सर्वेस्पराच्या नांवान प्रार्थना करपाक सुरवात केली." },
  ],
  "5": [
    { type: "section", text: "आदांवाची वंशावळ" },
    { type: "verse", num: 1, text: "ही आदांवाच्या वंशावळीची पुस्तक. ज्या दिसा देवान मनशाक रचलो, त्या दिसा देवाच्या सारकेपणान ताणें ताका केलो." },
    { type: "verse", num: 2, text: "दादलो आनी बायल ताणें तांकां रचलीं; आनी तांकां आशीर्वाद दिलो, आनी तांकां रचिल्ल्या दिसा तांचें नांव 'मनीस' दवरलें." },
    { type: "verse", num: 3, text: "आनी आदांव एकशें तीस वर्सांचो जालो तेन्ना ताका आपल्या सारकेपणान, आपल्या प्रतिमेप्रमाणें एक पूत जल्मलो; आनी ताणें ताचें नांव शेथ दवरलें." },
    { type: "verse", num: 4, text: "आनी शेथ जल्मल्या उपरांत आदांवाचे दीस आठशें वर्सां जाले; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 5, text: "आनी आदांवाचे सगळे दीस जे तो जगलो ते णवशें तीस वर्सां जाले; आनी तो मेलो." },
    { type: "verse", num: 6, text: "आनी शेथ एकशें पांच वर्सांचो जालो तेन्ना ताका एनोश जल्मलो." },
    { type: "verse", num: 7, text: "आनी एनोश जल्मल्या उपरांत शेथ आठशें सात वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 8, text: "आनी शेथाचे सगळे दीस णवशें बारा वर्सां जाले; आनी तो मेलो." },
    { type: "verse", num: 9, text: "आनी एनोश णव्वद वर्सांचो जालो तेन्ना ताका केनान जल्मलो." },
    { type: "verse", num: 10, text: "आनी केनान जल्मल्या उपरांत एनोश आठशें पंदरा वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 11, text: "आनी एनोशाचे सगळे दीस णवशें पांच वर्सां जाले; आनी तो मेलो." },
    { type: "verse", num: 12, text: "आनी केनान सत्तर वर्सांचो जालो तेन्ना ताका महललेल जल्मलो." },
    { type: "verse", num: 13, text: "आनी महललेल जल्मल्या उपरांत केनान आठशें चाळीस वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 14, text: "आनी केनानाचे सगळे दीस णवशें धा वर्सां जाले; आनी तो मेलो." },
    { type: "verse", num: 15, text: "आनी महललेल पासष्ट वर्सांचो जालो तेन्ना ताका यारेद जल्मलो." },
    { type: "verse", num: 16, text: "आनी यारेद जल्मल्या उपरांत महललेल आठशें तीस वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 17, text: "आनी महललेलाचे सगळे दीस आठशें पंच्याण्णव वर्सां जाले; आनी तो मेलो." },
    { type: "verse", num: 18, text: "आनी यारेद एकशें ब्यासष्ट वर्सांचो जालो तेन्ना ताका हनोख जल्मलो." },
    { type: "verse", num: 19, text: "आनी हनोख जल्मल्या उपरांत यारेद आठशें वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 20, text: "आनी यारेदाचे सगळे दीस णवशें ब्यासष्ट वर्सां जाले; आनी तो मेलो." },
    { type: "verse", num: 21, text: "आनी हनोख पासष्ट वर्सांचो जालो तेन्ना ताका मथूशेला जल्मलो." },
    { type: "verse", num: 22, text: "आनी मथूशेला जल्मल्या उपरांत हनोख तीनशें वर्सां देवाकडेन चललो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 23, text: "आनी हनोखाचे सगळे दीस तीनशें पासष्ट वर्सां जाले." },
    { type: "verse", num: 24, text: "आनी हनोख देवाकडेन चललो; आनी तो नासलो, कारण देवान ताका घेतलो." },
    { type: "verse", num: 25, text: "आनी मथूशेला एकशें सत्त्यांशीं वर्सांचो जालो तेन्ना ताका लामेख जल्मलो." },
    { type: "verse", num: 26, text: "आनी लामेख जल्मल्या उपरांत मथूशेला सातशें ब्यांशीं वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 27, text: "आनी मथूशेलाचे सगळे दीस णवशें उणसत्तर वर्सां जाले; आनी तो मेलो." },
    { type: "verse", num: 28, text: "आनी लामेख एकशें ब्यांशीं वर्सांचो जालो तेन्ना ताका एक पूत जल्मलो." },
    { type: "verse", num: 29, text: "आनी ताणें ताचें नांव नोहे दवरलें आनी म्हणलें, 'सर्वेस्परान शापिल्ल्या भुंयेपसून आमच्या कामांत आनी आमच्या हातांच्या कश्टांत हो आमकां भुजयतलो.'" },
    { type: "verse", num: 30, text: "आनी नोहे जल्मल्या उपरांत लामेख पांचशें पंच्याण्णव वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 31, text: "आनी लामेखाचे सगळे दीस सातशें सत्तर सात वर्सां जाले; आनी तो मेलो." },
    { type: "verse", num: 32, text: "आनी नोहे पांचशें वर्सांचो जालो; आनी नोहेक शेम, हाम आनी याफेथ जल्मले." },
  ],
  "6": [
    { type: "section", text: "मनशाची दुश्टकाय" },
    { type: "verse", num: 1, text: "आनी जेन्ना मनीस पृथ्वीचेर वाडपाक लागले, आनी तांकां धुवो जल्मल्यो." },
    { type: "verse", num: 2, text: "तेन्ना देवाच्या पुतांनी मनशांच्या धुवो सोबीत म्हूण पळयल्यो; आनी तांकां जायो त्यो सगळ्यो तांणीं बायलो घेतल्यो." },
    { type: "verse", num: 3, text: "आनी सर्वेस्परान म्हणलें, 'म्हजो आत्मो मनशाकडेन सदांकाळ झगडचो ना, कारण तो मांस; ताचे दीस एकशें वीस वर्सां आसतले.'" },
    { type: "verse", num: 4, text: "त्या दिसांनी पृथ्वीचेर राक्षस आसले, आनी त्या उपरांतूय, जेन्ना देवाचे पूत मनशांच्या धुवांकडेन गेले आनी तांकां भुरगीं जालीं; ते पोरने काळांतले बळीष्ट मनीस, नामनेचे दादले." },
    { type: "verse", num: 5, text: "आनी सर्वेस्परान पळयलें की मनशाची दुश्टकाय पृथ्वीचेर खूब; आनी ताच्या काळजांतल्या विचारांचो दरेक उद्देश सदांच वायटूच." },
    { type: "verse", num: 6, text: "आनी सर्वेस्पराक पृथ्वीचेर मनशाक केल्ल्याचो पश्चात्ताप जालो, आनी ताच्या काळजाक दूख जालें." },
    { type: "verse", num: 7, text: "आनी सर्वेस्परान म्हणलें, 'हांवें रचिल्लो मनीस पृथ्वीचेर आड नाश करतलों; मनीस आनी गोरवां आनी सरपटपी जीव आनी मळबांतलीं सुकणीं; कारण तांकां केल्ल्याचो म्हाका पश्चात्ताप जालो.'" },
    { type: "verse", num: 8, text: "पूण नोहेक सर्वेस्पराच्या दोळ्यांत कुर्पा मेळ्ळी." },
    { type: "section", text: "नोहे आनी जल-प्रलय" },
    { type: "verse", num: 9, text: "ही नोहेची वंशावळ. नोहे एक नीतीमान आनी ताच्या पिळगेंत निर्दोष मनीस आसलो; नोहे देवाकडेन चललो." },
    { type: "verse", num: 10, text: "आनी नोहेक तीन पूत जल्मले: शेम, हाम आनी याफेथ." },
    { type: "verse", num: 11, text: "आनी पृथ्वी देवामुखार भ्रश्ट जाली, आनी पृथ्वी हिंसेन भरली." },
    { type: "verse", num: 12, text: "आनी देवान पृथ्वीकडेन पळयलें, आनी पळय, ती भ्रश्ट आसली; कारण सगळ्या मांसान पृथ्वीचेर आपली वाट भ्रश्ट केल्ली." },
    { type: "verse", num: 13, text: "आनी देवान नोहेक म्हणलें, 'सगळ्या मांसाचो अंत म्हजेमुखार आयला; कारण पृथ्वी तांचेवरवीं हिंसेन भरल्या; आनी पळय, हांव तांकां पृथ्वेकडेन नाश करतलों.'" },
    { type: "verse", num: 14, text: "'तूं तुका एक तारू गोफेर लाकडाचें कर; तारवांत कुडी कर, आनी ताका भितर आनी भायर डांबरान लेप.'" },
    { type: "verse", num: 15, text: "'आनी तूं तें अशें करतलो: तारवाची लांबाय तीनशें हात, ताची रुंदाय पन्नास हात, आनी ताची उंचाय तीस हात.'" },
    { type: "verse", num: 16, text: "'तारवाक एक जनेल कर, आनी वयर एक हात जाग्यार पुरें कर; आनी तारवाचो दार ताच्या कुशीक दवर; सकयलो, मदलो आनी वयलो माळो कर.'" },
    { type: "verse", num: 17, text: "'आनी पळय, हांवच पृथ्वीचेर उदकाचो जल-प्रलय हाडटलों, मळबासकयलें जें सगळें मांस, ज्याचे थंय जिविताचो स्वास आसा, ताचो नाश करपाक; पृथ्वीचेर आशिल्लें सगळें मरतलें.'" },
    { type: "verse", num: 18, text: "'पूण हांव तुजेकडेन म्हजो करार स्थापन करतलों; आनी तूं तारवांत भितर सरतलो, तूं आनी तुजे पूत आनी तुजी बायल आनी तुज्या पुतांच्यो बायलो तुजेकडेन.'" },
    { type: "verse", num: 19, text: "'आनी सगळ्या जिव्या प्राण्यांतल्यान, सगळ्या मांसांतल्यान, दरेक जातींतलें दोन तूं तारवांत हाडतलो, तांकां तुजेकडेन जिवे दवरपाक; ते दादलो आनी मादी आसतले.'" },
    { type: "verse", num: 20, text: "'सुकण्यांतल्यान तांच्या जातीप्रमाणें, आनी गोरवांतल्यान तांच्या जातीप्रमाणें, आनी पृथ्वीचेर सरपटपी सगळ्यांतल्यान तांच्या जातीप्रमाणें, दरेक जातीचें दोन तुजेकडेन येतलीं, जिवीं उरपाक.'" },
    { type: "verse", num: 21, text: "'आनी खावपाचें जें कितें आसा तें तूं तुजेकडेन घे आनी सांठय; आनी तें तुका आनी तांकां खावपाक आसतलें.'" },
    { type: "verse", num: 22, text: "आनी नोहेन तशें केलें; देवान ताका जी आज्ञा दिल्ली तेप्रमाणें ताणें सगळें केलें." },
  ],
  "7": [
    { type: "section", text: "जल-प्रलय" },
    { type: "verse", num: 1, text: "आनी सर्वेस्परान नोहेक म्हणलें, 'तूं आनी तुजें सगळें कुटुंब तारवांत भितर सर; कारण ह्या पिळगेंत तुका हांवें म्हजेमुखार नीतीमान पळयला.'" },
    { type: "verse", num: 2, text: "'सगळ्या शुद्ध जनावरांतल्यान तूं सात सात, दादलो आनी ताची मादी, घे; आनी शुद्ध नाशिल्ल्या जनावरांतल्यान दोन, दादलो आनी ताची मादी.'" },
    { type: "verse", num: 3, text: "'मळबांतल्या सुकण्यांतल्यानूय सात सात, दादलो आनी मादी, सगळ्या पृथ्वीचेर बीय जिवें दवरपाक.'" },
    { type: "verse", num: 4, text: "'कारण आनीक सात दीस जाले उपरांत हांव पृथ्वीचेर चाळीस दीस आनी चाळीस राती पावस हाडटलों; आनी पृथ्वीचेर हांवें केल्ली सगळी जिवी वस्त हांव नाश करतलों.'" },
    { type: "verse", num: 5, text: "आनी सर्वेस्परान ताका जी आज्ञा दिल्ली तेप्रमाणें नोहेन केलें." },
    { type: "verse", num: 6, text: "आनी पृथ्वीचेर जल-प्रलयाचें उदक आयलें तेन्ना नोहे सशें वर्सांचो आसलो." },
    { type: "verse", num: 7, text: "आनी नोहे आनी ताचे पूत आनी ताची बायल आनी ताच्या पुतांच्यो बायलो जल-प्रलयाच्या उदकांपसून तारवांत भितर सरले." },
    { type: "verse", num: 8, text: "शुद्ध जनावरांतल्यान, आनी शुद्ध नाशिल्ल्या जनावरांतल्यान, आनी सुकण्यांतल्यान, आनी पृथ्वीचेर सरपटपी सगळ्यांतल्यान." },
    { type: "verse", num: 9, text: "दोन दोन नोहेकडेन तारवांत गेलीं, दादलो आनी मादी, जशें देवान नोहेक आज्ञा दिल्ली." },
    { type: "verse", num: 10, text: "आनी सात दीस जाले उपरांत जल-प्रलयाचें उदक पृथ्वीचेर आयलें." },
    { type: "verse", num: 11, text: "नोहेच्या जिविताच्या सशाव्या वर्सा, दुसऱ्या म्हयन्याच्या सतराव्या दिसा, त्या दिसा व्हड खोलायेचे सगळे झरे फुटले, आनी मळबाचीं जनेलां उगतीं जालीं." },
    { type: "verse", num: 12, text: "आनी पृथ्वीचेर चाळीस दीस आनी चाळीस राती पावस पडलो." },
    { type: "verse", num: 13, text: "त्याच दिसा नोहे, आनी शेम आनी हाम आनी याफेथ, नोहेचे पूत, आनी नोहेची बायल आनी ताच्या पुतांच्यो तीन बायलो तांचेकडेन तारवांत भितर सरले." },
    { type: "verse", num: 14, text: "ते, आनी दरेक रानवटी जनावर ताच्या जातीप्रमाणें, आनी सगळीं गोरवां तांच्या जातीप्रमाणें, आनी पृथ्वीचेर सरपटपी दरेक जीव ताच्या जातीप्रमाणें, आनी दरेक सुकणें ताच्या जातीप्रमाणें, दरेक पाखां आशिल्लें." },
    { type: "verse", num: 15, text: "आनी सगळ्या मांसांतल्यान, ज्यांचे थंय जिविताचो स्वास आसा, दोन दोन नोहेकडेन तारवांत गेलीं." },
    { type: "verse", num: 16, text: "आनी भितर गेलीं तीं दादलो आनी मादी, सगळ्या मांसांतल्यान, जशें देवान ताका आज्ञा दिल्ली; आनी सर्वेस्परान ताचेर दार बंद केलें." },
    { type: "verse", num: 17, text: "आनी जल-प्रलय पृथ्वीचेर चाळीस दीस आसलो; आनी उदकां वाडलीं आनी तारूं उखल्लें, आनी तें पृथ्वीचेर वयर उचल्लें." },
    { type: "verse", num: 18, text: "आनी उदकां जोर धरून पृथ्वीचेर खूब वाडलीं; आनी तारूं उदकांच्या तोंडार चललें." },
    { type: "verse", num: 19, text: "आनी उदकां पृथ्वीचेर अतिशय जोरान वाडलीं; आनी सगळ्या मळबासकयलीं सगळीं उंच दोंगरां धांपलीं गेलीं." },
    { type: "verse", num: 20, text: "पंदरा हात वयर उदकां वाडलीं; आनी दोंगरां धांपलीं गेलीं." },
    { type: "verse", num: 21, text: "आनी पृथ्वीचेर चलपी सगळें मांस मेलें: सुकणीं, गोरवां, रानवटीं जनावरां, पृथ्वीचेर सरपटपी सगळे जीव, आनी सगळे मनीस." },
    { type: "verse", num: 22, text: "जांच्या नाकांत जिविताच्या स्वासाचो फुंकार आसलो, सुक्या भुंयेचेर जें कितें आसलें, तें सगळें मेलें." },
    { type: "verse", num: 23, text: "आनी पृथ्वीच्या तोंडार आशिल्ली सगळी जिवी वस्त नाश जाली, मनशापसून गोरवांमेरेन, सरपटपी जीवांमेरेन, मळबांतल्या सुकण्यांमेरेन; ते पृथ्वीचेर नाश जाले; आनी फकत नोहे आनी ताचेकडेन तारवांत आशिल्ले उरले." },
    { type: "verse", num: 24, text: "आनी उदकां पृथ्वीचेर एकशें पन्नास दीस जोर धरून आसलीं." },
  ],
  "8": [
    { type: "section", text: "जल-प्रलयाचो शेवट" },
    { type: "verse", num: 1, text: "आनी देवान नोहेची आनी ताचेकडेन तारवांत आशिल्ल्या सगळ्या जिव्या प्राण्यांची आनी सगळ्या गोरवांची याद केली; आनी देवान पृथ्वीचेर वारो धाडलो, आनी उदकां उणीं जालीं." },
    { type: "verse", num: 2, text: "खोलायेचे झरे आनी मळबाचीं जनेलां बंद जालीं, आनी मळबांतलो पावस आडायलो." },
    { type: "verse", num: 3, text: "आनी उदकां पृथ्वीचेर सारकीं उणीं जायत गेलीं; आनी एकशें पन्नास दीस जाले उपरांत उदकां उणीं जालीं." },
    { type: "verse", num: 4, text: "आनी सातव्या म्हयन्याच्या सतराव्या दिसा तारूं अरारात दोंगरांचेर थारावलें." },
    { type: "verse", num: 5, text: "आनी उदकां धाव्या म्हयन्यामेरेन सारकीं उणीं जायत गेलीं; धाव्या म्हयन्याच्या पयल्या दिसा दोंगरांचीं तकलीं दिसलीं." },
    { type: "verse", num: 6, text: "आनी चाळीस दीस जाले उपरांत नोहेन आपणें तारवांत केल्लें जनेल उगडलें." },
    { type: "verse", num: 7, text: "आनी ताणें एक कावळो भायर सोडलो; तो भायर वचून उदकां पृथ्वीचेर सुकमेरेन हेवटें तेवटें उडत रावलो." },
    { type: "verse", num: 8, text: "ताणें एक पारवी आपणेकडसून भायर सोडली, पृथ्वीचेर उदकां उणीं जालींत काय तें पळोवपाक." },
    { type: "verse", num: 9, text: "पूण पारव्याक पांयांक थारावपाक सुवात मेळ्ळी ना, आनी ती ताचेकडेन तारवांत परत आयली; कारण सगळ्या पृथ्वीचेर उदकां आसलीं. ताणें हात लांब करून तिका धरली आनी तिका आपणेकडेन तारवांत भितर घेतली." },
    { type: "verse", num: 10, text: "आनी ताणें आनीक सात दीस रावलो; आनी परत पारवी तारवांतल्यान भायर सोडली." },
    { type: "verse", num: 11, text: "आनी पारवी सांजेवेळा ताचेकडेन आयली; आनी पळय, तिच्या चोंचींत ताजें कोपिल्लें जैतूनाचें पान आसलें; आनी नोहेक कळलें की पृथ्वीचेर उदकां उणीं जालीं." },
    { type: "verse", num: 12, text: "आनी ताणें आनीक सात दीस रावलो; आनी पारवी भायर सोडली; आनी ती ताचेकडेन परत आयली ना." },
    { type: "verse", num: 13, text: "आनी सशाव्या एकाव्या वर्सा, पयल्या म्हयन्याच्या पयल्या दिसा, पृथ्वीचेर उदकां सुकलीं; आनी नोहेन तारवाचें धांपणें काडलें आनी पळयलें, आनी पळय, भुंयेचें तोंड सुक्यात आसलें." },
    { type: "verse", num: 14, text: "आनी दुसऱ्या म्हयन्याच्या सत्ताविसाव्या दिसा पृथ्वी सुकली." },
    { type: "verse", num: 15, text: "आनी देवान नोहेक सांगलें," },
    { type: "verse", num: 16, text: "'तारवांतल्यान भायर सर, तूं आनी तुजी बायल आनी तुजे पूत आनी तुज्या पुतांच्यो बायलो तुजेकडेन.'" },
    { type: "verse", num: 17, text: "'तुजेकडेन आशिल्लो दरेक जिवो प्राणी, सगळ्या मांसांतलो, सुकण्यांतलो आनी गोरवांतलो, आनी पृथ्वीचेर सरपटपी सगळ्या जिवांतलो, तुजेकडेन भायर काड; म्हणचे ते पृथ्वीचेर वाडूंदीत, आनी फळां दिवूंदीत आनी पृथ्वीचेर वाडूंदीत.'" },
    { type: "verse", num: 18, text: "आनी नोहे भायर सरलो, आनी ताचे पूत आनी ताची बायल आनी ताच्या पुतांच्यो बायलो ताचेकडेन." },
    { type: "verse", num: 19, text: "दरेक जनावर, दरेक सरपटपी जीव, आनी दरेक सुकणें, पृथ्वीचेर चलपी सगळें, तांच्या कुळांप्रमाणें तारवांतल्यान भायर सरले." },
    { type: "section", text: "नोहेचें अर्पण" },
    { type: "verse", num: 20, text: "आनी नोहेन सर्वेस्पराक एक वेदी बांदली; आनी सगळ्या शुद्ध जनावरांतल्यान आनी सगळ्या शुद्ध सुकण्यांतल्यान घेवन वेदीचेर होमबली अर्पण केलीं." },
    { type: "verse", num: 21, text: "आनी सर्वेस्परान गोड वास घेतलो; आनी सर्वेस्परान आपल्या काळजांत म्हणलें, 'मनशा खातीर हांव आनीक केन्नाच भुंयेक शाप दिवचों ना; कारण मनशाच्या काळजाचो विचार ताच्या भुरगेपणापसूनच वायट; आनी हांवें केल्लेप्रमाणें सगळ्या जिव्या वस्तीक हांव आनीक केन्नाच मारचों ना.'" },
    { type: "verse", num: 22, text: "'पृथ्वी आसा मेरेन पेरणी आनी कापणी, थंडी आनी उश्णता, उन्हाळो आनी हिंवाळो, दीस आनी रात सोंपचीं ना.'" },
  ],
  "9": [
    { type: "section", text: "देवाचो नोहेकडेन करार" },
    { type: "verse", num: 1, text: "आनी देवान नोहेक आनी ताच्या पुतांक आशीर्वाद दिलो आनी तांकां म्हणलें, 'फळां दियात आनी वाडात आनी पृथ्वी भरात.'" },
    { type: "verse", num: 2, text: "'आनी पृथ्वीच्या सगळ्या जनावरांक, आनी मळबांतल्या सगळ्या सुकण्यांक, आनी भुंयेचेर सरपटपी सगळ्यांक, आनी दर्यांतल्या सगळ्या मासळ्यांक तुमची भिरांत आनी तुमचो दबाव आसतलो; ते तुमच्या हातांत दिल्यात.'" },
    { type: "verse", num: 3, text: "'दरेक जिवो चलपी जीव तुमकां खावपाक आसतलो; पाचव्या वखदांसारकें हांव तुमकां सगळें दिलां.'" },
    { type: "verse", num: 4, text: "'पूण मांस ताच्या जिवीतान, म्हणजे ताच्या रगतान, तुमी खावंका नाका.'" },
    { type: "verse", num: 5, text: "'आनी खात्रीन तुमच्या जिविताच्या रगताचो हांव हिशोब मागतलों; दरेक जनावराकडसून हांव ताचो हिशोब मागतलों, आनी मनशाकडसून; दरेक मनशाच्या भावाकडसून हांव मनशाच्या जिविताचो हिशोब मागतलों.'" },
    { type: "verse", num: 6, text: "'जो कोण मनशाचें रगत व्हारयता, ताचें रगत मनशाकडसून व्हारयतलें; कारण देवाच्या प्रतिमेप्रमाणें ताणें मनशाक केलो.'" },
    { type: "verse", num: 7, text: "'आनी तुमी फळां दियात आनी वाडात; पृथ्वीचेर भरपूर वाडात आनी तिचेर गुणाकार जायात.'" },
    { type: "verse", num: 8, text: "आनी देवान नोहेक आनी ताचेकडेन आशिल्ल्या ताच्या पुतांक सांगलें," },
    { type: "verse", num: 9, text: "'आनी पळय, हांव तुमचेकडेन आनी तुमच्या उपरांत तुमच्या संततीकडेन म्हजो करार स्थापन करतां;'" },
    { type: "verse", num: 10, text: "'आनी तुमचेकडेन आशिल्ल्या दरेक जिव्या प्राण्याकडेन, सुकण्यांकडेन, गोरवांकडेन, आनी तुमचेकडेन आशिल्ल्या पृथ्वीच्या दरेक जनावराकडेन, तारवांतल्यान भायर आयिल्ल्या सगळ्यांकडेन, पृथ्वीच्या दरेक जनावराकडेन.'" },
    { type: "verse", num: 11, text: "'आनी हांव तुमचेकडेन म्हजो करार स्थापन करतां; आनी जल-प्रलयाच्या उदकान सगळें मांस आनीक केन्नाच नाश जावचें ना; आनी पृथ्वीचो नाश करपाक जल-प्रलय आनीक केन्नाच येवचो ना.'" },
    { type: "verse", num: 12, text: "आनी देवान म्हणलें, 'हांव म्हजेमदीं आनी तुमचेमदीं आनी तुमचेकडेन आशिल्ल्या दरेक जिव्या प्राण्यामदीं, सदांकाळच्या पिळग्यांक करतां त्या कराराचें हें चिन्न:'" },
    { type: "verse", num: 13, text: "'हांव म्हजें धोणूं कुपांत दवरतां, आनी तें म्हजेमदीं आनी पृथ्वेमदीं कराराचें चिन्न आसतलें.'" },
    { type: "verse", num: 14, text: "'आनी जेन्ना हांव पृथ्वीचेर कूप हाडटलों, तेन्ना कुपांत धोणूं दिसतलें;'" },
    { type: "verse", num: 15, text: "'आनी हांव म्हजो करार याद करतलों, जो म्हजेमदीं आनी तुमचेमदीं आनी सगळ्या मांसाच्या दरेक जिव्या प्राण्यामदीं आसा; आनी सगळ्या मांसाचो नाश करपाक उदकां आनीक केन्नाच जल-प्रलय जावचो ना.'" },
    { type: "verse", num: 16, text: "'आनी धोणूं कुपांत आसतलें; आनी हांव ताचेकडेन पळयतलों, म्हणचे देवामदीं आनी पृथ्वीचेर आशिल्ल्या सगळ्या मांसाच्या दरेक जिव्या प्राण्यामदीं सदांकाळचो करार याद करपाक.'" },
    { type: "verse", num: 17, text: "आनी देवान नोहेक म्हणलें, 'हें त्या कराराचें चिन्न जो हांवें म्हजेमदीं आनी पृथ्वीचेर आशिल्ल्या सगळ्या मांसामदीं स्थापन केला.'" },
    { type: "section", text: "नोहेचे पूत" },
    { type: "verse", num: 18, text: "आनी तारवांतल्यान भायर आयिल्ले नोहेचे पूत शेम आनी हाम आनी याफेथ आसले; आनी हाम कनानाचो बापूय." },
    { type: "verse", num: 19, text: "हे तीन नोहेचे पूत; आनी तांचेपसून सगळी पृथ्वी पातळली." },
    { type: "verse", num: 20, text: "आनी नोहे शेतकार जालो आनी ताणें द्राक्षाचो मळो लायलो." },
    { type: "verse", num: 21, text: "आनी ताणें द्राक्षारस पियेलो आनी पियेल्ल्यान मस्त जालो; आनी आपल्या तंबूंत उघडो पडलो." },
    { type: "verse", num: 22, text: "आनी कनानाचो बापूय हामान आपल्या बापायचें उघडेपण पळयलें, आनी भायर आपल्या दोन भावांक सांगलें." },
    { type: "verse", num: 23, text: "आनी शेमान आनी याफेथान एक वस्त्र घेतलें आनी दोगांयच्या खांदांचेर दवरलें, आनी पाटसून चलून आपल्या बापायचें उघडेपण धांपलें; आनी तांचीं तोंडां पाटसून आसलीं, आनी तांणीं आपल्या बापायचें उघडेपण पळयलें ना." },
    { type: "verse", num: 24, text: "आनी नोहे आपल्या द्राक्षारसांतल्यान जागो जालो, आनी ताच्या ल्हान पुतान ताका कितें केल्लें तें ताका कळलें." },
    { type: "verse", num: 25, text: "आनी ताणें म्हणलें, 'कनान शापित; ताच्या भावांचो दासांचो दास तो आसतलो.'" },
    { type: "verse", num: 26, text: "आनी ताणें म्हणलें, 'शेमाचो देव सर्वेस्पर धन्य; आनी कनान ताचो दास आसतलो.'" },
    { type: "verse", num: 27, text: "'देवान याफेथाक विस्तार दिवचो, आनी तो शेमाच्या तंबूंत रावचो; आनी कनान ताचो दास आसतलो.'" },
    { type: "verse", num: 28, text: "आनी जल-प्रलया उपरांत नोहे तीनशें पन्नास वर्सां जगलो." },
    { type: "verse", num: 29, text: "आनी नोहेचे सगळे दीस णवशें पन्नास वर्सां जाले; आनी तो मेलो." },
  ],
  "10": [
    { type: "section", text: "राष्ट्रांची सूची" },
    { type: "verse", num: 1, text: "ही नोहेच्या पुतांची, शेम, हाम आनी याफेथ हांची वंशावळ; आनी जल-प्रलया उपरांत तांकां पूत जल्मले." },
    { type: "verse", num: 2, text: "याफेथाचे पूत: गोमेर, मागोग, मादय, यावान, तूबाल, मेशेख आनी तीरास." },
    { type: "verse", num: 3, text: "आनी गोमेराचे पूत: अश्कनाज, रीफाथ आनी तोगर्मा." },
    { type: "verse", num: 4, text: "आनी यावानाचे पूत: एलीशा, तार्शीश, कित्तीम आनी दोदानीम." },
    { type: "verse", num: 5, text: "हांचेपसून राष्ट्रांच्या द्वीपांनी वेगवेगळे जाले, तांच्या देसांनी, दरेकलो आपापल्या भाशेप्रमाणें, तांच्या कुळांप्रमाणें, तांच्या राष्ट्रांमदीं." },
    { type: "verse", num: 6, text: "आनी हामाचे पूत: कूश, मिस्रायीम, पूट आनी कनान." },
    { type: "verse", num: 7, text: "आनी कूशाचे पूत: सबा, हवीला, सब्ता, रामा आनी सब्तका. आनी रामाचे पूत: शबा आनी ददान." },
    { type: "verse", num: 8, text: "आनी कूशान निम्रोदाक जल्म दिलो; तो पृथ्वीचेर बळिष्ट जावपाक लागलो." },
    { type: "verse", num: 9, text: "तो सर्वेस्परामुखार बळिष्ट शिकारी आसलो; देखून म्हणटात, 'सर्वेस्परामुखार निम्रोदासारको बळिष्ट शिकारी.'" },
    { type: "verse", num: 10, text: "आनी ताच्या राज्याची सुरवात शिनार देसांत बाबेल, एरेख, अक्काद आनी कल्ने हांगासर जाली." },
    { type: "verse", num: 11, text: "त्या देसांतल्यान तो अश्शूराक गेलो आनी निनवे, रहोबोथ-ईर आनी कालह बांदलें." },
    { type: "verse", num: 12, text: "आनी निनवे आनी कालह हांचेमदीं रेसेन; तें व्हड शार." },
    { type: "verse", num: 13, text: "आनी मिस्रायीमान लूदीम, अनामीम, लहाबीम, नफ्तूहीम," },
    { type: "verse", num: 14, text: "पत्रूसीम, कस्लूहीम (ज्यांचेपसून पलिश्ती आयले) आनी कफ्तोरीम हांकां जल्म दिलो." },
    { type: "verse", num: 15, text: "आनी कनानान आपलो ज्येष्ठ सीदोन आनी हेथ हांकां जल्म दिलो." },
    { type: "verse", num: 16, text: "आनी यबूसी, अमोरी, गिर्गाशी," },
    { type: "verse", num: 17, text: "हिव्वी, अर्की, सीनी," },
    { type: "verse", num: 18, text: "अर्वादी, समारी आनी हमाथी; आनी उपरांत कनानी कुळां पातळलीं." },
    { type: "verse", num: 19, text: "आनी कनानीची शीम सीदोनापसून गरारामेरेन गाझा वाटेन, आनी सदोम, गमोरा, अदमा आनी सबोयीम मेरेन लाशा वाटेन आसली." },
    { type: "verse", num: 20, text: "हे हामाचे पूत, तांच्या कुळांप्रमाणें, तांच्या भाशांप्रमाणें, तांच्या देसांनी, तांच्या राष्ट्रांमदीं." },
    { type: "verse", num: 21, text: "आनी शेमाकूय पूत जल्मले; तो सगळ्या एबेराच्या भुरग्यांचो बापूय, याफेथाचो व्हडलो भाव." },
    { type: "verse", num: 22, text: "शेमाचे पूत: एलाम, अश्शूर, अर्पक्षद, लूद आनी अराम." },
    { type: "verse", num: 23, text: "आनी अरामाचे पूत: ऊज, हूल, गेथेर आनी मश." },
    { type: "verse", num: 24, text: "आनी अर्पक्षदान शेलहाक जल्म दिलो; आनी शेलहान एबेराक जल्म दिलो." },
    { type: "verse", num: 25, text: "आनी एबेराक दोन पूत जल्मले; एकल्याचें नांव पेलेग, कारण ताच्या दिसांनी पृथ्वी वांटली गेली; आनी ताच्या भावाचें नांव योक्तान." },
    { type: "verse", num: 26, text: "आनी योक्तानान अल्मोदाद, शेलेफ, हसर्मावेथ, येरह," },
    { type: "verse", num: 27, text: "हदोराम, ऊजाल, दिक्ला," },
    { type: "verse", num: 28, text: "ओबाल, अबीमाएल, शबा," },
    { type: "verse", num: 29, text: "ओफीर, हवीला आनी योबाब हांकां जल्म दिलो; हे सगळे योक्तानाचे पूत." },
    { type: "verse", num: 30, text: "आनी तांचें रावपाचें मेशापसून सफारामेरेन, उदेंतेच्या दोंगरामेरेन आसलें." },
    { type: "verse", num: 31, text: "हे शेमाचे पूत, तांच्या कुळांप्रमाणें, तांच्या भाशांप्रमाणें, तांच्या देसांनी, तांच्या राष्ट्रांमदीं." },
    { type: "verse", num: 32, text: "ही नोहेच्या पुतांचीं कुळां, तांच्या वंशावळींप्रमाणें, तांच्या राष्ट्रांमदीं; आनी हांचेपसून जल-प्रलया उपरांत पृथ्वीचेर राष्ट्रां वांटलीं गेलीं." },
  ],
  "11": [
    { type: "section", text: "बाबेलाचो बुरूज" },
    { type: "verse", num: 1, text: "आनी सगळ्या पृथ्वीची एकूच भास आनी एकूच उतरां आसलीं." },
    { type: "verse", num: 2, text: "आनी ते उदेंतेकडेन चलताना तांकां शिनार देसांत एक सपाट मळ मेळ्ळो; आनी ते थंय रावले." },
    { type: "verse", num: 3, text: "आनी ते एकामेकांक म्हणाले, 'येयात, आमी वीटो करूया आनी त्यो बरें भाजूया.' आनी तांकां फातरा बदला वीटो आनी चुन्या बदला डांबर आसलें." },
    { type: "verse", num: 4, text: "आनी ते म्हणाले, 'येयात, आमी आमकां एक शार आनी एक बुरूज बांदूया, ज्याचें तकलें मळबामेरेन पावतलें; आनी आमी आमकां नांव करूया, नाजाल्यार आमी सगळ्या पृथ्वीचेर पातळतलीं.'" },
    { type: "verse", num: 5, text: "आनी सर्वेस्पर मनशाच्या पुतांनी बांदिल्लें शार आनी बुरूज पळोवपाक सकयल आयलो." },
    { type: "verse", num: 6, text: "आनी सर्वेस्परान म्हणलें, 'पळय, लोक एकूच आनी तांची सगळ्यांची एकूच भास; आनी हें करपाक ते सुरू केलां; आनी आतां ते जें कितें करपाक मनांत घालतले तें तांकां आडावपाक मेळचें ना.'" },
    { type: "verse", num: 7, text: "'येयात, आमी सकयल वचूया आनी थंय तांची भास गोंदळावूया, म्हणचे ते एकामेकांची भास समजचे नात.'" },
    { type: "verse", num: 8, text: "अशें सर्वेस्परान तांकां थंयसून सगळ्या पृथ्वीचेर पातळयले; आनी तांणीं शार बांदप सोडलें." },
    { type: "verse", num: 9, text: "देखून ताचें नांव बाबेल दवरलें; कारण सर्वेस्परान थंय सगळ्या पृथ्वीची भास गोंदळायली; आनी थंयसून सर्वेस्परान तांकां सगळ्या पृथ्वीचेर पातळयले." },
    { type: "section", text: "शेमाची वंशावळ" },
    { type: "verse", num: 10, text: "ही शेमाची वंशावळ. शेम शंभर वर्सांचो आसलो तेन्ना जल-प्रलया उपरांत दोन वर्सांनी ताका अर्पक्षद जल्मलो." },
    { type: "verse", num: 11, text: "आनी अर्पक्षद जल्मल्या उपरांत शेम पांचशें वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 12, text: "आनी अर्पक्षद पस्तीस वर्सांचो जालो तेन्ना ताका शेलह जल्मलो." },
    { type: "verse", num: 13, text: "आनी शेलह जल्मल्या उपरांत अर्पक्षद चारशें तीन वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 14, text: "आनी शेलह तीस वर्सांचो जालो तेन्ना ताका एबेर जल्मलो." },
    { type: "verse", num: 15, text: "आनी एबेर जल्मल्या उपरांत शेलह चारशें तीन वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 16, text: "आनी एबेर चवतीस वर्सांचो जालो तेन्ना ताका पेलेग जल्मलो." },
    { type: "verse", num: 17, text: "आनी पेलेग जल्मल्या उपरांत एबेर चारशें तीस वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 18, text: "आनी पेलेग तीस वर्सांचो जालो तेन्ना ताका रऊ जल्मलो." },
    { type: "verse", num: 19, text: "आनी रऊ जल्मल्या उपरांत पेलेग दोनशें णव वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 20, text: "आनी रऊ बत्तीस वर्सांचो जालो तेन्ना ताका सरूग जल्मलो." },
    { type: "verse", num: 21, text: "आनी सरूग जल्मल्या उपरांत रऊ दोनशें सात वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 22, text: "आनी सरूग तीस वर्सांचो जालो तेन्ना ताका नाहोर जल्मलो." },
    { type: "verse", num: 23, text: "आनी नाहोर जल्मल्या उपरांत सरूग दोनशें वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 24, text: "आनी नाहोर उणतीस वर्सांचो जालो तेन्ना ताका तेरह जल्मलो." },
    { type: "verse", num: 25, text: "आनी तेरह जल्मल्या उपरांत नाहोर एकशें उणवीस वर्सां जगलो; आनी ताका पूत आनी धुवो जल्मल्यो." },
    { type: "verse", num: 26, text: "आनी तेरह सत्तर वर्सांचो जालो तेन्ना ताका अब्राम, नाहोर आनी हारान जल्मले." },
    { type: "section", text: "तेरहाची वंशावळ" },
    { type: "verse", num: 27, text: "ही तेरहाची वंशावळ. तेरहान अब्राम, नाहोर आनी हारान हांकां जल्म दिलो; आनी हारानान लोटाक जल्म दिलो." },
    { type: "verse", num: 28, text: "आनी हारान आपल्या बापाय तेरहामुखार, आपल्या जल्माच्या देसांत, कसदी लोकांच्या ऊरांत मेलो." },
    { type: "verse", num: 29, text: "आनी अब्रामान आनी नाहोरान बायलो घेतल्यो; अब्रामाच्या बायलेचें नांव साराय, आनी नाहोराच्या बायलेचें नांव मिल्का, हारानाची धूव, मिल्का आनी यिस्का हांची बापूय." },
    { type: "verse", num: 30, text: "पूण साराय बांज आसली; तिका भुरगें नासलें." },
    { type: "verse", num: 31, text: "आनी तेरहान आपलो पूत अब्राम, आनी आपल्या पुताचो पूत लोट, हारानाचो पूत, आनी आपली सून साराय, आपल्या पुता अब्रामाची बायल, घेतलीं; आनी ते कनान देसांत वचपाक कसदी लोकांच्या ऊरांतल्यान भायर सरले; आनी ते हारानांत आयले आनी थंय रावले." },
    { type: "verse", num: 32, text: "आनी तेरहाचे दीस दोनशें पांच वर्सां जाले; आनी तेरह हारानांत मेलो." },
  ],
  "12": [
    { type: "section", text: "देवाचो अब्रामाक आपोवणें" },
    { type: "verse", num: 1, text: "आनी सर्वेस्परान अब्रामाक म्हणलें, 'तुज्या देसांतल्यान आनी तुज्या नात्यागोत्यांतल्यान आनी तुज्या बापायच्या घरांतल्यान भायर सर, आनी हांव तुका दाखयतलों त्या देसांत वच.'" },
    { type: "verse", num: 2, text: "'आनी हांव तुजेपसून एक व्हड राष्ट्र करतलों, आनी तुका आशीर्वाद दितलों, आनी तुजें नांव व्हड करतलों; आनी तूं आशीर्वाद जातलो.'" },
    { type: "verse", num: 3, text: "'आनी तुका आशीर्वाद दितात त्यांकां हांव आशीर्वाद दितलों, आनी तुका शाप दिता ताका हांव शाप दितलों; आनी तुजे वरवीं पृथ्वीचीं सगळीं कुळां आशीर्वादीत जातलीं.'" },
    { type: "verse", num: 4, text: "आनी सर्वेस्परान ताका सांगिल्लेप्रमाणें अब्राम गेलो; आनी लोट ताचेकडेन गेलो. आनी हारानांतल्यान भायर सरताना अब्राम पंच्यात्तर वर्सांचो आसलो." },
    { type: "verse", num: 5, text: "आनी अब्रामान आपली बायल साराय, आनी आपल्या भावाचो पूत लोट, आनी तांणीं हारानांत मेळयिल्ली सगळी संपत्ती, आनी तांणीं हारानांत मेळयिल्ले प्राणी घेतले; आनी ते कनान देसांत वचपाक भायर सरले; आनी ते कनान देसांत आयले." },
    { type: "verse", num: 6, text: "आनी अब्राम शखेमाच्या जाग्यामेरेन, मोरे हांगासरल्या अलोन झाडामेरेन देसांतल्यान गेलो. आनी त्या वेळार कनानी त्या देसांत आसले." },
    { type: "verse", num: 7, text: "आनी सर्वेस्पर अब्रामाक दिसलो आनी म्हणलें, 'तुज्या संततीक हांव हो देस दितलों.' आनी ताका दिसिल्ल्या सर्वेस्पराक ताणें थंय एक वेदी बांदली." },
    { type: "verse", num: 8, text: "आनी थंयसून तो बेथेलाच्या उदेंतेकडल्या दोंगराकडेन गेलो आनी आपलो तंबू मारलो, अस्तंतेक बेथेल आनी उदेंतेक आय आसताना; आनी ताणें थंय सर्वेस्पराक एक वेदी बांदली आनी सर्वेस्पराच्या नांवान प्रार्थना केली." },
    { type: "verse", num: 9, text: "आनी अब्राम दक्षिणेकडेन चलत रावलो." },
    { type: "section", text: "अब्राम ईजिप्तांत" },
    { type: "verse", num: 10, text: "आनी त्या देसांत दुकाळ आसलो; आनी अब्राम ईजिप्तांत थंय रावपाक गेलो; कारण देसांत दुकाळ कठीण आसलो." },
    { type: "verse", num: 11, text: "आनी ईजिप्तांत भितर सरपाक लागताना ताणें आपल्या बायलेक सारायेक म्हणलें, 'पळय, हांव जाणां तूं सोबीत दिसपी बायल.' " },
    { type: "verse", num: 12, text: "'आनी ईजिप्ती लोक तुका पळयतले तेन्ना ते म्हणतले, ही ताची बायल; आनी ते म्हाका मारतले, पूण तुका जिवी दवरतले.'" },
    { type: "verse", num: 13, text: "'तूं म्हजी भयण म्हूण सांग, म्हणचे तुजे वरवीं म्हाका बरें जातलें, आनी तुजे खातीर म्हजो जीव वाचतलो.'" },
    { type: "verse", num: 14, text: "आनी अब्राम ईजिप्तांत आयलो तेन्ना ईजिप्ती लोकांनी बायल खूब सोबीत म्हूण पळयली." },
    { type: "verse", num: 15, text: "आनी फारोच्या अधिकाऱ्यांनी तिका पळयली आनी फारोमुखार तिची तोखणाय केली; आनी बायलेक फारोच्या घरांत व्हेली." },
    { type: "verse", num: 16, text: "आनी तिचे खातीर ताणें अब्रामाक बरें केलें; आनी ताका मेंढरां, बैल, गाडवां, चाकर, चाकर्णी, गाडवी आनी उंट मेळ्ळे." },
    { type: "verse", num: 17, text: "आनी सर्वेस्परान अब्रामाची बायल साराय हिचे खातीर फारोक आनी ताच्या घराक व्हड पिडांनी मारलें." },
    { type: "verse", num: 18, text: "आनी फारोन अब्रामाक आपयलो आनी म्हणलें, 'तूं म्हाका हें कितें केलें? ती तुजी बायल म्हूण तूं म्हाका कित्याक सांगलें ना?'" },
    { type: "verse", num: 19, text: "'ती म्हजी भयण म्हूण तूं कित्याक म्हणलो? म्हणून हांवें तिका म्हजी बायल करून घेतली. आतां पळय, तुजी बायल हांगा; तिका घे आनी वच.'" },
    { type: "verse", num: 20, text: "आनी फारोन ताचेविशीं मनशांक आज्ञा दिली; आनी तांणीं ताका आनी ताची बायल आनी ताचें सगळें धाडलें." },
  ],
  "13": [
    { type: "section", text: "अब्राम आनी लोट वेगळे जाले" },
    { type: "verse", num: 1, text: "आनी अब्राम ईजिप्तांतल्यान, तो आनी ताची बायल आनी ताचें सगळें, आनी ताचेकडेन लोट, दक्षिणेकडेन वयर गेलो." },
    { type: "verse", num: 2, text: "आनी अब्राम गोरवांनी, रुप्यान आनी भांगरान खूब गिरेस्त आसलो." },
    { type: "verse", num: 3, text: "आनी तो दक्षिणेपसून बेथेलामेरेन आपल्या प्रवासांनी गेलो, त्या जाग्यामेरेन जंय सुरवातेक ताचो तंबू आसलो, बेथेल आनी आय हांचेमदीं;" },
    { type: "verse", num: 4, text: "जंय ताणें पयलीं वेदी बांदिल्ली; आनी थंय अब्रामान सर्वेस्पराच्या नांवान प्रार्थना केली." },
    { type: "verse", num: 5, text: "आनी अब्रामाकडेन आशिल्ल्या लोटाकूय मेंढरां, गोरवां आनी तंबू आसले." },
    { type: "verse", num: 6, text: "आनी तो देस तांकां एकठांय रावपाक पुरो जालो ना; कारण तांची संपत्ती इतली चड आसली की ते एकठांय रावपाक शकले नात." },
    { type: "verse", num: 7, text: "आनी अब्रामाच्या गोरवांच्या गोवळ्यांमदीं आनी लोटाच्या गोरवांच्या गोवळ्यांमदीं झगडीं जालीं; आनी त्या वेळार कनानी आनी परिज्जी त्या देसांत रावताले." },
    { type: "verse", num: 8, text: "आनी अब्रामान लोटाक म्हणलें, 'म्हजेमदीं आनी तुजेमदीं, आनी म्हज्या गोवळ्यांमदीं आनी तुज्या गोवळ्यांमदीं झगडें आसूंक फावना; कारण आमी भावभाव.'" },
    { type: "verse", num: 9, text: "'सगळो देस तुजेमुखार ना? म्हजेपसून वेगळो जा; तूं दाव्या वाटेन गेलो जाल्यार हांव उजव्या वाटेन वतलों; वा तूं उजव्या वाटेन गेलो जाल्यार हांव दाव्या वाटेन वतलों.'" },
    { type: "verse", num: 10, text: "आनी लोटान दोळे उखलून यॉर्दन देगणाचो सगळो मळ पळयलो, की तो सगळो भिजयिल्लो आसलो, सर्वेस्परान सदोम आनी गमोरा नाश करचेपयलीं, सोआरामेरेन सर्वेस्पराच्या बागेसारको, ईजिप्त देसासारको." },
    { type: "verse", num: 11, text: "आनी लोटान यॉर्दन देगणाचो सगळो मळ आपल्याक वेंचलो; आनी लोट उदेंतेकडेन गेलो; आनी ते एकामेकांपसून वेगळे जाले." },
    { type: "verse", num: 12, text: "अब्राम कनान देसांत रावलो, आनी लोट मळाच्या शारांनी रावलो, आनी सदोमामेरेन तंबू मारले." },
    { type: "verse", num: 13, text: "पूण सदोमाचे मनीस सर्वेस्परामुखार खूब वायट आनी पातकी आसले." },
    { type: "verse", num: 14, text: "आनी लोट ताचेपसून वेगळो जाल्या उपरांत सर्वेस्परान अब्रामाक म्हणलें, 'तुजे दोळे उखल आनी तूं आसा त्या जाग्यापसून उत्तरेकडेन, दक्षिणेकडेन, उदेंतेकडेन आनी अस्तंतेकडेन पळय;'" },
    { type: "verse", num: 15, text: "'कारण तूं पळयता तो सगळो देस हांव तुका आनी तुज्या संततीक सदांकाळ दितलों.'" },
    { type: "verse", num: 16, text: "'आनी हांव तुजी संतत पृथ्वीच्या धुल्लेसारकी करतलों; कोणूय पृथ्वीची धुल्ल मेजूंक शकता जाल्यार, तुजी संततूय मेजतली.'" },
    { type: "verse", num: 17, text: "'ऊठ, ह्या देसाच्या लांबायेन आनी रुंदायेन भोंव; कारण हांव तो तुका दितलों.'" },
    { type: "verse", num: 18, text: "आनी अब्रामान आपलो तंबू हालयलो आनी हेब्रोनांतल्या मम्रेच्या अलोन झाडांलागीं रावपाक आयलो; आनी ताणें थंय सर्वेस्पराक एक वेदी बांदली." },
  ],
  "14": [
    { type: "section", text: "अब्रामान लोटाक सोडयलो" },
    { type: "verse", num: 1, text: "आनी शिनाराचो राजा अम्राफेल, एल्लासाराचो राजा अर्योख, एलामाचो राजा कदोर्लाओमेर आनी गोयीमाचो राजा तिदाल हांच्या दिसांनी," },
    { type: "verse", num: 2, text: "तांणीं सदोमाचो राजा बेरा, गमोराचो राजा बिर्शा, अदमाचो राजा शिनाब, सबोयीमाचो राजा शमेबेर आनी बेला (म्हणजे सोआर) हाचो राजा हांचेआड झूज केलें." },
    { type: "verse", num: 3, text: "हे सगळे सिद्दीम देगणांत एकठांय जाले, जो खारें दर्या." },
    { type: "verse", num: 4, text: "बारा वर्सां ते कदोर्लाओमेराची सेवा करताले, आनी तेराव्या वर्सा ते विरोधांत उठले." },
    { type: "verse", num: 5, text: "आनी चवदाव्या वर्सा कदोर्लाओमेर आनी ताचेकडेन आशिल्ले राजा आयले आनी अश्तरोथ-कर्णायीमांत रफायांक, हामांत जूजीमांक, शावे-किर्याथायीमांत एमीमांक मारले." },
    { type: "verse", num: 6, text: "आनी होरीमांक तांच्या सेईर दोंगरांत, रानांतल्या एल-पारानामेरेन मारले." },
    { type: "verse", num: 7, text: "आनी ते परत एन-मिश्पात (म्हणजे कादेश) हांगासर आयले, आनी अमालेकींचो सगळो देस आनी हससोन-तामारांत रावपी अमोरींकूय मारलें." },
    { type: "verse", num: 8, text: "आनी सदोमाचो राजा, गमोराचो राजा, अदमाचो राजा, सबोयीमाचो राजा आनी बेलाचो (म्हणजे सोआर) राजा भायर सरले; आनी सिद्दीम देगणांत तांचेआड झुजाक उबे जाले." },
    { type: "verse", num: 9, text: "एलामाचो राजा कदोर्लाओमेर, गोयीमाचो राजा तिदाल, शिनाराचो राजा अम्राफेल आनी एल्लासाराचो राजा अर्योख हांचेआड; चार राजा पांच राजांआड." },
    { type: "verse", num: 10, text: "आनी सिद्दीम देगण डांबराच्या खड्ड्यांनी भरिल्लें; आनी सदोम आनी गमोराचे राजा पळून गेले आनी थंय पडले; आनी उरिल्ले दोंगरांक पळून गेले." },
    { type: "verse", num: 11, text: "आनी तांणीं सदोम आनी गमोराची सगळी संपत्ती आनी तांचें सगळें खाणां घेतलें आनी गेले." },
    { type: "verse", num: 12, text: "आनी तांणीं अब्रामाच्या भावाचो पूत लोट, जो सदोमांत रावतालो, ताका आनी ताची संपत्ती घेवन गेले." },
    { type: "verse", num: 13, text: "आनी एक सुटिल्ल्यान येवन इब्री अब्रामाक सांगलें; तो अमोरी मम्रेच्या अलोन झाडांलागीं रावतालो, एश्कोल आनी आनेर हांचो भाव; आनी ते अब्रामाचे कराराचे भागीदार आसले." },
    { type: "verse", num: 14, text: "आनी अब्रामान आपलो भाव बंदखणींत पडलो म्हूण आयकलें तेन्ना, ताणें आपल्या घरांत जल्मिल्ल्या तीनशें अठरा तरबेजदार मनशांक भायर काडलें आनी दानामेरेन तांचो फाटलाग केलो." },
    { type: "verse", num: 15, text: "आनी ताणें रातीक आपल्या चाकरांक तांचेआड विभागलें, आनी तांकां मारलें, आनी दमास्कसाच्या दाव्या वाटेन आशिल्ल्या होबामेरेन तांचो फाटलाग केलो." },
    { type: "verse", num: 16, text: "आनी ताणें सगळी संपत्ती परत हाडली, आनी आपलो भाव लोट आनी ताची संपत्ती, आनी बायलांक आनी लोकांकूय परत हाडलें." },
    { type: "section", text: "मेल्कीसेदेकान अब्रामाक आशीर्वाद दिलो" },
    { type: "verse", num: 17, text: "आनी कदोर्लाओमेराक आनी ताचेकडेन आशिल्ल्या राजांक मारून तो परत आयलो उपरांत, सदोमाचो राजा शावे देगणांत ताका मेळपाक भायर सरलो, जो राजाचो देगण." },
    { type: "verse", num: 18, text: "आनी शालेमाचो राजा मेल्कीसेदेक भाकर आनी द्राक्षारस भायर हाडलो; आनी तो परमेश्वराचो याजक आसलो." },
    { type: "verse", num: 19, text: "आनी ताणें ताका आशीर्वाद दिलो आनी म्हणलें, 'ससर्ग आनी पृथ्वीचो धनी परमेश्वराकडसून अब्राम आशीर्वादीत.'" },
    { type: "verse", num: 20, text: "'आनी परमेश्वर, ज्याणें तुज्या दुस्मानांक तुज्या हातांत दिल्यात, तो धन्य.' आनी अब्रामान ताका सगळ्यांतलो दशांश दिलो." },
    { type: "verse", num: 21, text: "आनी सदोमाच्या राजान अब्रामाक म्हणलें, 'म्हाका प्राणी दी, आनी संपत्ती तूं आपल्याक घे.'" },
    { type: "verse", num: 22, text: "आनी अब्रामान सदोमाच्या राजाक म्हणलें, 'ससर्ग आनी पृथ्वीचो धनी सर्वेस्पर देवाकडेन हांवें हात उखल्लो;'" },
    { type: "verse", num: 23, text: "'एक सुतूय तुजें, एक वाणाचो पट्टोय तुजो, हांव घेवचों ना, म्हणचे तूं म्हणचो ना, हांवें अब्रामाक गिरेस्त केलो.'" },
    { type: "verse", num: 24, text: "'म्हाका कांयच नाका; फकत भुरग्यांनी जें खालें तें, आनी म्हजेकडेन गेल्ल्या मनशांचो वांटो, आनेर, एश्कोल आनी मम्रे; तांकां तांचो वांटो घेवंदीत.'" },
  ],
  "15": [
    { type: "section", text: "देवाचो अब्रामाकडेन करार" },
    { type: "verse", num: 1, text: "ह्या गजालीं उपरांत सर्वेस्पराचें उतर अब्रामाक दर्शनांत आयलें: 'अब्राम, भियेवंका नाका; हांव तुजी ढाल; तुजें इनाम खूब व्हड.'" },
    { type: "verse", num: 2, text: "आनी अब्रामान म्हणलें, 'सर्वेस्पर देवा, तूं म्हाका कितें दितलो? कारण हांव भुरग्यांबगर वतां, आनी म्हज्या घराचो वारसदार दमास्कसचो एलीएजेर.'" },
    { type: "verse", num: 3, text: "आनी अब्रामान म्हणलें, 'पळय, तूं म्हाका संतान दिवंक ना; आनी पळय, म्हज्या घरांत जल्मिल्लो एकलो म्हजो वारसदार.'" },
    { type: "verse", num: 4, text: "आनी पळय, सर्वेस्पराचें उतर ताका आयलें: 'हो तुजो वारसदार जावचो ना; पूण तुज्या कुडीतल्यान येतलो तो तुजो वारसदार जातलो.'" },
    { type: "verse", num: 5, text: "आनी ताणें ताका भायर व्हेलो आनी म्हणलें, 'मळबाकडेन पळय आनी नखेत्रां मेजूंक शकता जाल्यार मेज.' आनी ताणें ताका म्हणलें, 'तशी तुजी संतत आसतली.'" },
    { type: "verse", num: 6, text: "आनी ताणें सर्वेस्पराचेर विस्वास दवरलो; आनी ताणें ताका तें नीत मानलें." },
    { type: "verse", num: 7, text: "आनी ताणें ताका म्हणलें, 'हांव सर्वेस्पर, ज्याणें तुका कसदी लोकांच्या ऊरांतल्यान भायर काडलो, तुका हो देस वारशान दिवपाक.'" },
    { type: "verse", num: 8, text: "आनी ताणें म्हणलें, 'सर्वेस्पर देवा, हांव तो वारशान घेतलों म्हूण म्हाका कशें कळटलें?'" },
    { type: "verse", num: 9, text: "आनी ताणें ताका म्हणलें, 'म्हजेकडेन तीन वर्सांची एक कालवड, तीन वर्सांची एक बोकडी, तीन वर्सांचो एक मेंढो, एक कापशी आनी एक पारव्याचें पिल्लूं हाड.'" },
    { type: "verse", num: 10, text: "आनी ताणें हीं सगळीं ताचेकडेन हाडलीं, आनी तीं मदींच कापलीं, आनी दरेक अर्दें एकामेकांमुखार दवरलें; पूण सुकण्यांक ताणें कापलीं ना." },
    { type: "verse", num: 11, text: "आनी गिदां मांसाचेर देंवलीं, आनी अब्रामान तांकां धांवडायलीं." },
    { type: "verse", num: 12, text: "आनी सूर्य बुडताना, अब्रामाचेर गाढ न्हीद पडली; आनी पळय, भिरांत, व्हड काळोख ताचेर पडलो." },
    { type: "verse", num: 13, text: "आनी ताणें अब्रामाक म्हणलें, 'खात्रीन जाण, तुजी संतत परक्या देसांत परदेशी आसतली, आनी ते तांची सेवा करतले, आनी ते तांकां चारशें वर्सां पिडतले.'" },
    { type: "verse", num: 14, text: "'पूण ज्या राष्ट्राची ते सेवा करतले, ताचो हांव न्याय करतलों; आनी त्या उपरांत ते खूब संपत्तीन भायर सरतले.'" },
    { type: "verse", num: 15, text: "'आनी तूं आपल्या बापायांकडेन शांतीन वतलो; तुका बऱ्या म्हातारपणांत पुरतले.'" },
    { type: "verse", num: 16, text: "'पूण चवथ्या पिळगेंत ते हांगा परत येतले; कारण अमोरींची दुश्टकाय अजून पुरी जावंक ना.'" },
    { type: "verse", num: 17, text: "आनी सूर्य बुडलो आनी काळोख जालो तेन्ना पळय, धुंवर येवपी भट्टी आनी उज्याची मशाल त्या कापिल्ल्या कुडक्यांमदल्यान गेली." },
    { type: "verse", num: 18, text: "त्या दिसा सर्वेस्परान अब्रामाकडेन करार केलो: 'तुज्या संततीक हांव हो देस दिलो, ईजिप्ताच्या न्हंयेपसून व्हड न्हंय युफ्रातेसामेरेन;'" },
    { type: "verse", num: 19, text: "'केनीम, कनिज्जीम, कदमोनीम,'" },
    { type: "verse", num: 20, text: "'हित्ती, परिज्जी, रफायीम,'" },
    { type: "verse", num: 21, text: "'अमोरी, कनानी, गिर्गाशी आनी यबूसी हांचो.'" },
  ],
  "16": [
    { type: "section", text: "हागार आनी इश्माएल" },
    { type: "verse", num: 1, text: "आनी अब्रामाची बायल साराय तिका भुरगीं जल्मूंक नासलीं; आनी तिचेकडेन एक ईजिप्ती चाकर्णी आसली, तिचें नांव हागार." },
    { type: "verse", num: 2, text: "आनी सारायेन अब्रामाक म्हणलें, 'पळय, सर्वेस्परान म्हाका भुरगें जल्मपापसून आडायल्या; म्हजी चाकर्णीकडेन वच; कदाचीत तिचे वरवीं म्हाका भुरगीं मेळतलीं.' आनी अब्रामान सारायेचें उतर आयकलें." },
    { type: "verse", num: 3, text: "आनी अब्राम कनान देसांत धा वर्सां रावल्या उपरांत, अब्रामाची बायल सारायेन आपली ईजिप्ती चाकर्णी हागार आपल्या घोवा अब्रामाक बायल म्हूण दिली." },
    { type: "verse", num: 4, text: "आनी तो हागारेकडेन गेलो, आनी ती गुरवार जाली; आनी ती गुरवार जाल्या म्हूण तिणें पळयलें तेन्ना तिच्या दोळ्यांत तिची धनीण कमी जाली." },
    { type: "verse", num: 5, text: "आनी सारायेन अब्रामाक म्हणलें, 'म्हजेर जाल्लो अन्याय तुजेचेर; हांवें म्हजी चाकर्णी तुज्या कुशींत दिली; आनी ती गुरवार जाल्या म्हूण तिणें पळयलें तेन्ना हांव तिच्या दोळ्यांत कमी जालें. सर्वेस्पर म्हजेमदीं आनी तुजेमदीं न्याय करूं.'" },
    { type: "verse", num: 6, text: "पूण अब्रामान सारायेक म्हणलें, 'पळय, तुजी चाकर्णी तुज्या हातांत; तुका बरें दिसता तशें तिका कर.' आनी सारायेन तिका कठीण केलें, आनी ती तिच्या मुखापसून पळून गेली." },
    { type: "verse", num: 7, text: "आनी सर्वेस्पराच्या दुताक रानांत उदकाच्या झऱ्यालागीं, शूराच्या वाटेवयल्या झऱ्यालागीं ती मेळ्ळी." },
    { type: "verse", num: 8, text: "आनी ताणें म्हणलें, 'हागार, सारायेच्या चाकर्णी, तूं खंयसून आयली आनी तूं खंय वता?' आनी तिणें म्हणलें, 'हांव म्हज्या धनीणी सारायेच्या मुखापसून पळून वतां.'" },
    { type: "verse", num: 9, text: "आनी सर्वेस्पराच्या दुतान तिका म्हणलें, 'तुज्या धनीणीकडेन परत वच, आनी तिच्या हाताखाला रहा.'" },
    { type: "verse", num: 10, text: "आनी सर्वेस्पराच्या दुतान तिका म्हणलें, 'हांव तुजी संतत खूब वाडयतलों, ती मेजप अशक्य जातली.'" },
    { type: "verse", num: 11, text: "आनी सर्वेस्पराच्या दुतान तिका म्हणलें, 'पळय, तूं गुरवार; आनी तूं एका पुताक जल्म दितली, आनी ताचें नांव इश्माएल दवरतली; कारण सर्वेस्परान तुजें दूख आयकलें.'" },
    { type: "verse", num: 12, text: "'तो रानवट गाडवासारको मनीस जातलो; ताचो हात सगळ्यांआड, आनी सगळ्यांचो हात ताचेआड; आनी तो आपल्या सगळ्या भावांमुखार रावतलो.'" },
    { type: "verse", num: 13, text: "आनी तिणें तिचेकडेन उलयिल्ल्या सर्वेस्पराचें नांव 'तूं पळोवपी देव' म्हणलें; कारण तिणें म्हणलें, 'म्हाका पळयतल्याक हांवें हांगा पळयलो?'" },
    { type: "verse", num: 14, text: "देखून त्या हांडाचें नांव बएर-लहय-रोई दवरलें; पळय, तें कादेश आनी बेरेद हांचेमदीं आसा." },
    { type: "verse", num: 15, text: "आनी हागारेन अब्रामाक एक पूत जल्म दिलो; आनी अब्रामान हागारेन जल्म दिल्ल्या आपल्या पुताचें नांव इश्माएल दवरलें." },
    { type: "verse", num: 16, text: "आनी हागारेन अब्रामाक इश्माएलाक जल्म दिलो तेन्ना अब्राम श्यांशीं स वर्सांचो आसलो." },
  ],
  "17": [
    { type: "section", text: "सुनतेचो करार" },
    { type: "verse", num: 1, text: "आनी अब्राम णव्याण्णव वर्सांचो जालो तेन्ना सर्वेस्पर अब्रामाक दिसलो आनी ताका म्हणलें, 'हांव सर्वशक्तीमान देव; म्हजेमुखार चल आनी निर्दोष जा.'" },
    { type: "verse", num: 2, text: "'आनी हांव म्हजो करार म्हजेमदीं आनी तुजेमदीं करतलों, आनी तुका खूब खूब वाडयतलों.'" },
    { type: "verse", num: 3, text: "आनी अब्राम तोंडार पडलो; आनी देवान ताचेकडेन उलयलो:" },
    { type: "verse", num: 4, text: "'पळय, हांव; म्हजो करार तुजेकडेन आसा, आनी तूं जायत्या राष्ट्रांचो बापूय जातलो.'" },
    { type: "verse", num: 5, text: "'आनी तुजें नांव अब्राम म्हणचे नात; पूण तुजें नांव अब्राहाम जातलें; कारण हांवें तुका जायत्या राष्ट्रांचो बापूय केला.'" },
    { type: "verse", num: 6, text: "'आनी हांव तुका खूब खूब फळां दितलों, आनी तुजेपसून राष्ट्रां करतलों, आनी तुजेपसून राजा येतले.'" },
    { type: "verse", num: 7, text: "'आनी हांव म्हजो करार म्हजेमदीं आनी तुजेमदीं आनी तुज्या उपरांत तुज्या संततीमदीं तांच्या पिळग्यांमदीं सदांकाळचो करार म्हूण स्थापन करतलों, तुजो आनी तुज्या उपरांत तुज्या संततीचो देव जावपाक.'" },
    { type: "verse", num: 8, text: "'आनी हांव तुका आनी तुज्या उपरांत तुज्या संततीक, तूं परदेशी म्हूण रावता तो कनान देस, सगळो देस सदांकाळचो वारसो म्हूण दितलों; आनी हांव तांचो देव जातलों.'" },
    { type: "verse", num: 9, text: "आनी देवान अब्राहामाक म्हणलें, 'आनी तूं म्हजो करार सांबाळ, तूं आनी तुज्या उपरांत तुजी संतत तांच्या पिळग्यांमदीं.'" },
    { type: "verse", num: 10, text: "'हो म्हजो करार, जो तुमी सांबाळतलात, म्हजेमदीं आनी तुमचेमदीं आनी तुज्या उपरांत तुज्या संततीमदीं: तुमचो दरेक दादलो सुनत करतलो.'" },
    { type: "verse", num: 11, text: "'आनी तुमी तुमच्या मांसाच्या आगच्या कातडीची सुनत करतलात; आनी ती म्हजेमदीं आनी तुमचेमदीं कराराचें चिन्न आसतलें.'" },
    { type: "verse", num: 12, text: "'आनी आठ दिसांचो जालो ताची तुमचे मदीं सुनत जातली, दरेक दादल्याची, तुमच्या पिळग्यांमदीं, घरांत जल्मिल्लो वा तुज्या संततीचो नाशिल्ल्या कोणत्याय परक्या मनशाकडसून रुप्यान विकत घेतिल्लो.'" },
    { type: "verse", num: 13, text: "'तुज्या घरांत जल्मिल्ल्याची आनी तुज्या रुप्यान विकत घेतिल्ल्याची सुनत जावंकूच जाय; आनी म्हजो करार तुमच्या मांसांत सदांकाळचो करार आसतलो.'" },
    { type: "verse", num: 14, text: "'आनी ज्या दादल्याच्या मांसाच्या आगच्या कातडीची सुनत जावंक ना, त्या प्राण्याक ताच्या लोकांमदल्यान काडून उडयतलो; ताणें म्हजो करार मोडला.'" },
    { type: "verse", num: 15, text: "आनी देवान अब्राहामाक म्हणलें, 'तुजी बायल साराय, तिचें नांव साराय म्हणचो ना; पूण तिचें नांव सारा जातलें.'" },
    { type: "verse", num: 16, text: "'आनी हांव तिका आशीर्वाद दितलों, आनी तिचेपसून तुका एक पूत दितलों; हय, हांव तिका आशीर्वाद दितलों, आनी ती राष्ट्रांची आवय जातली; तिचेपसून लोकांचे राजा येतले.'" },
    { type: "verse", num: 17, text: "तेन्ना अब्राहाम तोंडार पडलो आनी हांसलो, आनी आपल्या काळजांत म्हणलें, 'शंभर वर्सांच्या मनशाक भुरगें जल्मतलें? आनी सारा, णव्वद वर्सांची, जल्म दितली?'" },
    { type: "verse", num: 18, text: "आनी अब्राहामान देवाक म्हणलें, 'इश्माएल तुजेमुखार जगूंदी!'" },
    { type: "verse", num: 19, text: "आनी देवान म्हणलें, 'ना, पूण तुजी बायल सारा तुका एक पूत जल्म दितली; आनी तूं ताचें नांव इसाक दवरतलो; आनी हांव ताचेकडेन म्हजो करार ताच्या उपरांत ताच्या संतती खातीर सदांकाळचो करार म्हूण स्थापन करतलों.'" },
    { type: "verse", num: 20, text: "'आनी इश्माएलाविशीं हांवें तुजें आयकलां; पळय, हांवें ताका आशीर्वाद दिला, आनी ताका फळां दितलों आनी ताका खूब खूब वाडयतलों; तो बारा अधिपतींक जल्म दितलो, आनी हांव ताका एक व्हड राष्ट्र करतलों.'" },
    { type: "verse", num: 21, text: "'पूण म्हजो करार हांव इसाकाकडेन स्थापन करतलों, जाका सारा तुका फुडल्या वर्सा ह्या ठरायिल्ल्या वेळार जल्म दितली.'" },
    { type: "verse", num: 22, text: "आनी ताचेकडेन उलोवन जाले उपरांत, देव अब्राहामासावन वयर गेलो." },
    { type: "verse", num: 23, text: "आनी अब्राहामान आपलो पूत इश्माएल आनी आपल्या घरांत जल्मिल्ले सगळे आनी आपल्या रुप्यान विकत घेतिल्ले सगळे, अब्राहामाच्या घरांतल्या मनशांमदलो दरेक दादलो घेतलो, आनी त्याच दिसा तांच्या मांसाच्या आगच्या कातडीची सुनत केली, जशें देवान ताका सांगिल्लें." },
    { type: "verse", num: 24, text: "आनी ताच्या मांसाच्या आगच्या कातडीची सुनत जाली तेन्ना अब्राहाम णव्याण्णव वर्सांचो आसलो." },
    { type: "verse", num: 25, text: "आनी ताचो पूत इश्माएल ताच्या मांसाच्या आगच्या कातडीची सुनत जाली तेन्ना तेरा वर्सांचो आसलो." },
    { type: "verse", num: 26, text: "त्याच दिसा अब्राहामाची आनी ताच्या पुता इश्माएलाची सुनत जाली." },
    { type: "verse", num: 27, text: "आनी ताच्या घरांतले सगळे दादले, घरांत जल्मिल्ले आनी परक्या मनशाकडसून रुप्यान विकत घेतिल्ले, ताचेकडेन सुनत जाले." },
  ],
  "18": [
    { type: "section", text: "तीन भेट दिवपी" },
    { type: "verse", num: 1, text: "आनी सर्वेस्पर मम्रेच्या अलोन झाडांलागीं ताका दिसलो; दिसाच्या उश्णतायेंत तो आपल्या तंबूच्या दारांत बसिल्लो." },
    { type: "verse", num: 2, text: "आनी ताणें दोळे उखलून पळयलें, आनी पळय, तीन मनीस ताचेमुखार उबे; आनी तांकां पळयतकूच तो आपल्या तंबूच्या दारांतल्यान तांकां मेळपाक धांवलो आनी भुंयेक लागून नमस्कार केलो." },
    { type: "verse", num: 3, text: "आनी म्हणलें, 'म्हज्या धन्या, तुज्या दोळ्यांत म्हाका कुर्पा मेळ्ळ्या जाल्यार, तुज्या चाकराकडसून चुकून वचूंका नाका.'" },
    { type: "verse", num: 4, text: "'थोडें उदक हाडूंदीत, आनी तुमचे पांय धुयात, आनी झाडासकयल विसव घेयात.'" },
    { type: "verse", num: 5, text: "'आनी हांव एक तुकडो भाकर हाडटलों, म्हणचे तुमचें काळीज भुजयात; त्या उपरांत तुमी मुखार वचात; कारण तुमी आपल्या चाकराकडेन आयल्यात.' आनी ते म्हणाले, 'तूं म्हणता तशें कर.'" },
    { type: "verse", num: 6, text: "आनी अब्राहाम तंबूंत साराकडेन घडघडीन गेलो आनी म्हणलें, 'बेगीन तीन मापां मयद्याचें पीठ घे, मळ आनी भाकऱ्यो कर.'" },
    { type: "verse", num: 7, text: "आनी अब्राहाम गोरवांकडेन धांवलो आनी एक बरो आनी कोवळो वासरू घेतलो आनी तो चाकराक दिलो; आनी ताणें बेगीन तो तयार केलो." },
    { type: "verse", num: 8, text: "आनी ताणें लोणी आनी दूद आनी ताणें तयार केल्लो वासरू घेतलो आनी तांचेमुखार दवरलो; आनी ते खाताले तेन्ना तो तांचेलागीं झाडासकयल उबो रावलो." },
    { type: "verse", num: 9, text: "आनी तांणीं ताका म्हणलें, 'तुजी बायल सारा खंय आसा?' आनी ताणें म्हणलें, 'तंबूंत.'" },
    { type: "verse", num: 10, text: "आनी ताणें म्हणलें, 'हांव खात्रीन फुडल्या वर्सा ह्या वेळार तुजेकडेन परत येतलों; आनी पळय, तुज्या बायलेक साराक एक पूत आसतलो.' आनी सारा ताचे फाटल्यान तंबूच्या दारांत आयकतालें." },
    { type: "verse", num: 11, text: "अब्राहाम आनी सारा म्हातारे, पिरायेन फुडें गेल्ले आसले; साराक बायलांचे प्रकार सोंपिल्ले." },
    { type: "verse", num: 12, text: "देखून सारा आपल्या भितर हांसलें आनी म्हणलें, 'हांव म्हातारी जाल्या उपरांत म्हाका सुख मेळटलें? आनी म्हजो धनीय म्हातारो.'" },
    { type: "verse", num: 13, text: "आनी सर्वेस्परान अब्राहामाक म्हणलें, 'सारा कित्याक हांसलें? हांव म्हातारी जावन खरेंच जल्म दितलें काय?'" },
    { type: "verse", num: 14, text: "'सर्वेस्पराक कांयच कठीण आसा? ठरायिल्ल्या वेळार हांव तुजेकडेन परत येतलों, आनी साराक एक पूत आसतलो.'" },
    { type: "verse", num: 15, text: "तेन्ना सारान न्हयकारलें: 'हांव हांसलें ना;' कारण तिका भंय जाल्लो. पूण ताणें म्हणलें, 'ना; तूं हांसली.'" },
    { type: "section", text: "अब्राहामान सदोमा खातीर विनवणी केली" },
    { type: "verse", num: 16, text: "आनी ते मनीस थंयसून उठले आनी सदोमाकडेन पळयलें; आनी अब्राहाम तांकां वाट दाखोवपाक तांचेकडेन गेलो." },
    { type: "verse", num: 17, text: "आनी सर्वेस्परान म्हणलें, 'हांव करतां तें अब्राहामापसून लिपयतलों?' " },
    { type: "verse", num: 18, text: "'अब्राहाम खात्रीन एक व्हड आनी बळिष्ट राष्ट्र जातलो, आनी ताचे वरवीं पृथ्वीचीं सगळीं राष्ट्रां आशीर्वादीत जातलीं.'" },
    { type: "verse", num: 19, text: "'कारण हांव ताका वळखतां, म्हणचे तो आपल्या भुरग्यांक आनी आपल्या उपरांत आपल्या घराक आज्ञा दितलो, आनी ते सर्वेस्पराची वाट नीत आनी न्याय करून सांबाळतले; म्हणचे सर्वेस्परान अब्राहामाक जें सांगलां तें ताचेर हाडचें.'" },
    { type: "verse", num: 20, text: "आनी सर्वेस्परान म्हणलें, 'सदोम आनी गमोराविशीं बोबाट व्हड, आनी तांचें पातक खूब जड.'" },
    { type: "verse", num: 21, text: "'हांव सकयल वचून पळयतलों, तांणीं सगळेंच म्हजेकडेन आयिल्ल्या बोबाटाप्रमाणें केलां काय; आनी नाजाल्यार हांव जाणतलों.'" },
    { type: "verse", num: 22, text: "आनी ते मनीस थंयसून वळले आनी सदोमाकडेन गेले; पूण अब्राहाम अजून सर्वेस्परामुखार उबो रावलो." },
    { type: "verse", num: 23, text: "आनी अब्राहाम लागीं सरलो आनी म्हणलें, 'तूं नीतीमानाक दुश्टाकडेन नाश करतलो?' " },
    { type: "verse", num: 24, text: "'कदाचीत शारांत पन्नास नीतीमान आसतले; तरी तूं ती सुवात नाश करतलो, आनी तातूंत आशिल्ल्या पन्नास नीतीमानां खातीर ती भोगशीना?' " },
    { type: "verse", num: 25, text: "'नीतीमानाक दुश्टाकडेन मारप तुजेपसून पयस; नीतीमानाक दुश्टासारकें करप तुजेपसून पयस; सगळ्या पृथ्वीचो न्यायाधीश न्याय करचो ना?' " },
    { type: "verse", num: 26, text: "आनी सर्वेस्परान म्हणलें, 'सदोम शारांत म्हाका पन्नास नीतीमान मेळ्ळे जाल्यार, तांचे खातीर सगळी सुवात भोगशीतलों.'" },
    { type: "verse", num: 27, text: "आनी अब्राहामान जाप दिली, 'पळय, हांव धुल्ल आनी राख जावन सर्वेस्पराकडेन उलोवपाक धीट जालों.'" },
    { type: "verse", num: 28, text: "'कदाचीत पन्नास नीतीमानांतल्यान पांच उणे आसतले; पांच उणे आशिल्ल्यान तूं सगळें शार नाश करतलो?' आनी ताणें म्हणलें, 'थंय म्हाका पंचेचाळीस मेळ्ळे जाल्यार हांव नाश करचों ना.'" },
    { type: "verse", num: 29, text: "आनी ताणें परत ताचेकडेन उलयलो आनी म्हणलें, 'कदाचीत थंय चाळीस मेळतले.' आनी ताणें म्हणलें, 'चाळिसां खातीर हांव करचों ना.'" },
    { type: "verse", num: 30, text: "आनी ताणें म्हणलें, 'सर्वेस्पराक राग येवंका नाका, आनी हांव उलयतलों: कदाचीत थंय तीस मेळतले.' आनी ताणें म्हणलें, 'थंय म्हाका तीस मेळ्ळे जाल्यार हांव करचों ना.'" },
    { type: "verse", num: 31, text: "आनी ताणें म्हणलें, 'पळय, हांव सर्वेस्पराकडेन उलोवपाक धीट जालों: कदाचीत थंय वीस मेळतले.' आनी ताणें म्हणलें, 'वीसां खातीर हांव नाश करचों ना.'" },
    { type: "verse", num: 32, text: "आनी ताणें म्हणलें, 'सर्वेस्पराक राग येवंका नाका, आनी हांव आनीक एक खेप उलयतलों: कदाचीत थंय धा मेळतले.' आनी ताणें म्हणलें, 'धां खातीर हांव नाश करचों ना.'" },
    { type: "verse", num: 33, text: "आनी सर्वेस्पर अब्राहामाकडेन उलोवन जालो तेन्ना गेलो; आनी अब्राहाम आपल्या जाग्याक परत गेलो." },
  ],
  "19": [
    { type: "section", text: "सदोम आनी गमोराचो नाश" },
    { type: "verse", num: 1, text: "आनी ते दोन दूत सांजेवेळा सदोमांत आयले; आनी लोट सदोमाच्या दारांत बसिल्लो. लोटान तांकां पळयले तेन्ना तो तांकां मेळपाक उठलो आनी तोंडार भुंयेक नमस्कार केलो." },
    { type: "verse", num: 2, text: "आनी ताणें म्हणलें, 'म्हज्या धन्यांनो, तुमच्या चाकराच्या घरांत येयात आनी रात रावात आनी तुमचे पांय धुयात; आनी तुमी सकाळीं उठून तुमच्या वाटेन वचात.' आनी ते म्हणाले, 'ना; आमी गल्लींत रात रावतले.'" },
    { type: "verse", num: 3, text: "आनी ताणें तांकां खूब आग्रह केलो; आनी ते ताचेकडेन वळले आनी ताच्या घरांत भितर सरले; आनी ताणें तांकां जेवण तयार केलें, आनी बेखमीर भाकऱ्यो भाजल्यो; आनी तांणीं खालें." },
    { type: "verse", num: 4, text: "पूण ते न्हिदचेपयलीं, शाराचे मनीस, सदोमाचे मनीस, भुरग्यांपसून म्हातारींमेरेन, सगळे लोक सगळ्या वाटांनी घराभोंवतणी आयले." },
    { type: "verse", num: 5, text: "आनी तांणीं लोटाक आपयलो आनी ताका म्हणाले, 'आज रातीक तुजेकडेन आयिल्ले मनीस खंय आसात? तांकां आमचेकडेन भायर काड, म्हणचे आमी तांकां वळखूया.'" },
    { type: "verse", num: 6, text: "आनी लोट तांचेकडेन दारांत भायर सरलो आनी दार आपल्या फाटल्यान बंद केलें." },
    { type: "verse", num: 7, text: "आनी म्हणलें, 'म्हज्या भावांनो, अशें वायट करूंका नाकात.'" },
    { type: "verse", num: 8, text: "'पळयात, म्हज्यो दोन धुवो आसात, ज्यांणीं दादल्याक वळखूंक ना; तांकां हांव तुमचेकडेन भायर काडटलों; तुमकां बरें दिसता तशें तांकां करात; फकत ह्या मनशांक कांयच करूंका नाकात; कारण ते म्हज्या छपराच्या सावळ्यांत आयल्यात.'" },
    { type: "verse", num: 9, text: "आनी ते म्हणाले, 'पाटीं सर.' आनी म्हणाले, 'हो एकलो परदेशी म्हूण रावपाक आयलो आनी न्याय करपी जालो! आतां तांचेपरस तुका चड वायट करतले.' आनी तांणीं लोटाचेर खूब जोर केलो आनी दार मोडपाक लागीं सरले." },
    { type: "verse", num: 10, text: "पूण त्या मनशांनी हात लांब करून लोटाक घरांत आपणेकडेन भितर घेतलो आनी दार बंद केलें." },
    { type: "verse", num: 11, text: "आनी घराच्या दारांत आशिल्ल्या मनशांक, ल्हानापसून व्हडामेरेन, तांणीं कुड्ड्या केल्यो; आनी ते दार सोदून थकले." },
    { type: "verse", num: 12, text: "आनी त्या मनशांनी लोटाक म्हणलें, 'हांगा तुजो आनीक कोण आसा? जांवय, तुजे पूत, तुज्यो धुवो, आनी शारांत तुजें जें कितें आसा तें ह्या जाग्यांतल्यान भायर काड.'" },
    { type: "verse", num: 13, text: "'कारण आमी ही सुवात नाश करतले; कारण तांचेआड बोबाट सर्वेस्परामुखार व्हड जाला; आनी सर्वेस्परान आमकां तो नाश करपाक धाडल्यात.'" },
    { type: "verse", num: 14, text: "आनी लोट भायर सरलो आनी ताच्या धुवांक घेवपी जांवयांक सांगलें, 'उठात, ह्या जाग्यांतल्यान भायर सरात; कारण सर्वेस्पर हें शार नाश करतलो.' पूण ताच्या जांवयांक तो खेळ करता अशें दिसलें." },
    { type: "verse", num: 15, text: "आनी उजवाडटाना दुतांनी लोटाक घडघडायलो: 'ऊठ, तुजी बायल आनी तुज्यो दोन धुवो ज्यो हांगा आसात त्यो घे, नाजाल्यार शाराच्या शिक्षेंत तूं नाश जातलो.'" },
    { type: "verse", num: 16, text: "पूण तो कुळकुळत रावलो; तेन्ना त्या मनशांनी ताचो हात आनी ताच्या बायलेचो हात आनी ताच्या दोन धुवांचो हात धरलो, सर्वेस्पराची ताचेर दया आशिल्ली; आनी ताका भायर हाडून शारा भायर दवरलो." },
    { type: "verse", num: 17, text: "आनी तांकां भायर हाडताना ताणें म्हणलें, 'तुज्या जिवा खातीर पळ; फाटीं पळयूंका नाका, आनी मळांत खंयच उबो रावंका नाका; दोंगराक पळ, नाजाल्यार तूं नाश जातलो.'" },
    { type: "verse", num: 18, text: "आनी लोटान तांकां म्हणलें, 'ना, म्हज्या धन्या.'" },
    { type: "verse", num: 19, text: "'पळय, तुज्या चाकराक तुज्या दोळ्यांत कुर्पा मेळ्ळ्या, आनी तूं म्हजो जीव वाचोवपाक म्हजेर केल्ली तुजी दया व्हड; पूण दोंगराक पळपाक म्हाका जायना, नाजाल्यार वायट म्हाका गांठतलें आनी हांव मरतलों.'" },
    { type: "verse", num: 20, text: "'पळय, हें शार पळपाक लागीं, आनी तें ल्हान; थंय हांव पळूंदी — तें ल्हान न्हय? — आनी म्हजो जीव वाचतलो.'" },
    { type: "verse", num: 21, text: "आनी ताणें ताका म्हणलें, 'पळय, ह्या गजालींतूय हांवें तुजें मानलां, तूं सांगता तें शार हांव उध्वस्त करचों ना.'" },
    { type: "verse", num: 22, text: "'बेगीन पळ थंय; कारण तूं थंय पावमेरेन हांव कांयच करूंक शकना.' देखून त्या शाराचें नांव सोआर दवरलें." },
    { type: "verse", num: 23, text: "लोट सोआरांत पावतकूच सूर्य पृथ्वीचेर उदेलो." },
    { type: "verse", num: 24, text: "तेन्ना सर्वेस्परान सदोम आनी गमोरा हांचेर मळबांतल्यान सर्वेस्पराकडसून गंधकाचो आनी उज्याचो पावस हाडलो." },
    { type: "verse", num: 25, text: "आनी ताणें तीं शारां आनी सगळो मळ आनी शारांतले सगळे रावपी आनी भुंयेचेर उगोवपी सगळें उध्वस्त केलें." },
    { type: "verse", num: 26, text: "पूण ताची बायल ताच्या फाटल्यान फाटीं पळयतालें, आनी ती मिठाचो खांब जाली." },
    { type: "verse", num: 27, text: "आनी अब्राहाम सकाळीं उठलो आनी त्या जाग्यार गेलो जंय तो सर्वेस्परामुखार उबो आसलो." },
    { type: "verse", num: 28, text: "आनी ताणें सदोम आनी गमोराकडेन आनी मळाच्या सगळ्या देसाकडेन पळयलें, आनी पळय, भट्टीच्या धुंवरासारको देसांतलो धुंवर वयर सरतालो." },
    { type: "verse", num: 29, text: "आनी देवान मळाचीं शारां नाश केलीं तेन्ना, देवान अब्राहामाची याद केली आनी लोट ज्या शारांनी रावतालो तीं शारां उध्वस्त करताना लोटाक नाशांतल्यान भायर धाडलो." },
    { type: "section", text: "लोट आनी ताच्यो धुवो" },
    { type: "verse", num: 30, text: "आनी लोट सोआरांतल्यान वयर गेलो आनी दोंगरांत रावलो, आनी ताच्यो दोन धुवो ताचेकडेन; कारण ताका सोआरांत रावपाक भंय जालो; आनी तो आनी ताच्यो दोन धुवो एका गुंफेंत रावले." },
    { type: "verse", num: 31, text: "आनी व्हडलेन ल्हानेक म्हणलें, 'आमचो बापूय म्हातारो, आनी सगळ्या पृथ्वीच्या रितीप्रमाणें आमचेकडेन येवपाक पृथ्वीचेर दादलो ना.'" },
    { type: "verse", num: 32, text: "'यो, आपल्या बापायक द्राक्षारस पियोवया, आनी ताचेकडेन न्हिदूया, म्हणचे आपल्या बापायपसून संतत उरोवया.'" },
    { type: "verse", num: 33, text: "आनी तांणीं त्या राती आपल्या बापायक द्राक्षारस पियोवलो; आनी व्हडली भितर गेली आनी आपल्या बापायकडेन न्हिदली; आनी ती न्हिदली वा उठली तें ताका कळलें ना." },
    { type: "verse", num: 34, text: "आनी दुसऱ्या दिसा व्हडलेन ल्हानेक म्हणलें, 'पळय, काल रातीक हांव म्हज्या बापायकडेन न्हिदलें; आज रातीय ताका द्राक्षारस पियोवया; आनी तूं भितर वच आनी ताचेकडेन न्हीद, म्हणचे आपल्या बापायपसून संतत उरोवया.'" },
    { type: "verse", num: 35, text: "आनी तांणीं त्या रातीय आपल्या बापायक द्राक्षारस पियोवलो; आनी ल्हानी उठली आनी ताचेकडेन न्हिदली; आनी ती न्हिदली वा उठली तें ताका कळलें ना." },
    { type: "verse", num: 36, text: "अशें लोटाच्या दोनूय धुवांक आपल्या बापायपसून गर्भ रावलो." },
    { type: "verse", num: 37, text: "आनी व्हडलेन एका पुताक जल्म दिलो आनी ताचें नांव मोआब दवरलें; तो आयच्या मोआबींचो बापूय." },
    { type: "verse", num: 38, text: "आनी ल्हानेनूय एका पुताक जल्म दिलो आनी ताचें नांव बेन-अम्मी दवरलें; तो आयच्या अम्मोनींचो बापूय." },
  ],
  "20": [
    { type: "section", text: "अब्राहाम आनी अबीमेलेख" },
    { type: "verse", num: 1, text: "आनी अब्राहाम थंयसून दक्षिणेच्या देसांत गेलो, आनी कादेश आनी शूर हांचेमदीं रावलो; आनी तो गरारांत परदेशी जालो." },
    { type: "verse", num: 2, text: "आनी अब्राहामान आपल्या बायलेक सारा हिचेविशीं म्हणलें, 'ती म्हजी भयण.' आनी गराराचो राजा अबीमेलेखान साराक धाडून हाडली." },
    { type: "verse", num: 3, text: "पूण देवान अबीमेलेखाक रातीक सपनांत आयलो आनी ताका म्हणलें, 'पळय, तूं घेतिल्ल्या बायले खातीर तूं मेल्लो; कारण ती एका मनशाची बायल.'" },
    { type: "verse", num: 4, text: "पूण अबीमेलेख तिचेलागीं गेल्लो ना; आनी ताणें म्हणलें, 'सर्वेस्परा, नीतीमान राष्ट्रालेकूय तूं मारतलो?' " },
    { type: "verse", num: 5, text: "'ताणें म्हाका म्हणलें ना, ती म्हजी भयण? आनी तिणेंय स्वता म्हणलें, तो म्हजो भाव. म्हज्या काळजाच्या शुद्धतायेन आनी म्हज्या हातांच्या निर्दोषपणान हांवें हें केलें.'" },
    { type: "verse", num: 6, text: "आनी देवान सपनांत ताका म्हणलें, 'हय, हांव जाणां तूं तुज्या काळजाच्या शुद्धतायेन हें केलें, आनी म्हणून हांवेंच तुका म्हजेआड पातक करपापसून आडायलो; देखून हांवें तुका तिका लागपाक दिलें ना.'" },
    { type: "verse", num: 7, text: "'आतां त्या मनशाची बायल परत दी; कारण तो प्रवादी, आनी तो तुजे खातीर प्रार्थना करतलो, आनी तूं जिवो उरतलो; पूण तूं ती परत दिली ना जाल्यार, तूं आनी तुजें सगळें खात्रीन मरतलें म्हूण जाण.'" },
    { type: "verse", num: 8, text: "आनी अबीमेलेख सकाळीं उठलो आनी आपल्या सगळ्या चाकरांक आपयलो आनी ह्यो सगळ्यो गजाली तांच्या कानांत सांगल्यो; आनी ते मनीस खूब भियेले." },
    { type: "verse", num: 9, text: "तेन्ना अबीमेलेखान अब्राहामाक आपयलो आनी ताका म्हणलें, 'तूं आमकां कितें केलें? आनी हांवें तुजेआड कितें पातक केलें, म्हणून तूं म्हजेर आनी म्हज्या राज्याचेर व्हड पातक हाडलें? तूं म्हाका करूंक फावनाशिल्लीं कामां केलीं.'" },
    { type: "verse", num: 10, text: "आनी अबीमेलेखान अब्राहामाक म्हणलें, 'तूं कितें पळयलें, म्हणून तूं हें केलें?'" },
    { type: "verse", num: 11, text: "आनी अब्राहामान म्हणलें, 'कारण हांवें मानलें, ह्या जाग्यार खात्रीन देवाची भिरांत ना; आनी ते म्हज्या बायले खातीर म्हाका मारतले.'" },
    { type: "verse", num: 12, text: "'आनी खरेंच ती म्हजी भयण, म्हज्या बापायची धूव, पूण म्हज्या आवयची धूव न्हय; आनी ती म्हजी बायल जाली.'" },
    { type: "verse", num: 13, text: "'आनी देवान म्हाका म्हज्या बापायच्या घरांतल्यान भोंवडेक धाडलो तेन्ना हांवें तिका म्हणलें, ही तुजी दया म्हजेर करतली: आमी वतात त्या दरेक जाग्यार म्हजेविशीं म्हण, तो म्हजो भाव.'" },
    { type: "verse", num: 14, text: "आनी अबीमेलेखान मेंढरां, बैल, चाकर आनी चाकर्ण्यो घेतल्यो आनी अब्राहामाक दिल्यो, आनी ताची बायल सारा ताका परत दिली." },
    { type: "verse", num: 15, text: "आनी अबीमेलेख म्हणलें, 'पळय, म्हजो देस तुजेमुखार आसा; तुका बरें दिसता थंय रहा.'" },
    { type: "verse", num: 16, text: "आनी साराक ताणें म्हणलें, 'पळय, हांवें तुज्या भावाक रुप्याचीं हजार नाणीं दिल्यांत; पळय, तें तुका तुजेकडेन आशिल्ल्या सगळ्यांमुखार दोळ्यांचें आवरण, आनी सगळ्यांमुखार तूं निर्दोष.'" },
    { type: "verse", num: 17, text: "तेन्ना अब्राहामान देवाकडेन प्रार्थना केली; आनी देवान अबीमेलेखाक आनी ताच्या बायलेक आनी ताच्या चाकर्ण्यांक बरें केलें; आनी तांणीं भुरगीं जल्म दिलीं." },
    { type: "verse", num: 18, text: "कारण अब्राहामाची बायल सारा हिचे खातीर सर्वेस्परान अबीमेलेखाच्या घराचो दरेक गर्भ पुरो बंद केल्लो." },
  ],
  "21": [
    { type: "section", text: "इसाकाचो जल्म" },
    { type: "verse", num: 1, text: "आनी सर्वेस्परान साराक ताणें सांगिल्लेप्रमाणें भेट दिली, आनी सर्वेस्परान साराक ताणें म्हणिल्लेप्रमाणें केलें." },
    { type: "verse", num: 2, text: "आनी सारा गुरवार जाली आनी देवान सांगिल्ल्या ठरायिल्ल्या वेळार अब्राहामाक ताच्या म्हातारपणांत एक पूत जल्म दिलो." },
    { type: "verse", num: 3, text: "आनी अब्राहामान साराकडसून जल्मिल्ल्या आपल्या पुताचें नांव इसाक दवरलें." },
    { type: "verse", num: 4, text: "आनी देवान ताका आज्ञा दिल्लेप्रमाणें अब्राहामान आपल्या पुता इसाकाची आठ दिसांचो जालो तेन्ना सुनत केली." },
    { type: "verse", num: 5, text: "आनी ताचो पूत इसाक जल्मलो तेन्ना अब्राहाम शंभर वर्सांचो आसलो." },
    { type: "verse", num: 6, text: "आनी सारान म्हणलें, 'देवान म्हाका हांसयल्या; जो कोण आयकतलो तो म्हजेकडेन हांसतलो.'" },
    { type: "verse", num: 7, text: "आनी तिणें म्हणलें, 'सारा भुरग्यांक दूद दितली म्हूण अब्राहामाक कोणें सांगिल्लें? कारण ताच्या म्हातारपणांत हांवें ताका पूत जल्म दिलो.'" },
    { type: "verse", num: 8, text: "आनी भुरगें वाडलें आनी ताचें दूद सोडलें; आनी इसाकाचें दूद सोडिल्ल्या दिसा अब्राहामान व्हड जेवणावळ केली." },
    { type: "section", text: "हागार आनी इश्माएलाक धाडलें" },
    { type: "verse", num: 9, text: "आनी ईजिप्ती हागारेन अब्राहामाक जल्म दिल्लो पूत खेळटालो म्हूण सारान पळयलें." },
    { type: "verse", num: 10, text: "तिणें अब्राहामाक म्हणलें, 'ही चाकर्णी आनी तिचो पूत भायर घाल; कारण ह्या चाकर्णीचो पूत म्हज्या पुता इसाकाकडेन वारसदार जावचो ना.'" },
    { type: "verse", num: 11, text: "आनी ही गजाल अब्राहामाच्या दोळ्यांत खूब वायट दिसली, ताच्या पुता खातीर." },
    { type: "verse", num: 12, text: "आनी देवान अब्राहामाक म्हणलें, 'भुरग्या खातीर आनी तुज्या चाकर्णी खातीर तुज्या दोळ्यांत वायट दिसूंका नाका; सारा तुका सांगता तें सगळें आयक; कारण इसाकांत तुजी संतत आपयतली.'" },
    { type: "verse", num: 13, text: "'आनी चाकर्णीच्या पुताचेंय हांव एक राष्ट्र करतलों, कारण तो तुजो संतान.'" },
    { type: "verse", num: 14, text: "आनी अब्राहाम सकाळीं उठलो आनी भाकर आनी उदकाचो बुदकुलो घेतलो आनी हागारेक दिलो, तिच्या खांदाचेर दवरून, आनी भुरग्याक; आनी तिका धाडली. आनी ती गेली आनी बएर-शेबाच्या रानांत भोंवली." },
    { type: "verse", num: 15, text: "आनी बुदकुल्यांतलें उदक सोंपलें, आनी तिणें भुरग्याक एका झुडपासकयल सोडलो." },
    { type: "verse", num: 16, text: "आनी ती वचून बाणाच्या मारा इतल्या पयसुल्ल्यान बसली; कारण तिणें म्हणलें, 'भुरग्याचें मरण हांव पळोवंक शकना.' आनी ती समोर बसली आनी आवाज उखलून रडली." },
    { type: "verse", num: 17, text: "आनी देवान भुरग्याचो आवाज आयकलो; आनी देवाच्या दुतान मळबांतल्यान हागारेक आपयलें आनी तिका म्हणलें, 'हागार, तुका कितें जालें? भियेवंका नाका; कारण भुरगो जंय आसा थंय देवान ताचो आवाज आयकलो.'" },
    { type: "verse", num: 18, text: "'ऊठ, भुरग्याक उखल आनी ताका तुज्या हातान धर; कारण हांव ताचें एक व्हड राष्ट्र करतलों.'" },
    { type: "verse", num: 19, text: "आनी देवान तिचे दोळे उगडले, आनी तिणें उदकाचो हांडो पळयलो; आनी तिणें वचून बुदकुलो उदकान भरलो आनी भुरग्याक पियोवलो." },
    { type: "verse", num: 20, text: "आनी देव भुरग्याकडेन आसलो; आनी तो वाडलो आनी रानांत रावलो आनी बाणकार जालो." },
    { type: "verse", num: 21, text: "आनी तो पारानाच्या रानांत रावलो; आनी ताच्या आवयन ईजिप्त देसांतल्यान ताका बायल घेतली." },
    { type: "section", text: "अब्राहाम आनी अबीमेलेखाचो करार" },
    { type: "verse", num: 22, text: "आनी त्या वेळार अबीमेलेख आनी ताच्या सैन्याचो सेनापती फीकोल अब्राहामाक म्हणाले, 'तूं करता तें सगळें देव तुजेकडेन आसा.'" },
    { type: "verse", num: 23, text: "'आतां हांगा देवाची आण घे, म्हाका वा म्हज्या पुताक वा म्हज्या नातवाक तूं फटयचो ना; पूण हांवें तुका केल्ल्या दयेप्रमाणें तूं म्हाका आनी तूं रावता त्या देसाक कर.'" },
    { type: "verse", num: 24, text: "आनी अब्राहामान म्हणलें, 'हांव आण घेतलों.'" },
    { type: "verse", num: 25, text: "आनी अब्राहामान अबीमेलेखाक उदकाच्या हांड्याविशीं दटायलो, जो अबीमेलेखाच्या चाकरांनी बळान घेतिल्लो." },
    { type: "verse", num: 26, text: "आनी अबीमेलेखान म्हणलें, 'हें कोणें केलें तें म्हाका खबर ना; आनी तूं म्हाका सांगलें ना, आनी आज शिवाय हांवें आयकलें ना.'" },
    { type: "verse", num: 27, text: "आनी अब्राहामान मेंढरां आनी बैल घेतले आनी अबीमेलेखाक दिले; आनी ते दोगांयनी करार केलो." },
    { type: "verse", num: 28, text: "आनी अब्राहामान कळपांतल्यान सात मेंढऱ्यो वेगळ्यो दवरल्यो." },
    { type: "verse", num: 29, text: "आनी अबीमेलेखान अब्राहामाक म्हणलें, 'तूं वेगळ्यो दवरिल्ल्यो ह्यो सात मेंढऱ्यो कित्या?' " },
    { type: "verse", num: 30, text: "आनी ताणें म्हणलें, 'ह्यो सात मेंढऱ्यो तूं म्हजेकडसून घे, म्हणचे तें म्हाका साक्ष आसतलें की हांवें हो हांडो खणलो.'" },
    { type: "verse", num: 31, text: "देखून त्या जाग्याचें नांव बएर-शेबा दवरलें; कारण थंय ते दोगांयनी आण घेतली." },
    { type: "verse", num: 32, text: "अशें तांणीं बएर-शेबांत करार केलो; तेन्ना अबीमेलेख आनी ताच्या सैन्याचो सेनापती फीकोल उठले आनी पलिश्ती देसांत परत गेले." },
    { type: "verse", num: 33, text: "आनी अब्राहामान बएर-शेबांत एक झाड लायलें, आनी थंय सदांकाळच्या देवा सर्वेस्पराच्या नांवान प्रार्थना केली." },
    { type: "verse", num: 34, text: "आनी अब्राहाम पलिश्ती देसांत जायते दीस परदेशी जावन रावलो." },
  ],
  "22": [
    { type: "section", text: "अब्राहामाची परिक्षा" },
    { type: "verse", num: 1, text: "आनी ह्या गजालीं उपरांत देवान अब्राहामाची परिक्षा केली आनी ताका म्हणलें, 'अब्राहाम!' आनी ताणें म्हणलें, 'हांगा हांव.'" },
    { type: "verse", num: 2, text: "आनी ताणें म्हणलें, 'तुजो पूत, तुजो एकलोच, ज्याचो तूं मोग करता, इसाक, ताका घे, आनी मोरिया देसांत वच; आनी थंय हांव तुका सांगतलों त्या एका दोंगरांचेर होमबली म्हूण ताचें अर्पण कर.'" },
    { type: "verse", num: 3, text: "आनी अब्राहाम सकाळीं उठलो आनी आपल्या गाडवाक खोगीर घालें, आनी आपले दोन चाकर आनी आपलो पूत इसाक ताचेकडेन घेतले; आनी होमबलीची लाकडां कापलीं, आनी उठून देवान ताका सांगिल्ल्या जाग्याक गेलो." },
    { type: "verse", num: 4, text: "तिसऱ्या दिसा अब्राहामान दोळे उखलून तो जागो पयसुल्ल्यान पळयलो." },
    { type: "verse", num: 5, text: "आनी अब्राहामान आपल्या चाकरांक म्हणलें, 'तुमी हांगा गाडवाकडेन रावात; आनी हांव आनी भुरगो थंय वतले आनी आराधना करतले आनी तुमचेकडेन परत येतले.'" },
    { type: "verse", num: 6, text: "आनी अब्राहामान होमबलीचीं लाकडां घेतलीं आनी आपल्या पुता इसाकाचेर दवरलीं; आनी आपल्या हातांत उजो आनी सुरी घेतली; आनी ते दोगूय एकठांय गेले." },
    { type: "verse", num: 7, text: "आनी इसाकान आपल्या बापाय अब्राहामाक सांगलें, 'म्हज्या बापा!' आनी ताणें म्हणलें, 'हांगा हांव, म्हज्या पुता.' आनी ताणें म्हणलें, 'उजो आनी लाकडां आसात; पूण होमबलीचो मेंढो खंय?' " },
    { type: "verse", num: 8, text: "आनी अब्राहामान म्हणलें, 'म्हज्या पुता, देवच आपल्याक होमबलीचो मेंढो दितलो.' अशें ते दोगूय एकठांय गेले." },
    { type: "verse", num: 9, text: "आनी देवान ताका सांगिल्ल्या जाग्यार ते आयले; आनी अब्राहामान थंय वेदी बांदली आनी लाकडां मांडलीं, आनी आपल्या पुता इसाकाक बांदलो आनी ताका वेदीचेर, लाकडांचेर दवरलो." },
    { type: "verse", num: 10, text: "आनी अब्राहामान हात लांब करून सुरी घेतली, आपल्या पुताक मारपाक." },
    { type: "verse", num: 11, text: "आनी सर्वेस्पराच्या दुतान मळबांतल्यान ताका आपयलो आनी म्हणलें, 'अब्राहाम, अब्राहाम!' आनी ताणें म्हणलें, 'हांगा हांव.'" },
    { type: "verse", num: 12, text: "आनी ताणें म्हणलें, 'भुरग्याचेर हात घालूंका नाका, आनी ताका कांयच करूंका नाका; कारण आतां हांव जाणां तूं देवाची भिरांत बाळगता, कारण तूं तुजो पूत, तुजो एकलोच, म्हजेपसून आडायलो ना.'" },
    { type: "verse", num: 13, text: "आनी अब्राहामान दोळे उखलून पळयलें, आनी पळय, ताच्या फाटल्यान एक मेंढो झुडपांत शिंगांनी अडकिल्लो; आनी अब्राहामान वचून मेंढो घेतलो आनी आपल्या पुता बदला होमबली म्हूण अर्पण केलो." },
    { type: "verse", num: 14, text: "आनी अब्राहामान त्या जाग्याचें नांव 'सर्वेस्पर दितलो' दवरलें; जशें आज म्हणटात, 'सर्वेस्पराच्या दोंगरांत दितलो.'" },
    { type: "verse", num: 15, text: "आनी सर्वेस्पराच्या दुतान दुसरे खेपे मळबांतल्यान अब्राहामाक आपयलो." },
    { type: "verse", num: 16, text: "आनी म्हणलें, 'म्हजीच आण हांव घेतां, सर्वेस्पर म्हणता, तूं हें केलें आनी तुजो पूत, तुजो एकलोच, आडायलो ना देखून,'" },
    { type: "verse", num: 17, text: "'हांव तुका खात्रीन आशीर्वाद दितलों, आनी तुजी संतत मळबांतल्या नखेत्रांसारकी आनी दर्याच्या तडीवयल्या रेंवेसारकी खूब वाडयतलों; आनी तुजी संतत आपल्या दुस्मानांच्या दारांचो ताबो घेतली.'" },
    { type: "verse", num: 18, text: "'आनी तुज्या संततीवरवीं पृथ्वीचीं सगळीं राष्ट्रां आशीर्वादीत जातलीं; कारण तूं म्हजो आवाज आयकला.'" },
    { type: "verse", num: 19, text: "अशें अब्राहाम आपल्या चाकरांकडेन परत आयलो; आनी ते उठले आनी एकठांय बएर-शेबाक गेले; आनी अब्राहाम बएर-शेबांत रावलो." },
    { type: "verse", num: 20, text: "आनी ह्या गजालीं उपरांत अब्राहामाक सांगलें: 'पळय, मिल्कानूय तुज्या भावा नाहोराक पूत जल्म दिल्यात:'" },
    { type: "verse", num: 21, text: "'ताचो ज्येष्ठ ऊज, आनी ताचो भाव बूज, आनी अरामाचो बापूय कमुएल,'" },
    { type: "verse", num: 22, text: "'आनी केसेद, हजो, पिल्दाश, यिदलाफ आनी बथूएल.'" },
    { type: "verse", num: 23, text: "आनी बथूएलान रिबकाक जल्म दिलो. हे आठ मिल्कान अब्राहामाचो भाव नाहोराक जल्म दिले." },
    { type: "verse", num: 24, text: "आनी ताची उपपत्नी, तिचें नांव रऊमा, तिणेंय तेबह, गहम, तहश आनी माका हांकां जल्म दिलो." },
  ],
  "23": [
    { type: "section", text: "साराचें मरण" },
    { type: "verse", num: 1, text: "आनी साराचें जिवीत एकशें सत्तावीस वर्सां जालें; हीं साराच्या जिविताचीं वर्सां." },
    { type: "verse", num: 2, text: "आनी सारा किर्याथ-अर्बा (म्हणजे हेब्रोन) हांगासर कनान देसांत मेली; आनी अब्राहाम साराक रडपाक आनी शोक करपाक आयलो." },
    { type: "verse", num: 3, text: "आनी अब्राहाम आपल्या मेल्ल्यामुखापसून उठलो, आनी हेथाच्या पुतांकडेन उलयलो:" },
    { type: "verse", num: 4, text: "'हांव तुमचेमदीं परदेशी आनी प्रवासी; तुमचेमदीं म्हाका एक कबराची सुवात दियात, म्हणचे हांव म्हज्या मेल्ल्याक पुरूंक शकतलों.'" },
    { type: "verse", num: 5, text: "आनी हेथाच्या पुतांनी अब्राहामाक जाप दिली:" },
    { type: "verse", num: 6, text: "'म्हज्या धन्या, आमचें आयक; तूं आमचेमदीं देवाचो अधिपती; आमच्या कबरांमदल्या वेंचिक कबरेंत तुज्या मेल्ल्याक पूर; आमचेमदीं कोणूय तुका आपली कबर तुज्या मेल्ल्याक पुरपाक आडायचो ना.'" },
    { type: "verse", num: 7, text: "आनी अब्राहाम उठलो आनी त्या देसाच्या लोकांक, हेथाच्या पुतांक, नमस्कार केलो." },
    { type: "verse", num: 8, text: "आनी ताणें तांचेकडेन उलयलो: 'म्हज्या मेल्ल्याक पुरपाक तुमच्या मनांत आसा जाल्यार, म्हजें आयकात आनी म्हजे खातीर सोहराचो पूत एफ्रोनाक विनवात,'" },
    { type: "verse", num: 9, text: "'म्हणचे तो म्हाका मक्पेलाची गुंफा दिवचो, जी ताच्या शेताच्या शेवटाक आसा; पुरो मोल दिवन तो ती म्हाका तुमचेमदीं कबराची सुवात म्हूण दिवचो.'" },
    { type: "verse", num: 10, text: "आनी एफ्रोन हेथाच्या पुतांमदीं बसिल्लो. आनी हित्ती एफ्रोनान अब्राहामाक हेथाच्या पुतांमुखार, ताच्या शाराच्या दारांत भितर सरतात त्या सगळ्यांमुखार जाप दिली:" },
    { type: "verse", num: 11, text: "'ना, म्हज्या धन्या, म्हजें आयक; हें शेत हांव तुका दितां, आनी तातूंतली गुंफाय तुका दितां; म्हज्या लोकांच्या पुतांमुखार हांव तुका दितां; तुज्या मेल्ल्याक पूर.'" },
    { type: "verse", num: 12, text: "आनी अब्राहामान त्या देसाच्या लोकांमुखार नमस्कार केलो." },
    { type: "verse", num: 13, text: "आनी ताणें एफ्रोनाक त्या देसाच्या लोकांच्या कानांत सांगलें, 'पूण तूं आयकता जाल्यार, हांव तुका शेताचें मोल दितलों; म्हजेकडसून घे, आनी हांव थंय म्हज्या मेल्ल्याक पुरतलों.'" },
    { type: "verse", num: 14, text: "आनी एफ्रोनान अब्राहामाक जाप दिली:" },
    { type: "verse", num: 15, text: "'म्हज्या धन्या, म्हजें आयक; चारशें शेकेल रुपें जमनीचें — म्हजेमदीं आनी तुजेमदीं तें कितें? तुज्या मेल्ल्याक पूर.'" },
    { type: "verse", num: 16, text: "आनी अब्राहामान एफ्रोनाचें आयकलें; आनी अब्राहामान एफ्रोनाक हेथाच्या पुतांमुखार ताणें सांगिल्ल्याप्रमाणें रूप तोललें, चारशें शेकेल रुपें, वेपाऱ्यांच्या चलतीचें." },
    { type: "verse", num: 17, text: "अशें मक्पेलांतलें एफ्रोनाचें शेत, जें मम्रेमुखार आसा, शेत आनी तातूंतली गुंफा आनी शेतांत आनी ताच्या सगळ्या शिमांभोंवतणी आशिल्लीं सगळीं झाडां अब्राहामाक विकत" },
    { type: "verse", num: 18, text: "मेळ्ळीं, हेथाच्या पुतांमुखार, ताच्या शाराच्या दारांत भितर सरतात त्या सगळ्यांमुखार." },
    { type: "verse", num: 19, text: "आनी त्या उपरांत अब्राहामान आपली बायल सारा मक्पेलाच्या शेतांतल्या गुंफेंत पुरली, जी मम्रे (म्हणजे हेब्रोन) मुखार कनान देसांत आसा." },
    { type: "verse", num: 20, text: "आनी शेत आनी तातूंतली गुंफा हेथाच्या पुतांकडसून अब्राहामाक कबराची सुवात म्हूण थीर जाली." },
  ],
  "24": [
    { type: "section", text: "इसाकाक बायल" },
    { type: "verse", num: 1, text: "आनी अब्राहाम म्हातारो, पिरायेन फुडें गेल्लो; आनी सर्वेस्परान अब्राहामाक सगळ्या गजालींत आशीर्वाद दिल्लो." },
    { type: "verse", num: 2, text: "आनी अब्राहामान आपल्या घरांतल्या ज्येष्ठ चाकराक, जो ताच्या सगळ्या संपत्तीचेर आसलो, म्हणलें, 'तुजो हात म्हज्या मांडयेसकयल दवर.'" },
    { type: "verse", num: 3, text: "'आनी हांव तुका ससर्ग आनी पृथ्वीच्या देवा सर्वेस्पराची आण घालतलों, म्हणचे तूं म्हज्या पुताक कनानी लोकांच्या धुवांमदल्यान, ज्यांचेमदीं हांव रावतां, बायल घेवचो ना.'" },
    { type: "verse", num: 4, text: "'पूण म्हज्या देसांत आनी म्हज्या नात्यागोत्यांत वच आनी म्हज्या पुता इसाकाक बायल घे.'" },
    { type: "verse", num: 5, text: "आनी चाकरान ताका म्हणलें, 'कदाचीत बायल म्हजेकडेन ह्या देसांत येवपाक तयार आसची ना; तुजो पूत तूं खंयसून आयलो त्या देसांत हांवें परत व्हरचो?' " },
    { type: "verse", num: 6, text: "आनी अब्राहामान ताका म्हणलें, 'म्हजो पूत थंय परत व्हरपाक जतन कर.'" },
    { type: "verse", num: 7, text: "'ससर्गाचो देव सर्वेस्पर, ज्याणें म्हाका म्हज्या बापायच्या घरांतल्यान आनी म्हज्या जल्माच्या देसांतल्यान काडलो, आनी ज्याणें म्हाका उलयलो आनी ज्याणें म्हाका आण घालून म्हणलें, तुज्या संततीक हांव हो देस दितलों, तो तुजेमुखार आपलो दूत धाडटलो, आनी तूं म्हज्या पुताक थंयसून बायल हाडतलो.'" },
    { type: "verse", num: 8, text: "'आनी बायल तुजेकडेन येवपाक तयार ना जाल्यार, तुका म्हज्या ह्या आणेपसून सूट; फकत म्हजो पूत थंय परत व्हरूंका नाका.'" },
    { type: "verse", num: 9, text: "आनी चाकरान आपलो हात आपल्या धन्या अब्राहामाच्या मांडयेसकयल दवरलो आनी ह्या गजालीविशीं ताका आण घालली." },
    { type: "verse", num: 10, text: "आनी चाकरान आपल्या धन्याच्या उंटांमदले धा उंट घेतले आनी गेलो; कारण ताच्या धन्याची सगळी बरी संपत्ती ताच्या हातांत आसली; आनी तो उठून मेसोपोतामियांत नाहोराच्या शारांत गेलो." },
    { type: "verse", num: 11, text: "आनी ताणें उंटांक शारा भायर उदकाच्या हांड्यालागीं बसयले, सांजेवेळा, बायलो उदक काडपाक भायर सरपाच्या वेळार." },
    { type: "verse", num: 12, text: "आनी ताणें म्हणलें, 'सर्वेस्परा, म्हज्या धन्या अब्राहामाच्या देवा, आज म्हाका यश दी, आनी म्हज्या धन्या अब्राहामाक दया दाखय.'" },
    { type: "verse", num: 13, text: "'पळय, हांव उदकाच्या झऱ्यालागीं उबो आसां, आनी शाराच्या मनशांच्यो धुवो उदक काडपाक भायर सरतात.'" },
    { type: "verse", num: 14, text: "'जे चलयेक हांव म्हणतलों, तुजो घडो दवर, म्हणचे हांव पियेतलों; आनी ती म्हणटली, पीय, आनी तुज्या उंटांकूय हांव पियोवतलें; ती तूं तुज्या चाकरा इसाकाक ठरायल्या; आनी तेवरवीं म्हाका कळटलें तूं म्हज्या धन्याक दया दाखयल्या.'" },
    { type: "verse", num: 15, text: "आनी तो उलोवन जावचेपयलीं, पळय, रिबका भायर सरली, जी अब्राहामाचो भाव नाहोर हाची बायल मिल्का हिचो पूत बथूएल हाची धूव, तिच्या खांदाचेर घडो घेवन." },
    { type: "verse", num: 16, text: "आनी ती चली दिसपाक खूब सोबीत आसली, कुंवारी, जिका कोणेंच दादल्यान वळखूंक ना; आनी ती झऱ्याकडेन देंवली आनी आपलो घडो भरलो आनी वयर आयली." },
    { type: "verse", num: 17, text: "आनी चाकर तिका मेळपाक धांवलो आनी म्हणलें, 'तुज्या घड्यांतलें थोडें उदक म्हाका पियेवंक दी.'" },
    { type: "verse", num: 18, text: "आनी तिणें म्हणलें, 'पीय, म्हज्या धन्या;' आनी तिणें बेगीन आपलो घडो हातांत देंवयलो आनी ताका पियेवंक दिलें." },
    { type: "verse", num: 19, text: "आनी ताका पियेवंक दिल्या उपरांत तिणें म्हणलें, 'तुज्या उंटांकूय हांव उदक काडटलें, ते पियेमेरेन.'" },
    { type: "verse", num: 20, text: "आनी तिणें बेगीन आपलो घडो दोणींत ओतलो, आनी परत हांड्याकडेन धांवली उदक काडपाक; आनी ताच्या सगळ्या उंटांक काडलें." },
    { type: "verse", num: 21, text: "आनी मनीस तिचेकडेन स्तब्ध पळयतालो, सर्वेस्परान ताचो प्रवास यशस्वी केला काय ना तें जाणपाक." },
    { type: "verse", num: 22, text: "आनी उंटांनी पियेलें तेन्ना, मनशान अर्दो शेकेल वजनाची भांगराची नथ, आनी तिच्या हातांक धा शेकेल वजनाच्यो दोन भांगराच्यो बांगड्यो काडल्यो." },
    { type: "verse", num: 23, text: "आनी म्हणलें, 'तूं कोणाची धूव? म्हाका सांग; तुज्या बापायच्या घरांत आमकां रावपाक जागो आसा?' " },
    { type: "verse", num: 24, text: "आनी तिणें ताका म्हणलें, 'हांव बथूएलाची धूव, मिल्कान नाहोराक जल्म दिल्ल्याचो पूत.'" },
    { type: "verse", num: 25, text: "आनी तिणें ताका म्हणलें, 'आमचेकडेन पेंडो आनी चारोय भरपूर आसा, आनी रावपाक जागोय आसा.'" },
    { type: "verse", num: 26, text: "आनी मनशान तकलें बागयलें आनी सर्वेस्पराक नमस्कार केलो." },
    { type: "verse", num: 27, text: "आनी म्हणलें, 'म्हज्या धन्या अब्राहामाचो देव सर्वेस्पर धन्य, ज्याणें म्हज्या धन्याक आपली दया आनी सत सोडूंक ना; सर्वेस्परान म्हाका वाटेन म्हज्या धन्याच्या भावांच्या घराक हाडलो.'" },
    { type: "verse", num: 28, text: "आनी चली धांवली आनी आपल्या आवयच्या घराक ह्यो गजाली सांगल्यो." },
    { type: "verse", num: 29, text: "आनी रिबकाक एक भाव आसलो, ताचें नांव लाबान; आनी लाबान भायर झऱ्यालागीं मनशाकडेन धांवलो." },
    { type: "verse", num: 30, text: "आनी ताणें नथ पळयली, आनी आपल्या भयणीच्या हातांचेर बांगड्यो, आनी आपली भयण रिबका हिचीं उतरां आयकलीं, 'मनशान म्हाका अशें सांगलें;' तेन्ना तो मनशाकडेन आयलो; आनी पळय, तो उंटांलागीं झऱ्याकडेन उबो आसलो." },
    { type: "verse", num: 31, text: "आनी ताणें म्हणलें, 'भितर सर, सर्वेस्पराच्या आशीर्वादीता; तूं भायर कित्याक उबो? हांवें घर आनी उंटांक जागो तयार केला.'" },
    { type: "verse", num: 32, text: "आनी मनीस घरांत भितर सरलो; आनी ताणें उंटांचें खोगीर काडलें, आनी उंटांक पेंडो आनी चारो दिलो, आनी ताचे पांय आनी ताचेकडेन आशिल्ल्या मनशांचे पांय धुवपाक उदक दिलें." },
    { type: "verse", num: 33, text: "आनी ताचेमुखार खावपाक दवरलें; पूण ताणें म्हणलें, 'म्हजी गजाल सांगमेरेन हांव खावचों ना.' आनी ताणें म्हणलें, 'सांग.'" },
    { type: "verse", num: 34, text: "आनी ताणें म्हणलें, 'हांव अब्राहामाचो चाकर.'" },
    { type: "verse", num: 35, text: "'आनी सर्वेस्परान म्हज्या धन्याक खूब आशीर्वाद दिला, आनी तो व्हड जाला; आनी ताणें ताका मेंढरां, गोरवां, रुपें, भांगर, चाकर, चाकर्ण्यो, उंट आनी गाडवां दिल्यांत.'" },
    { type: "verse", num: 36, text: "'आनी म्हज्या धन्याची बायल सारान म्हज्या धन्याक ती म्हातारी जाल्या उपरांत एक पूत जल्म दिलो; आनी ताणें ताका आपलें सगळें दिलां.'" },
    { type: "verse", num: 37, text: "'आनी म्हज्या धन्यान म्हाका आण घालली: कनानी लोकांच्या धुवांमदल्यान, ज्यांच्या देसांत हांव रावतां, म्हज्या पुताक बायल घेवंका नाका;'" },
    { type: "verse", num: 38, text: "'पूण म्हज्या बापायच्या घराक आनी म्हज्या नात्यागोत्याक वच, आनी म्हज्या पुताक बायल घे.'" },
    { type: "verse", num: 39, text: "'आनी हांवें म्हज्या धन्याक म्हणलें, कदाचीत बायल म्हजेकडेन येवची ना.'" },
    { type: "verse", num: 40, text: "'आनी ताणें म्हाका म्हणलें, सर्वेस्पर, ज्याचेमुखार हांव चललों, तो तुजेकडेन आपलो दूत धाडटलो, आनी तुजो प्रवास यशस्वी करतलो; आनी तूं म्हज्या नात्यागोत्यांतल्यान आनी म्हज्या बापायच्या घरांतल्यान म्हज्या पुताक बायल घेतलो.'" },
    { type: "verse", num: 41, text: "'तेन्ना तुका म्हज्या आणेपसून सूट, तूं म्हज्या नात्यागोत्याकडेन गेलो, आनी तांणीं तुका दिली ना जाल्यार; तेन्ना तुका म्हज्या आणेपसून सूट.'" },
    { type: "verse", num: 42, text: "'आनी हांव आज झऱ्यालागीं आयलों, आनी म्हणलों, सर्वेस्परा, म्हज्या धन्या अब्राहामाच्या देवा, तूं म्हजो प्रवास यशस्वी करता जाल्यार;'" },
    { type: "verse", num: 43, text: "'पळय, हांव उदकाच्या झऱ्यालागीं उबो आसां; जी कुंवारी उदक काडपाक भायर सरतली, आनी हांव तिका म्हणतलों, तुज्या घड्यांतलें थोडें उदक म्हाका पियेवंक दी;'" },
    { type: "verse", num: 44, text: "'आनी ती म्हाका म्हणटली, तूं पीय, आनी तुज्या उंटांकूय हांव काडटलें; तीच सर्वेस्परान म्हज्या धन्याच्या पुताक ठरायिल्ली बायल.'" },
    { type: "verse", num: 45, text: "'हांव म्हज्या काळजांत उलोवन जावचेपयलीं, पळय, रिबका आपल्या खांदाचेर घडो घेवन भायर सरली; आनी ती झऱ्याकडेन देंवली आनी उदक काडलें; आनी हांवें तिका म्हणलें, म्हाका पियेवंक दी.'" },
    { type: "verse", num: 46, text: "'आनी तिणें बेगीन आपलो घडो देंवयलो आनी म्हणलें, पीय, आनी तुज्या उंटांकूय हांव पियोवतलें; तेन्ना हांवें पियेलें, आनी तिणें उंटांकूय पियोवले.'" },
    { type: "verse", num: 47, text: "'आनी हांवें तिका विचारलें, तूं कोणाची धूव? आनी तिणें म्हणलें, हांव बथूएलाची धूव, नाहोराचो पूत, ज्याक मिल्कान ताका जल्म दिलो. आनी हांवें तिच्या नाकाक नथ आनी तिच्या हातांक बांगड्यो घाल्यो.'" },
    { type: "verse", num: 48, text: "'आनी हांवें तकलें बागयलें आनी सर्वेस्पराक नमस्कार केलो, आनी म्हज्या धन्या अब्राहामाच्या देवा सर्वेस्पराक धन्य केलो, ज्याणें म्हाका खऱ्या वाटेन म्हज्या धन्याच्या भावाची धूव ताच्या पुताक घेवपाक हाडलो.'" },
    { type: "verse", num: 49, text: "'आनी आतां तुमी म्हज्या धन्याक दया आनी सत दाखयतात जाल्यार म्हाका सांगात; आनी ना जाल्यार म्हाका सांगात; म्हणचे हांव उजव्या वा दाव्या वाटेन वळतलों.'" },
    { type: "verse", num: 50, text: "तेन्ना लाबानान आनी बथूएलान जाप दिली, 'ही गजाल सर्वेस्पराकडसून आयल्या; आमी तुका बरें वा वायट सांगपाक शकनात.'" },
    { type: "verse", num: 51, text: "'पळय, रिबका तुजेमुखार आसा; तिका घे आनी वच, आनी सर्वेस्परान सांगिल्लेप्रमाणें ती तुज्या धन्याच्या पुताची बायल जांव.'" },
    { type: "verse", num: 52, text: "आनी अब्राहामाच्या चाकरान तांचीं उतरां आयकलीं तेन्ना ताणें सर्वेस्पराक भुंयेक पडून नमस्कार केलो." },
    { type: "verse", num: 53, text: "आनी चाकरान रुप्याचीं आनी भांगराचीं भूषणां आनी वस्त्रां काडलीं आनी रिबकाक दिलीं; आनी तिच्या भावाक आनी तिच्या आवयक मोलादीक वस्ती दिल्यो." },
    { type: "verse", num: 54, text: "आनी तांणीं खालें आनी पियेलें, तो आनी ताचेकडेन आशिल्ले मनीस, आनी रात रावले. आनी सकाळीं उठले तेन्ना ताणें म्हणलें, 'म्हाका म्हज्या धन्याकडेन धाडात.'" },
    { type: "verse", num: 55, text: "आनी तिच्या भावान आनी तिच्या आवयन म्हणलें, 'चली आमचेकडेन थोडे दीस, उणेपक्षीं धा रावूंदी; त्या उपरांत ती वचूंदी.'" },
    { type: "verse", num: 56, text: "आनी ताणें तांकां म्हणलें, 'म्हाका आडावंका नाकात, सर्वेस्परान म्हजो प्रवास यशस्वी केला; म्हाका धाडात, म्हणचे हांव म्हज्या धन्याकडेन वतलों.'" },
    { type: "verse", num: 57, text: "आनी ते म्हणाले, 'चलयेक आपोवया आनी तिच्या तोंडांतल्यान आयकूया.'" },
    { type: "verse", num: 58, text: "आनी तांणीं रिबकाक आपयली आनी तिका म्हणलें, 'तूं ह्या मनशाकडेन वतली?' आनी तिणें म्हणलें, 'हांव वतलें.'" },
    { type: "verse", num: 59, text: "आनी तांणीं आपली भयण रिबका आनी तिची दायी आनी अब्राहामाचो चाकर आनी ताचे मनीस धाडले." },
    { type: "verse", num: 60, text: "आनी तांणीं रिबकाक आशीर्वाद दिलो आनी तिका म्हणलें, 'आमच्या भयणी, तूं हजारां हजार जा; आनी तुजी संतत तांच्या दुस्मानांच्या दारांचो ताबो घेतली.'" },
    { type: "verse", num: 61, text: "आनी रिबका आनी तिच्या चाकर्ण्यो उठल्यो आनी उंटांचेर बसल्यो आनी मनशाफाटल्यान गेल्यो; अशें चाकरान रिबकाक घेतली आनी गेलो." },
    { type: "verse", num: 62, text: "आनी इसाक बएर-लहय-रोईच्या वाटेन येतालो; कारण तो दक्षिण देसांत रावतालो." },
    { type: "verse", num: 63, text: "आनी इसाक सांजेवेळा शेतांत ध्यान करपाक भायर गेल्लो; आनी ताणें दोळे उखलून पळयलें, आनी पळय, उंट येताले." },
    { type: "verse", num: 64, text: "आनी रिबकान दोळे उखलून इसाकाक पळयलो, आनी उंटाचेर आड देंवली." },
    { type: "verse", num: 65, text: "आनी तिणें चाकराक म्हणलें, 'शेतांत आमकां मेळपाक येता तो मनीस कोण?' आनी चाकरान म्हणलें, 'तो म्हजो धनी.' तेन्ना तिणें बुरखो घेतलो." },
    { type: "verse", num: 66, text: "आनी चाकरान इसाकाक ताणें केल्ल्यो सगळ्यो गजाली सांगल्यो." },
    { type: "verse", num: 67, text: "आनी इसाकान तिका आपल्या आवय साराच्या तंबूंत हाडली, आनी रिबकाक घेतली, आनी ती ताची बायल जाली; आनी ताणें तिचो मोग केलो. अशें इसाकाक आपल्या आवये उपरांत भुजवण मेळ्ळी." },
  ],
  "25": [
    { type: "section", text: "अब्राहामाचें मरण" },
    { type: "verse", num: 1, text: "आनी अब्राहामान परत एक बायल घेतली, तिचें नांव कतूरा." },
    { type: "verse", num: 2, text: "आनी तिणें ताका जिम्रान, योक्षान, मदान, मिद्यान, यिश्बाक आनी शूह हांकां जल्म दिलो." },
    { type: "verse", num: 3, text: "आनी योक्षानान शबा आनी ददानाक जल्म दिलो. आनी ददानाचे पूत अश्शूरीम, लतूशीम आनी लऊम्मीम." },
    { type: "verse", num: 4, text: "आनी मिद्यानाचे पूत एफा, एफेर, हनोख, अबीदा आनी एल्दा. हे सगळे कतूराचे पूत." },
    { type: "verse", num: 5, text: "आनी अब्राहामान आपलें सगळें इसाकाक दिलें." },
    { type: "verse", num: 6, text: "पूण अब्राहामाच्या उपपत्नींच्या पुतांक अब्राहामान दानां दिलीं, आनी आपणें जिवो आसतनाच तांकां आपल्या पुता इसाकापसून उदेंतेकडेन, उदेंतेच्या देसांत धाडलें." },
    { type: "verse", num: 7, text: "आनी अब्राहामाच्या जिविताचीं वर्सां हीं: एकशें पंच्यात्तर वर्सां." },
    { type: "verse", num: 8, text: "आनी अब्राहामान प्राण सोडलो आनी बऱ्या म्हातारपणांत, म्हातारो आनी तृप्त मेलो; आनी आपल्या लोकांमदीं एकवटलो." },
    { type: "verse", num: 9, text: "आनी ताचे पूत इसाक आनी इश्माएल हांणीं ताका मक्पेलाच्या गुंफेंत पुरलो, मम्रेमुखार, हित्ती सोहराचो पूत एफ्रोन हाच्या शेतांत." },
    { type: "verse", num: 10, text: "जें शेत अब्राहामान हेथाच्या पुतांकडसून विकत घेतिल्लें; थंय अब्राहामाक पुरलो, आनी ताची बायल सारा." },
    { type: "verse", num: 11, text: "आनी अब्राहाम मेल्या उपरांत, देवान ताचो पूत इसाक ताका आशीर्वाद दिलो; आनी इसाक बएर-लहय-रोईलागीं रावलो." },
    { type: "section", text: "इश्माएलाची वंशावळ" },
    { type: "verse", num: 12, text: "ही अब्राहामाचो पूत इश्माएल, ज्याक साराची ईजिप्ती चाकर्णी हागारेन अब्राहामाक जल्म दिलो, ताची वंशावळ." },
    { type: "verse", num: 13, text: "आनी हीं इश्माएलाच्या पुतांचीं नांवां, तांच्या नांवांप्रमाणें, तांच्या पिळग्यांप्रमाणें: इश्माएलाचो ज्येष्ठ नबायोथ; आनी केदार, अद्बएल, मिब्साम," },
    { type: "verse", num: 14, text: "मिश्मा, दूमा, मस्सा," },
    { type: "verse", num: 15, text: "हदद, तेमा, यतूर, नाफीश आनी केदमा." },
    { type: "verse", num: 16, text: "हे इश्माएलाचे पूत, आनी हीं तांचीं नांवां, तांच्या गांवांनी आनी तांच्या छावण्यांनी; बारा अधिपती तांच्या राष्ट्रांप्रमाणें." },
    { type: "verse", num: 17, text: "आनी इश्माएलाच्या जिविताचीं वर्सां हीं: एकशें सदतीस वर्सां; आनी ताणें प्राण सोडलो आनी मेलो, आनी आपल्या लोकांमदीं एकवटलो." },
    { type: "verse", num: 18, text: "आनी ते हवीलापसून शूरामेरेन, जो ईजिप्तामुखार अश्शूराकडेन वतना आसा, रावले; तो आपल्या सगळ्या भावांमुखार पडलो." },
    { type: "section", text: "एसाव आनी याकोब" },
    { type: "verse", num: 19, text: "ही अब्राहामाचो पूत इसाक ताची वंशावळ: अब्राहामान इसाकाक जल्म दिलो." },
    { type: "verse", num: 20, text: "आनी इसाक चाळीस वर्सांचो जालो तेन्ना ताणें रिबकाक बायल घेतली, ती पदन-अरामचो अरामी बथूएल हाची धूव, अरामी लाबानाची भयण." },
    { type: "verse", num: 21, text: "आनी इसाकान आपल्या बायले खातीर सर्वेस्पराकडेन प्रार्थना केली, कारण ती बांज आसली; आनी सर्वेस्परान ताची प्रार्थना आयकली, आनी ताची बायल रिबका गुरवार जाली." },
    { type: "verse", num: 22, text: "आनी भुरगीं तिच्या गर्भांत एकामेकांआड झगडतालीं; आनी तिणें म्हणलें, 'अशें आसा जाल्यार, हांव कित्याक जगतां?' आनी ती सर्वेस्पराकडेन विचारपाक गेली." },
    { type: "verse", num: 23, text: "आनी सर्वेस्परान तिका म्हणलें, 'तुज्या गर्भांत दोन राष्ट्रां आसात, आनी तुज्या कुडीतल्यान दोन लोक वेगळे जातले; एक लोक दुसऱ्या लोकांपरस बळिष्ट आसतलो, आनी व्हडलो ल्हान्याची सेवा करतलो.'" },
    { type: "verse", num: 24, text: "आनी तिचे दीस जल्म दिवपाचे भरले, आनी पळय, तिच्या गर्भांत जुळीं आसलीं." },
    { type: "verse", num: 25, text: "आनी पयलो भायर आयलो तो तांबडो, सगळो केसाच्या वस्त्रासारको; आनी तांणीं ताचें नांव एसाव दवरलें." },
    { type: "verse", num: 26, text: "आनी त्या उपरांत ताचो भाव भायर आयलो, आनी ताच्या हातान एसावाची तकली धरिल्ली; आनी ताचें नांव याकोब दवरलें. ते जल्मले तेन्ना इसाक साठ वर्सांचो आसलो." },
    { type: "verse", num: 27, text: "आनी भुरगीं वाडलीं; आनी एसाव शिकारीत चतुर मनीस, रानाचो मनीस जालो; आनी याकोब शांत मनीस, तंबूंत रावपी जालो." },
    { type: "verse", num: 28, text: "आनी इसाकान एसावाचो मोग केलो, कारण ताणें ताचें शिकारीचें मांस खालें; पूण रिबकान याकोबाचो मोग केलो." },
    { type: "verse", num: 29, text: "आनी याकोबान रांदणें शिजयलें; आनी एसाव शेतांतल्यान आयलो, आनी तो थकिल्लो." },
    { type: "verse", num: 30, text: "आनी एसावान याकोबाक म्हणलें, 'हें तांबडें, हें तांबडें रांदणें म्हाका खावपाक दी; कारण हांव थकलों.' देखून ताचें नांव एदोम दवरलें." },
    { type: "verse", num: 31, text: "आनी याकोबान म्हणलें, 'आज तुजें ज्येष्ठपण म्हाका विक.'" },
    { type: "verse", num: 32, text: "आनी एसावान म्हणलें, 'पळय, हांव मरपाचेर आसां; म्हाका ज्येष्ठपण कित्याक?' " },
    { type: "verse", num: 33, text: "आनी याकोबान म्हणलें, 'आज म्हाका आण घाल.' आनी ताणें ताका आण घाल्ली; आनी ताणें आपलें ज्येष्ठपण याकोबाक विकलें." },
    { type: "verse", num: 34, text: "तेन्ना याकोबान एसावाक भाकर आनी मसुराचें रांदणें दिलें; आनी ताणें खालें आनी पियेलें, आनी उठलो आनी गेलो. अशें एसावान आपलें ज्येष्ठपण तुच्छ मानलें." },
  ],
  "26": [
    { type: "section", text: "इसाक गरारांत" },
    { type: "verse", num: 1, text: "आनी अब्राहामाच्या दिसांनी आयिल्ल्या पयल्या दुकाळा शिवाय देसांत दुकाळ आयलो. आनी इसाक गराराच्या पलिश्ती राजा अबीमेलेखाकडेन गेलो." },
    { type: "verse", num: 2, text: "आनी सर्वेस्पर ताका दिसलो आनी म्हणलें, 'ईजिप्तांत देंवका नाका; हांव तुका सांगतां त्या देसांत रहा.'" },
    { type: "verse", num: 3, text: "'ह्या देसांत परदेशी जावन रहा, आनी हांव तुजेकडेन आसतलों आनी तुका आशीर्वाद दितलों; कारण तुका आनी तुज्या संततीक हे सगळे देस हांव दितलों, आनी हांव तुज्या बापाय अब्राहामाक घाल्लेली आण सांबाळटलों.'" },
    { type: "verse", num: 4, text: "'आनी तुजी संतत मळबांतल्या नखेत्रांसारकी वाडयतलों, आनी तुज्या संततीक हे सगळे देस दितलों; आनी तुज्या संततीवरवीं पृथ्वीचीं सगळीं राष्ट्रां आशीर्वादीत जातलीं.'" },
    { type: "verse", num: 5, text: "'कारण अब्राहामान म्हजो आवाज आयकलो, आनी म्हजी आज्ञा, म्हजे विधी, म्हजे कायदे आनी म्हजें शास्त्र सांबाळलें.'" },
    { type: "verse", num: 6, text: "आनी इसाक गरारांत रावलो." },
    { type: "verse", num: 7, text: "आनी त्या जाग्याच्या मनशांनी ताच्या बायलेविशीं विचारलें तेन्ना ताणें म्हणलें, 'ती म्हजी भयण;' कारण ताका म्हणपाक भंय जालो, 'ती म्हजी बायल;' त्या जाग्याचे मनीस रिबके खातीर म्हाका मारतले, कारण ती दिसपाक सोबीत." },
    { type: "verse", num: 8, text: "आनी तो थंय जायतो काळ रावल्या उपरांत, पलिश्ती राजा अबीमेलेखान जनेलांतल्यान पळयलें, आनी पळय, इसाक आपल्या बायलेक रिबकाक कवटाळटालो." },
    { type: "verse", num: 9, text: "आनी अबीमेलेखान इसाकाक आपयलो आनी म्हणलें, 'पळय, खात्रीन ती तुजी बायल; आनी तूं कशें म्हणलो, ती म्हजी भयण?' आनी इसाकान ताका म्हणलें, 'कारण हांवें म्हणलें, तिचे खातीर हांव मरतलों.'" },
    { type: "verse", num: 10, text: "आनी अबीमेलेखान म्हणलें, 'तूं आमकां हें कितें केलें? थोड्यांत लोकांमदलो एकलो तुज्या बायलेकडेन गेल्लो आसतो, आनी तूं आमचेर दोष हाडतो.'" },
    { type: "verse", num: 11, text: "आनी अबीमेलेखान सगळ्या लोकांक आज्ञा दिली: 'जो कोण ह्या मनशाक वा ताच्या बायलेक लागता, तो खात्रीन मरतलो.'" },
    { type: "verse", num: 12, text: "तेन्ना इसाकान त्या देसांत पेरणी केली, आनी त्या वर्सा शंभर पटीन कापणी मेळयली; आनी सर्वेस्परान ताका आशीर्वाद दिलो." },
    { type: "verse", num: 13, text: "आनी तो मनीस व्हड जालो, आनी वाडत वाडत खूब व्हड जालो." },
    { type: "verse", num: 14, text: "कारण ताका मेंढरांचीं कळपां, गोरवांचीं कळपां आनी खूब चाकर आसले; आनी पलिश्ती ताचो हेवो करताले." },
    { type: "verse", num: 15, text: "आनी ताच्या बापायच्या चाकरांनी ताच्या बापाय अब्राहामाच्या दिसांनी खणिल्ल्यो सगळ्यो हांड्यो पलिश्तींनी धुल्लेन भरून बंद केल्यो." },
    { type: "verse", num: 16, text: "आनी अबीमेलेखान इसाकाक म्हणलें, 'आमचेकडसून वच; कारण तूं आमचेपरस खूब बळिष्ट जाला.'" },
    { type: "verse", num: 17, text: "आनी इसाक थंयसून गेलो आनी गराराच्या देगणांत तंबू मारून रावलो." },
    { type: "verse", num: 18, text: "आनी इसाकान ताच्या बापाय अब्राहामाच्या दिसांनी खणिल्ल्यो उदकाच्यो हांड्यो परत खणल्यो, ज्यो अब्राहाम मेल्या उपरांत पलिश्तींनी बंद केल्ल्यो; आनी ताणें तांकां ताच्या बापायन दवरिल्लीं नांवां दवरलीं." },
    { type: "verse", num: 19, text: "आनी इसाकाच्या चाकरांनी देगणांत खणलें आनी थंय व्हांवपी उदकाची हांडी सोदली." },
    { type: "verse", num: 20, text: "आनी गराराच्या गोवळ्यांनी इसाकाच्या गोवळ्यांकडेन झगडलें: 'उदक आमचें.' आनी ताणें त्या हांडीचें नांव एसेक दवरलें, कारण तांणीं ताचेकडेन झगडलें." },
    { type: "verse", num: 21, text: "आनी तांणीं आनीक एक हांडी खणली, आनी तिचे खातीरय झगडले; आनी ताणें तिचें नांव सित्ना दवरलें." },
    { type: "verse", num: 22, text: "आनी तो थंयसून गेलो आनी आनीक एक हांडी खणली; आनी तिचे खातीर झगडले नात; आनी ताणें तिचें नांव रहोबोथ दवरलें; आनी म्हणलें, 'कारण आतां सर्वेस्परान आमकां जागो दिला, आनी आमी देसांत वाडतले.'" },
    { type: "verse", num: 23, text: "आनी तो थंयसून बएर-शेबाक वयर गेलो." },
    { type: "verse", num: 24, text: "आनी त्या राती सर्वेस्पर ताका दिसलो आनी म्हणलें, 'हांव तुज्या बापाय अब्राहामाचो देव; भियेवंका नाका, कारण हांव तुजेकडेन आसां, आनी तुका आशीर्वाद दितलों, आनी म्हज्या चाकरा अब्राहामा खातीर तुजी संतत वाडयतलों.'" },
    { type: "verse", num: 25, text: "आनी ताणें थंय एक वेदी बांदली आनी सर्वेस्पराच्या नांवान प्रार्थना केली, आनी थंय आपलो तंबू मारलो; आनी इसाकाच्या चाकरांनी थंय एक हांडी खणली." },
    { type: "verse", num: 26, text: "तेन्ना अबीमेलेख गरारापसून ताचेकडेन आयलो, ताचो इश्ट अहुज्जाथ आनी ताच्या सैन्याचो सेनापती फीकोल." },
    { type: "verse", num: 27, text: "आनी इसाकान तांकां म्हणलें, 'तुमी म्हजेकडेन कित्याक आयल्यात? तुमकां म्हजो राग आयला आनी तुमी म्हाका तुमचेकडसून धाडलो.'" },
    { type: "verse", num: 28, text: "आनी ते म्हणाले, 'आमी स्पश्ट पळयलां सर्वेस्पर तुजेकडेन आसा; आनी आमी म्हणलीं, आमचेमदीं आनी तुजेमदीं आण जांव, आनी आमी तुजेकडेन करार करूया.'" },
    { type: "verse", num: 29, text: "'म्हणचे तूं आमकां वायट करचो ना, जशें आमी तुका लागलीं नात, आनी जशें आमी तुका फकत बरें केलें, आनी तुका शांतीन धाडलो. तूं आतां सर्वेस्पराचो आशीर्वादीत.'" },
    { type: "verse", num: 30, text: "आनी ताणें तांकां जेवणावळ केली, आनी तांणीं खालें आनी पियेलें." },
    { type: "verse", num: 31, text: "आनी ते सकाळीं उठले आनी एकामेकांक आण घाल्ली. आनी इसाकान तांकां धाडलें, आनी ते ताचेकडसून शांतीन गेले." },
    { type: "verse", num: 32, text: "आनी त्याच दिसा इसाकाच्या चाकरांनी आयले आनी तांणीं खणिल्ल्या हांडीविशीं ताका सांगलें: 'आमकां उदक मेळ्ळां.'" },
    { type: "verse", num: 33, text: "आनी ताणें तिचें नांव शिबा दवरलें; देखून त्या शाराचें नांव आज मेरेन बएर-शेबा." },
    { type: "verse", num: 34, text: "आनी एसाव चाळीस वर्सांचो जालो तेन्ना ताणें हित्ती बएरीची धूव यहूदीथ आनी हित्ती एलोनाची धूव बासमथ हांकां बायलो घेतल्यो." },
    { type: "verse", num: 35, text: "आनी त्यो इसाक आनी रिबकाक आत्म्याच्या दुखाक कारण जाल्यो." },
  ],
  "27": [
    { type: "section", text: "याकोबान एसावाचो आशीर्वाद चोरलो" },
    { type: "verse", num: 1, text: "आनी इसाक म्हातारो जालो आनी ताचे दोळे धूसर जाले, ताका दिसपाक जायना जालें, तेन्ना ताणें आपलो व्हडलो पूत एसाव ताका आपयलो आनी ताका म्हणलें, 'म्हज्या पुता.' आनी ताणें ताका म्हणलें, 'हांगा हांव.'" },
    { type: "verse", num: 2, text: "आनी ताणें म्हणलें, 'पळय, हांव म्हातारो जालों; म्हजो मरपाचो दीस म्हाका खबर ना.'" },
    { type: "verse", num: 3, text: "'आतां तुजीं हत्यारां, तुजो भातो आनी तुजो धनुष्य घे, आनी शेतांत वच आनी म्हजे खातीर शिकार कर.'" },
    { type: "verse", num: 4, text: "'आनी म्हाका आवडटा तसलें रुचीक जेवण तयार कर आनी म्हजेकडेन हाड, म्हणचे हांव खातलों; म्हणचे हांव मरचेपयलीं म्हजो आत्मो तुका आशीर्वाद दितलो.'" },
    { type: "verse", num: 5, text: "आनी इसाक आपल्या पुता एसावाकडेन उलयतालो तेन्ना रिबकान आयकलें. आनी एसाव शिकार करपाक आनी हाडपाक शेतांत गेलो." },
    { type: "verse", num: 6, text: "आनी रिबकान आपल्या पुता याकोबाक सांगलें, 'पळय, तुजो बापूय तुज्या भावा एसावाकडेन उलयतना हांवें आयकलें:'" },
    { type: "verse", num: 7, text: "'म्हजे खातीर शिकार हाड आनी रुचीक जेवण तयार कर, म्हणचे हांव खातलों आनी मरचेपयलीं सर्वेस्परामुखार तुका आशीर्वाद दितलों.'" },
    { type: "verse", num: 8, text: "'आतां, म्हज्या पुता, हांव तुका सांगतां तें म्हजो आवाज आयक.'" },
    { type: "verse", num: 9, text: "'कळपांत वच आनी थंयसून दोन बरे बोकडाचे पिले हाड; आनी हांव ते तुज्या बापायक ताका आवडटा तसले रुचीक जेवण तयार करतलें.'" },
    { type: "verse", num: 10, text: "'आनी तूं ताचेकडेन व्हरतलो, म्हणचे तो खातलो, म्हणचे मरचेपयलीं तो तुका आशीर्वाद दितलो.'" },
    { type: "verse", num: 11, text: "आनी याकोबान आपल्या आवयक रिबकाक म्हणलें, 'पळय, म्हजो भाव एसाव केसाळ मनीस, आनी हांव गुळगुळीत मनीस.'" },
    { type: "verse", num: 12, text: "'कदाचीत म्हजो बापूय म्हाका चाचपतलो, आनी हांव ताका फटोवपी दिसतलों; आनी हांव आशीर्वादा बदला शाप मेळयतलों.'" },
    { type: "verse", num: 13, text: "आनी ताची आवय ताका म्हणलें, 'म्हज्या पुता, तुजो शाप म्हजेर; फकत म्हजो आवाज आयक आनी वच आनी म्हाका हाड.'" },
    { type: "verse", num: 14, text: "आनी तो गेलो आनी घेतले आनी आपल्या आवयकडेन हाडले; आनी ताच्या आवयन ताच्या बापायक आवडटा तसलें रुचीक जेवण तयार केलें." },
    { type: "verse", num: 15, text: "आनी रिबकान आपल्या व्हडल्या पुता एसावाचीं घरांत आशिल्लीं बरीं वस्त्रां घेतलीं आनी आपल्या ल्हान पुता याकोबाक न्हेसयलीं." },
    { type: "verse", num: 16, text: "आनी बोकडाच्या पिलांचीं कातडीं ताच्या हातांचेर आनी ताच्या गळ्याच्या गुळगुळीत जाग्याचेर घाल्यो." },
    { type: "verse", num: 17, text: "आनी तिणें तयार केल्लें रुचीक जेवण आनी भाकर आपल्या पुता याकोबाच्या हातांत दिलीं." },
    { type: "verse", num: 18, text: "आनी तो आपल्या बापायकडेन आयलो आनी म्हणलें, 'म्हज्या बापा.' आनी ताणें म्हणलें, 'हांगा हांव; तूं कोण, म्हज्या पुता?'" },
    { type: "verse", num: 19, text: "आनी याकोबान आपल्या बापायक म्हणलें, 'हांव तुजो ज्येष्ठ एसाव; तूं म्हाका सांगिल्लेप्रमाणें हांवें केलां; उठ, बस आनी म्हजी शिकार खा, म्हणचे तुजो आत्मो म्हाका आशीर्वाद दितलो.'" },
    { type: "verse", num: 20, text: "आनी इसाकान आपल्या पुताक म्हणलें, 'म्हज्या पुता, तुका इतक्या बेगीन कशें मेळ्ळें?' आनी ताणें म्हणलें, 'कारण तुज्या देवा सर्वेस्परान तें म्हजेमुखार हाडलें.'" },
    { type: "verse", num: 21, text: "आनी इसाकान याकोबाक म्हणलें, 'लागीं सर, म्हणचे हांव तुका चाचपतलों, म्हज्या पुता, तूं खरेंच म्हजो पूत एसाव काय ना.'" },
    { type: "verse", num: 22, text: "आनी याकोब आपल्या बापाय इसाकालागीं गेलो; आनी ताणें ताका चाचपलो आनी म्हणलें, 'आवाज याकोबाचो, पूण हात एसावाचे.'" },
    { type: "verse", num: 23, text: "आनी ताणें ताका वळखलो ना, कारण ताचे हात ताच्या भावा एसावाच्या हातांसारके केसाळ आसले; आनी ताणें ताका आशीर्वाद दिलो." },
    { type: "verse", num: 24, text: "आनी ताणें म्हणलें, 'तूं खरेंच म्हजो पूत एसाव?' आनी ताणें म्हणलें, 'हांव.'" },
    { type: "verse", num: 25, text: "आनी ताणें म्हणलें, 'म्हजेलागीं हाड, आनी म्हज्या पुताची शिकार हांव खातलों, म्हणचे म्हजो आत्मो तुका आशीर्वाद दितलो.' आनी ताणें ताचेलागीं हाडलें, आनी ताणें खालें; आनी ताणें ताका द्राक्षारस हाडलो, आनी ताणें पियेलें." },
    { type: "verse", num: 26, text: "आनी ताचो बापूय इसाकान ताका म्हणलें, 'लागीं सर आनी म्हाका उमो दी, म्हज्या पुता.'" },
    { type: "verse", num: 27, text: "आनी तो लागीं सरलो आनी ताका उमो दिलो; आनी ताणें ताच्या वस्त्रांचो वास घेतलो, आनी ताका आशीर्वाद दिलो आनी म्हणलें, 'पळय, म्हज्या पुताचो वास सर्वेस्परान आशीर्वाद दिल्ल्या शेतासारको.'" },
    { type: "verse", num: 28, text: "'देवान तुका मळबांतलें दंव आनी पृथ्वीचो सार दिवचो, आनी भरपूर धान्य आनी द्राक्षारस.'" },
    { type: "verse", num: 29, text: "'लोक तुजी सेवा करूंदीत, आनी राष्ट्रां तुका नमस्कार करूंदीत; तुज्या भावांचो धनी जा, आनी तुज्या आवयचे पूत तुका नमस्कार करूंदीत; तुका शाप दिता तो शापित जांव, आनी तुका आशीर्वाद दिता तो आशीर्वादीत जांव.'" },
    { type: "verse", num: 30, text: "आनी इसाकान याकोबाक आशीर्वाद दिवन जालो तेन्ना, याकोब आपल्या बापाय इसाकाच्या मुखापसून भायर सरतकूच, ताचो भाव एसाव आपल्या शिकारीपसून आयलो." },
    { type: "verse", num: 31, text: "आनी ताणेंय रुचीक जेवण तयार केलें आनी आपल्या बापायकडेन हाडलें आनी म्हणलें, 'म्हजो बापूय उठूंदी आनी आपल्या पुताची शिकार खावंदी, म्हणचे तुजो आत्मो म्हाका आशीर्वाद दितलो.'" },
    { type: "verse", num: 32, text: "आनी ताचो बापूय इसाकान ताका म्हणलें, 'तूं कोण?' आनी ताणें म्हणलें, 'हांव तुजो ज्येष्ठ पूत एसाव.'" },
    { type: "verse", num: 33, text: "आनी इसाक खूब भियेलो आनी म्हणलें, 'तेन्ना शिकार करून म्हजेकडेन हाडली तो कोण? तूं येवचेपयलीं हांवें सगळें खालें आनी ताका आशीर्वाद दिलो; हय, आनी तो आशीर्वादीतूच जातलो.'" },
    { type: "verse", num: 34, text: "एसावान आपल्या बापायचीं उतरां आयकलीं तेन्ना तो खूब जोरान बोबाटलो आनी म्हणलें, 'म्हज्या बापा, म्हाकाय आशीर्वाद दी, म्हाकाय!'" },
    { type: "verse", num: 35, text: "आनी ताणें म्हणलें, 'तुजो भाव कपटान आयलो आनी तुजो आशीर्वाद घेवन गेलो.'" },
    { type: "verse", num: 36, text: "आनी ताणें म्हणलें, 'ताचें नांव याकोब बरोबर दवरलें; कारण ताणें म्हाका दोन खेपो फटयलो; ताणें म्हजें ज्येष्ठपण घेतलें; आनी पळय, आतां ताणें म्हजो आशीर्वाद घेतलो.' आनी ताणें म्हणलें, 'तूं म्हजे खातीर आशीर्वाद दवरूंक ना?' " },
    { type: "verse", num: 37, text: "आनी इसाकान जाप दिली आनी एसावाक म्हणलें, 'पळय, हांवें ताका तुजो धनी केला, आनी ताचे सगळे भाव ताका चाकर म्हूण दिल्यात; आनी धान्यान आनी द्राक्षारसान ताका सांबाळला; आनी आतां, म्हज्या पुता, तुका कितें करतलों?'" },
    { type: "verse", num: 38, text: "आनी एसावान आपल्या बापायक म्हणलें, 'म्हज्या बापा, तुजेकडेन फकत एकूच आशीर्वाद आसा? म्हाकाय आशीर्वाद दी, म्हज्या बापा!' आनी एसावान आवाज उखलून रडलो." },
    { type: "verse", num: 39, text: "आनी ताचो बापूय इसाकान जाप दिली आनी ताका म्हणलें, 'पळय, पृथ्वीच्या सारापसून पयस आनी वयर मळबांतल्या दंवापसून पयस तुजें रावपाचें जातलें.'" },
    { type: "verse", num: 40, text: "'आनी तुज्या तरवारीन तूं जगतलो, आनी तुज्या भावाची सेवा करतलो; आनी तूं भटकतलो तेन्ना तुज्या गळ्यावयलें ताचें जूं तूं मोडून उडयतलो.'" },
    { type: "verse", num: 41, text: "आनी एसावान याकोबाचो राग धरलो, ताच्या बापायन ताका दिल्ल्या आशीर्वादा खातीर; आनी एसावान आपल्या काळजांत म्हणलें, 'म्हज्या बापायचे शोकाचे दीस लागीं आसात; तेन्ना हांव म्हज्या भावा याकोबाक मारतलों.'" },
    { type: "verse", num: 42, text: "आनी रिबकाक आपल्या व्हडल्या पुता एसावाचीं उतरां सांगलीं; आनी तिणें धाडून आपल्या ल्हान पुता याकोबाक आपयलो आनी ताका म्हणलें, 'पळय, तुजो भाव एसाव तुका मारपाक म्हूण तुजेविशीं भुजता.'" },
    { type: "verse", num: 43, text: "'आतां, म्हज्या पुता, म्हजो आवाज आयक; उठ आनी हारानांत म्हज्या भावा लाबानाकडेन पळ.'" },
    { type: "verse", num: 44, text: "'आनी थोडे दीस ताचेकडेन रहा, तुज्या भावाचो राग उणो जामेरेन.'" },
    { type: "verse", num: 45, text: "'तुज्या भावाचो तुजेचेर आशिल्लो राग उणो जातलो, आनी तूं ताका कितें केलें तें तो विसरतलो; तेन्ना हांव धाडून तुका थंयसून हाडयतलें. एकाच दिसा तुमचे दोगांयकडसून हांव कित्याक वंचीत जातलें?'" },
    { type: "verse", num: 46, text: "आनी रिबकान इसाकाक म्हणलें, 'हेथाच्या धुवां खातीर म्हजें जिवीत म्हाका कंटाळ्याचें; याकोबान ह्या देसाच्या धुवांमदल्यान, हेथाच्या ह्या धुवांसारकी, बायल घेतली जाल्यार म्हाका जिवीत कित्याक?'" },
  ],
  "28": [
    { type: "section", text: "याकोब पदन-अरामाक गेलो" },
    { type: "verse", num: 1, text: "आनी इसाकान याकोबाक आपयलो आनी ताका आशीर्वाद दिलो आनी ताका आज्ञा दिली: 'कनानी धुवांमदल्यान बायल घेवंका नाका.'" },
    { type: "verse", num: 2, text: "'ऊठ, पदन-अरामांत, तुज्या आवयचो बापूय बथूएल हाच्या घराक वच; आनी तुज्या आवयचो भाव लाबान हाच्या धुवांमदल्यान बायल घे.'" },
    { type: "verse", num: 3, text: "'आनी सर्वशक्तीमान देव तुका आशीर्वाद दिवचो, आनी तुका फळां दिवचो आनी तुका वाडयचो, म्हणचे तूं लोकांचो समुदाय जातलो.'" },
    { type: "verse", num: 4, text: "'आनी तुका आनी तुज्या संततीक अब्राहामाचो आशीर्वाद दिवचो, म्हणचे तूं परदेशी म्हूण रावता तो देस, जो देवान अब्राहामाक दिल्लो, तो तूं वारशान घेतलो.'" },
    { type: "verse", num: 5, text: "अशें इसाकान याकोबाक धाडलो; आनी तो पदन-अरामांत लाबानाकडेन गेलो, तो अरामी बथूएलाचो पूत, याकोब आनी एसाव हांची आवय रिबका हिचो भाव." },
    { type: "verse", num: 6, text: "इसाकान याकोबाक आशीर्वाद दिलो आनी ताका पदन-अरामांत बायल घेवपाक धाडलो, आनी ताका आशीर्वाद दिताना आज्ञा दिली, कनानी धुवांमदल्यान बायल घेवंका नाका, हें एसावान पळयलें." },
    { type: "verse", num: 7, text: "आनी याकोबान आपल्या बापायचें आनी आवयचें आयकलें आनी पदन-अरामांत गेलो." },
    { type: "verse", num: 8, text: "आनी कनानी धुवो आपल्या बापाय इसाकाच्या दोळ्यांत वायट म्हूण एसावान पळयलें." },
    { type: "verse", num: 9, text: "तेन्ना एसाव इश्माएलाकडेन गेलो आनी अब्राहामाचो पूत इश्माएल हाची धूव, नबायोथाची भयण, महालथ, तिका आपल्या बायलांभायर बायल घेतली." },
    { type: "section", text: "याकोबाचें सपन बेथेलांत" },
    { type: "verse", num: 10, text: "आनी याकोब बएर-शेबांतल्यान भायर सरलो आनी हारानाकडेन गेलो." },
    { type: "verse", num: 11, text: "आनी तो एका जाग्यार पावलो आनी थंय रात रावलो, कारण सूर्य बुडिल्लो; आनी ताणें त्या जाग्यांतले फातर घेतले आनी आपल्या तकल्यासकयल दवरले, आनी त्या जाग्यार न्हिदलो." },
    { type: "verse", num: 12, text: "आनी ताणें सपन पळयलें, आनी पळय, एक शिडी पृथ्वीचेर उबी आसली, आनी तिचें तकलें मळबामेरेन पावतालें; आनी पळय, देवाचे दूत तिचेर चडताले आनी देंवताले." },
    { type: "verse", num: 13, text: "आनी पळय, सर्वेस्पर तिचेर उबो आसलो आनी म्हणलें, 'हांव सर्वेस्पर, तुजो बापूय अब्राहामाचो देव आनी इसाकाचो देव; जी भुंय तूं न्हिदला तिचेर ती तुका आनी तुज्या संततीक हांव दितलों.'" },
    { type: "verse", num: 14, text: "'आनी तुजी संतत पृथ्वीच्या धुल्लेसारकी आसतली, आनी तूं अस्तंतेकडेन, उदेंतेकडेन, उत्तरेकडेन आनी दक्षिणेकडेन पातळतलो; आनी तुजे वरवीं आनी तुज्या संतती वरवीं पृथ्वीचीं सगळीं कुळां आशीर्वादीत जातलीं.'" },
    { type: "verse", num: 15, text: "'आनी पळय, हांव तुजेकडेन आसां, आनी तूं वता थंय सगळ्यानीं तुजी राखण करतलों, आनी तुका ह्या देसांत परत हाडटलों; कारण हांवें तुका सांगलां तें करमेरेन हांव तुका सोडचों ना.'" },
    { type: "verse", num: 16, text: "आनी याकोब न्हिदेंतल्यान जागो जालो आनी म्हणलें, 'खात्रीन सर्वेस्पर ह्या जाग्यार आसा; आनी म्हाका खबर नासली.'" },
    { type: "verse", num: 17, text: "आनी तो भियेलो आनी म्हणलें, 'हो जागो किती भिरांतीचो! हो देवाचें घर शिवाय दुसरो कांयच ना, आनी हें मळबाचें दार.'" },
    { type: "verse", num: 18, text: "आनी याकोब सकाळीं उठलो, आनी आपल्या तकल्यासकयल दवरिल्लो फातर घेतलो आनी तो खांब म्हूण उबो केलो, आनी ताच्या तकल्यार तेल ओतलें." },
    { type: "verse", num: 19, text: "आनी ताणें त्या जाग्याचें नांव बेथेल दवरलें; पूण पयलीं त्या शाराचें नांव लूज आसलें." },
    { type: "verse", num: 20, text: "आनी याकोबान नवस केलो: 'देव म्हजेकडेन आसतलो, आनी हांव वतां त्या वाटेन म्हजी राखण करतलो, आनी म्हाका खावपाक भाकर आनी न्हेसपाक वस्त्र दितलो जाल्यार,'" },
    { type: "verse", num: 21, text: "'आनी हांव शांतीन म्हज्या बापायच्या घराक परत आयलों जाल्यार, तेन्ना सर्वेस्पर म्हजो देव जातलो.'" },
    { type: "verse", num: 22, text: "'आनी हो फातर हांवें खांब म्हूण उबो केला तो देवाचें घर जातलें; आनी तूं म्हाका दिता तें सगळें, हांव खात्रीन तुका दशांश दितलों.'" },
  ],
  "29": [
    { type: "section", text: "याकोब लाबानाकडेन" },
    { type: "verse", num: 1, text: "तेन्ना याकोबान आपलो प्रवास चालू केलो आनी उदेंतेच्या लोकांच्या देसांत गेलो." },
    { type: "verse", num: 2, text: "आनी ताणें पळयलें, शेतांत एक हांडो आसलो, आनी पळय, ताचेलागीं मेंढरांचीं तीन कळपां पडून आसलीं; कारण त्या हांड्यांतल्यान कळपांक पियेवताले; आनी हांड्याच्या तोंडार व्हड फातर आसलो." },
    { type: "verse", num: 3, text: "आनी थंय सगळीं कळपां एकठांय जातालीं; आनी ते हांड्याच्या तोंडावयलो फातर लोटताले, आनी मेंढरांक पियेवताले; आनी फातर परत हांड्याच्या तोंडार ताच्या जाग्यार दवरताले." },
    { type: "verse", num: 4, text: "आनी याकोबान तांकां म्हणलें, 'म्हज्या भावांनो, तुमी खंयचे?' आनी ते म्हणाले, 'आमी हारानांतले.'" },
    { type: "verse", num: 5, text: "आनी ताणें तांकां म्हणलें, 'नाहोराचो पूत लाबान तुमी वळखतात?' आनी ते म्हणाले, 'वळखतात.'" },
    { type: "verse", num: 6, text: "आनी ताणें तांकां म्हणलें, 'तो बरो आसा?' आनी ते म्हणाले, 'बरो आसा; आनी पळय, ताची धूव राखेल मेंढरांकडेन येता.'" },
    { type: "verse", num: 7, text: "आनी ताणें म्हणलें, 'पळयात, अजून खूब दीस आसा, गोरवां एकठांय करपाचो वेळ ना; मेंढरांक पियोवात आनी वचात आनी चरात.'" },
    { type: "verse", num: 8, text: "आनी ते म्हणाले, 'आमकां जायना, सगळीं कळपां एकठांय जामेरेन; आनी ते हांड्याच्या तोंडावयलो फातर लोटतात; तेन्ना आमी मेंढरांक पियेवतात.'" },
    { type: "verse", num: 9, text: "तो अजून तांचेकडेन उलयतालो, तेन्ना राखेल आपल्या बापायच्या मेंढरांकडेन आयली; कारण ती तांकां चरयतालें." },
    { type: "verse", num: 10, text: "आनी याकोबान आपल्या आवयचो भाव लाबान हाची धूव राखेल, आनी आपल्या आवयच्या भावा लाबानाचीं मेंढरां पळयलीं, तेन्ना याकोब लागीं सरलो आनी हांड्याच्या तोंडावयलो फातर लोटलो आनी आपल्या आवयच्या भावा लाबानाच्या मेंढरांक पियोवलो." },
    { type: "verse", num: 11, text: "आनी याकोबान राखेलाक उमो दिलो, आनी आवाज उखलून रडलो." },
    { type: "verse", num: 12, text: "आनी याकोबान राखेलाक सांगलें, तो तिच्या बापायचो नातेवाईक, रिबकाचो पूत म्हूण; आनी ती धांवली आनी आपल्या बापायक सांगलें." },
    { type: "verse", num: 13, text: "आनी लाबानान आपल्या भयणीचो पूत याकोब हाची खबर आयकली तेन्ना, तो ताका मेळपाक धांवलो, आनी ताका कवटाळलो, आनी उमो दिलो, आनी ताका आपल्या घरांत हाडलो. आनी ताणें लाबानाक ह्यो सगळ्यो गजाली सांगल्यो." },
    { type: "verse", num: 14, text: "आनी लाबानान ताका म्हणलें, 'खात्रीन तूं म्हजें हाड आनी म्हजें मांस.' आनी तो ताचेकडेन एक म्हयनो रावलो." },
    { type: "verse", num: 15, text: "आनी लाबानान याकोबाक म्हणलें, 'तूं म्हजो नातेवाईक म्हूण फुकट म्हजी सेवा करतलो? म्हाका सांग, तुजो मजूर कितें?'" },
    { type: "verse", num: 16, text: "आनी लाबानाक दोन धुवो आसल्यो; व्हडलेचें नांव लेआ, आनी ल्हानेचें नांव राखेल." },
    { type: "verse", num: 17, text: "लेआचे दोळे कोमळ आसले; पूण राखेल रुपान आनी दिसपाक सोबीत आसली." },
    { type: "verse", num: 18, text: "आनी याकोबान राखेलाचो मोग केलो; आनी म्हणलें, 'तुजी ल्हान धूव राखेल हिचे खातीर हांव तुजी सात वर्सां सेवा करतलों.'" },
    { type: "verse", num: 19, text: "आनी लाबानान म्हणलें, 'ती दुसऱ्या मनशाक दिवचेपरस तुका दिवप बरें; म्हजेकडेन रहा.'" },
    { type: "verse", num: 20, text: "आनी याकोबान राखेल खातीर सात वर्सां सेवा केली; आनी ताच्या मोगान तीं ताका थोडेच दीस दिसलीं." },
    { type: "verse", num: 21, text: "आनी याकोबान लाबानाक म्हणलें, 'म्हजी बायल दी, कारण म्हजे दीस भरल्यात, म्हणचे हांव तिचेकडेन वतलों.'" },
    { type: "verse", num: 22, text: "आनी लाबानान त्या जाग्याचे सगळे मनीस एकठांय केले आनी जेवणावळ केली." },
    { type: "verse", num: 23, text: "आनी सांजेवेळा ताणें आपली धूव लेआ घेतली आनी ताचेकडेन हाडली; आनी तो तिचेकडेन गेलो." },
    { type: "verse", num: 24, text: "आनी लाबानान आपली चाकर्णी जिल्पा आपल्या धुवेक लेआक चाकर्णी दिली." },
    { type: "verse", num: 25, text: "आनी सकाळीं पळय, ती लेआ! आनी ताणें लाबानाक म्हणलें, 'तूं म्हाका हें कितें केलें? हांवें राखेल खातीर तुजी सेवा केली ना? तूं म्हाका कित्याक फटयलो?'" },
    { type: "verse", num: 26, text: "आनी लाबानान म्हणलें, 'आमच्या देसांत ल्हानेक व्हडलेपयलीं दिवप रीत ना.'" },
    { type: "verse", num: 27, text: "'हिचो सप्तक पुरो कर, आनी आमी तुका तीय दितले, तूं म्हजी आनीक सात वर्सां सेवा करतलो तेवरवीं.'" },
    { type: "verse", num: 28, text: "आनी याकोबान तशें केलें आनी तिचो सप्तक पुरो केलो; आनी ताणें ताका आपली धूव राखेल बायल म्हूण दिली." },
    { type: "verse", num: 29, text: "आनी लाबानान आपली चाकर्णी बिल्हा आपल्या धुवेक राखेलाक चाकर्णी दिली." },
    { type: "verse", num: 30, text: "आनी तो राखेलाकडेनूय गेलो, आनी ताणें लेआपरस राखेलाचो चड मोग केलो, आनी ताची आनीक सात वर्सां सेवा केली." },
    { type: "section", text: "याकोबाचीं भुरगीं" },
    { type: "verse", num: 31, text: "आनी सर्वेस्परान पळयलें लेआचो मोग कोणूय करीना म्हूण, ताणें तिचो गर्भ उगडलो; पूण राखेल बांज आसली." },
    { type: "verse", num: 32, text: "आनी लेआ गुरवार जाली आनी एका पुताक जल्म दिलो, आनी ताचें नांव रऊबेन दवरलें; कारण तिणें म्हणलें, 'सर्वेस्परान म्हजें दूख पळयलें; आतां म्हजो घोव म्हजो मोग करतलो.'" },
    { type: "verse", num: 33, text: "आनी ती परत गुरवार जाली आनी एका पुताक जल्म दिलो; आनी म्हणलें, 'म्हजो मोग करनात म्हूण सर्वेस्परान आयकलें, देखून ताणें म्हाका हो पूतय दिलो.' आनी ताचें नांव शिमोन दवरलें." },
    { type: "verse", num: 34, text: "आनी ती परत गुरवार जाली आनी एका पुताक जल्म दिलो; आनी म्हणलें, 'आतां ह्या खेपे म्हजो घोव म्हजेकडेन चिकटतलो, कारण हांवें ताका तीन पूत जल्म दिल्यात.' देखून ताचें नांव लेवी दवरलें." },
    { type: "verse", num: 35, text: "आनी ती परत गुरवार जाली आनी एका पुताक जल्म दिलो; आनी म्हणलें, 'ह्या खेपे हांव सर्वेस्पराची स्तुती करतलें.' देखून ताचें नांव यहूदा दवरलें. आनी तिणें भुरगीं जल्मोवप बंद केलें." },
  ],
  "30": [
    { type: "section", text: "याकोबाचीं आनीक भुरगीं" },
    { type: "verse", num: 1, text: "आनी राखेलान पळयलें, तिणें याकोबाक भुरगीं जल्मोवंक ना, तेन्ना राखेलाक आपल्या भयणीचो हेवो आयलो; आनी तिणें याकोबाक म्हणलें, 'म्हाका भुरगीं दी, नाजाल्यार हांव मरतलें.'" },
    { type: "verse", num: 2, text: "आनी याकोबाक राखेलाचेर राग आयलो आनी म्हणलें, 'हांव देवाच्या जाग्यार आसां, ज्याणें तुका गर्भाचें फळ आडायलें?'" },
    { type: "verse", num: 3, text: "आनी तिणें म्हणलें, 'पळय, म्हजी चाकर्णी बिल्हा; तिचेकडेन वच; आनी ती म्हज्या धोंपऱ्यांचेर जल्म दितली, म्हणचे तिचे वरवीं म्हाकाय भुरगीं मेळतलीं.'" },
    { type: "verse", num: 4, text: "आनी तिणें ताका आपली चाकर्णी बिल्हा बायल म्हूण दिली; आनी याकोब तिचेकडेन गेलो." },
    { type: "verse", num: 5, text: "आनी बिल्हा गुरवार जाली आनी याकोबाक एक पूत जल्म दिलो." },
    { type: "verse", num: 6, text: "आनी राखेलान म्हणलें, 'देवान म्हजो न्याय केला, आनी म्हजो आवाज आयकला, आनी म्हाका एक पूत दिलो.' देखून तिणें ताचें नांव दान दवरलें." },
    { type: "verse", num: 7, text: "आनी राखेलाची चाकर्णी बिल्हा परत गुरवार जाली आनी याकोबाक दुसरो पूत जल्म दिलो." },
    { type: "verse", num: 8, text: "आनी राखेलान म्हणलें, 'हांवें म्हज्या भयणीकडेन देवाच्या झगड्यांनी झगडलें आनी जिकलें.' आनी तिणें ताचें नांव नफ्ताली दवरलें." },
    { type: "verse", num: 9, text: "लेआन पळयलें, तिणें भुरगीं जल्मोवप बंद केलां, तेन्ना तिणें आपली चाकर्णी जिल्पा याकोबाक बायल म्हूण दिली." },
    { type: "verse", num: 10, text: "आनी लेआची चाकर्णी जिल्पान याकोबाक एक पूत जल्म दिलो." },
    { type: "verse", num: 11, text: "आनी लेआन म्हणलें, 'नशीब आयलें!' आनी तिणें ताचें नांव गाद दवरलें." },
    { type: "verse", num: 12, text: "आनी लेआची चाकर्णी जिल्पान याकोबाक दुसरो पूत जल्म दिलो." },
    { type: "verse", num: 13, text: "आनी लेआन म्हणलें, 'हांव धन्य! कारण धुवो म्हाका धन्य म्हणतल्यो.' आनी तिणें ताचें नांव आशेर दवरलें." },
    { type: "verse", num: 14, text: "आनी रऊबेन गव्हाच्या कापणेच्या दिसांनी शेतांत गेलो आनी दूदिफळां सोदलीं आनी तीं आपल्या आवयक लेआक हाडलीं. आनी राखेलान लेआक म्हणलें, 'तुज्या पुताच्या दूदिफळांतलीं म्हाका दी.'" },
    { type: "verse", num: 15, text: "आनी तिणें तिका म्हणलें, 'तूं म्हजो घोव घेतलो तें थोडें? आनी तूं म्हज्या पुताचीं दूदिफळांय घेवपाक सोदता?' आनी राखेलान म्हणलें, 'तुज्या पुताच्या दूदिफळां खातीर तो आज राती तुजेकडेन न्हिदतलो.'" },
    { type: "verse", num: 16, text: "आनी याकोब सांजेवेळा शेतांतल्यान आयलो, तेन्ना लेआ ताका मेळपाक भायर सरली आनी म्हणलें, 'तूं म्हजेकडेन येवंक जाय; कारण म्हज्या पुताच्या दूदिफळांनी हांवें तुका भाड्यान घेतला.' आनी तो त्या राती तिचेकडेन न्हिदलो." },
    { type: "verse", num: 17, text: "आनी देवान लेआचें आयकलें; आनी ती गुरवार जाली आनी याकोबाक पांचवो पूत जल्म दिलो." },
    { type: "verse", num: 18, text: "आनी लेआन म्हणलें, 'देवान म्हाका म्हजो मजूर दिला, कारण हांवें म्हज्या घोवाक म्हजी चाकर्णी दिली.' आनी तिणें ताचें नांव इस्साखार दवरलें." },
    { type: "verse", num: 19, text: "आनी लेआ परत गुरवार जाली आनी याकोबाक सवो पूत जल्म दिलो." },
    { type: "verse", num: 20, text: "आनी लेआन म्हणलें, 'देवान म्हाका बरें दान दिलां; आतां म्हजो घोव म्हजेकडेन रावतलो, कारण हांवें ताका स वर्सां पूत जल्म दिल्यात.' आनी तिणें ताचें नांव जबुलून दवरलें." },
    { type: "verse", num: 21, text: "आनी त्या उपरांत तिणें एका धुवेक जल्म दिलो आनी तिचें नांव दीना दवरलें." },
    { type: "verse", num: 22, text: "आनी देवान राखेलाची याद केली, आनी देवान तिचें आयकलें आनी तिचो गर्भ उगडलो." },
    { type: "verse", num: 23, text: "आनी ती गुरवार जाली आनी एका पुताक जल्म दिलो; आनी म्हणलें, 'देवान म्हजी लज काडून उडयल्या.'" },
    { type: "verse", num: 24, text: "आनी तिणें ताचें नांव योसेफ दवरलें; आनी म्हणलें, 'सर्वेस्पर म्हाका आनीक एक पूत भर घालूंदी.'" },
    { type: "section", text: "याकोबाची कळपां वाडलीं" },
    { type: "verse", num: 25, text: "आनी राखेलान योसेफाक जल्म दिल्या उपरांत याकोबान लाबानाक म्हणलें, 'म्हाका धाड, म्हणचे हांव म्हज्या जाग्याक आनी म्हज्या देसांत वतलों.'" },
    { type: "verse", num: 26, text: "'म्हज्यो बायलो आनी म्हजीं भुरगीं दी, ज्यांचे खातीर हांवें तुजी सेवा केल्या, आनी हांव वतलों; कारण हांवें तुजी केल्ली सेवा तूं जाणा.'" },
    { type: "verse", num: 27, text: "आनी लाबानान ताका म्हणलें, 'तुज्या दोळ्यांत म्हाका कुर्पा मेळ्ळ्या जाल्यार, रहा; कारण हांवें अणभव घेवन जाणलां, तुजे खातीर सर्वेस्परान म्हाका आशीर्वाद दिला.'" },
    { type: "verse", num: 28, text: "आनी ताणें म्हणलें, 'तुजो मजूर ठरय, आनी हांव दितलों.'" },
    { type: "verse", num: 29, text: "आनी ताणें ताका म्हणलें, 'हांवें तुजी कशी सेवा केल्या, आनी तुजीं गोरवां म्हजेकडेन कशीं जालीं तें तूं जाणा.'" },
    { type: "verse", num: 30, text: "'कारण हांव येवचेपयलीं तुजेकडेन थोडें आसलें, आनी तें खूब वाडलें; आनी म्हज्या पांया उपरांत सर्वेस्परान तुका आशीर्वाद दिला; आनी आतां म्हज्या स्वताच्या घरा खातीर हांव केन्ना कितें करतलों?'" },
    { type: "verse", num: 31, text: "आनी ताणें म्हणलें, 'तुका कितें दितलों?' आनी याकोबान म्हणलें, 'म्हाका कांयच दिवंका नाका; तूं म्हाका ही गजाल करता जाल्यार, हांव परत तुजीं कळपां चरयतलों आनी राखण करतलों.'" },
    { type: "verse", num: 32, text: "'आज हांव तुज्या सगळ्या कळपांमदल्यान वतलों, आनी थंयसून दरेक ठिपकें आनी पट्टेदार मेंढरू, आनी बोकडांमदलें दरेक काळें, आनी ठिपकीं आनी पट्टेदार बोकडीं वेगळीं करतलों; आनी तीं म्हजो मजूर आसतलीं.'" },
    { type: "verse", num: 33, text: "'आनी फुडाराक म्हजी नीत म्हजे खातीर साक्ष दितली, तूं म्हजो मजूर पळोवपाक येतलो तेन्ना; बोकडांमदलें जें कितें ठिपकें आनी पट्टेदार ना, आनी मेंढरांमदलें काळें ना, तें म्हजेकडेन आसल्यार चोरयिल्लें मानतलें.'" },
    { type: "verse", num: 34, text: "आनी लाबानान म्हणलें, 'बरें, तूं म्हणता तशें जांव.'" },
    { type: "verse", num: 35, text: "आनी त्या दिसा ताणें पट्टेदार आनी ठिपकीं बोकडां, आनी सगळ्यो पट्टेदार आनी ठिपक्यो बोकड्यो, ज्यांचेर धवेपण आसलें, आनी मेंढरांमदलें सगळें काळें वेगळें केलें; आनी आपल्या पुतांच्या हातांत दवरलें." },
    { type: "verse", num: 36, text: "आनी ताणें आपल्यामदीं आनी याकोबामदीं तीन दिसांचो प्रवास दवरलो; आनी याकोबान लाबानाचीं उरिल्लीं कळपां चरयलीं." },
    { type: "verse", num: 37, text: "आनी याकोबान ताज्यो काड्यो चिनाराच्या, बदामाच्या आनी धावण्याच्या घेतल्यो आनी तांच्यो साली काडल्यो, धव्यो पट्ट्यो करून, काड्यांचें धवें उगडें केलें." },
    { type: "verse", num: 38, text: "आनी साली काडिल्ल्यो काड्यो ताणें कळपांमुखार दोण्यांनी दवरल्यो, उदकाच्या दोण्यांत, जंय कळपां पियेवपाक येतालीं; आनी ते पियेवपाक येताले तेन्ना गुरवार जाताले." },
    { type: "verse", num: 39, text: "आनी कळपां काड्यांमुखार गुरवार जालीं, आनी कळपांनी पट्टेदार, ठिपकीं आनी चिरेदार जल्म दिलीं." },
    { type: "verse", num: 40, text: "आनी याकोबान मेंढरां वेगळीं केलीं, आनी कळपांचीं तोंडां लाबानाच्या कळपांमदल्या पट्टेदार आनी सगळ्या काळ्यांकडेन केलीं; आनी ताणें आपलीं कळपां वेगळीं दवरलीं आनी लाबानाच्या कळपांकडेन घालीं नात." },
    { type: "verse", num: 41, text: "आनी बळिष्ट कळपां गुरवार जाताले तेन्ना, याकोबान काड्यो दोण्यांत कळपांच्या दोळ्यांमुखार दवरताले, म्हणचे ते काड्यांकडेन गुरवार जाताले." },
    { type: "verse", num: 42, text: "पूण कळपां कमजोर आसताले तेन्ना, ताणें तांकां दवरूंक नासलें; अशें कमजोर लाबानाचीं आनी बळिष्ट याकोबाचीं जालीं." },
    { type: "verse", num: 43, text: "आनी मनीस खूब खूब वाडलो; आनी ताका खूब कळपां, चाकर्ण्यो, चाकर, उंट आनी गाडवां मेळ्ळीं." },
  ],
  "31": [
    { type: "section", text: "याकोब लाबानाकडसून पळून गेलो" },
    { type: "verse", num: 1, text: "आनी लाबानाच्या पुतांचीं उतरां ताणें आयकलीं: 'याकोबान आमच्या बापायचें सगळें घेतलां; आनी आमच्या बापायच्या संपत्तीपसून ताणें ही सगळी म्हिमा मेळयल्या.'" },
    { type: "verse", num: 2, text: "आनी याकोबान लाबानाचें तोंड पळयलें, आनी पळय, तें ताचेकडेन पयलींसारकें नासलें." },
    { type: "verse", num: 3, text: "आनी सर्वेस्परान याकोबाक म्हणलें, 'तुज्या बापायांच्या देसांत आनी तुज्या नात्यागोत्यांत परत वच, आनी हांव तुजेकडेन आसतलों.'" },
    { type: "verse", num: 4, text: "आनी याकोबान धाडून राखेल आनी लेआक शेतांत आपल्या कळपांकडेन आपयल्यो." },
    { type: "verse", num: 5, text: "आनी तांकां म्हणलें, 'हांव तुमच्या बापायचें तोंड पळयतां, तें म्हजेकडेन पयलींसारकें ना; पूण म्हज्या बापायचो देव म्हजेकडेन आसा.'" },
    { type: "verse", num: 6, text: "'आनी तुमी जाणतात, हांवें म्हज्या सगळ्या बळान तुमच्या बापायची सेवा केल्या.'" },
    { type: "verse", num: 7, text: "'आनी तुमच्या बापायन म्हाका फटयलो आनी म्हजो मजूर धा खेपो बदललो; पूण देवान ताका म्हाका वायट करपाक दिलें ना.'" },
    { type: "verse", num: 8, text: "'ताणें म्हणलें, ठिपकीं तुजो मजूर, जाल्यार सगळ्या कळपांनी ठिपकीं जल्म दिलीं; आनी ताणें म्हणलें, पट्टेदार तुजो मजूर, जाल्यार सगळ्या कळपांनी पट्टेदार जल्म दिलीं.'" },
    { type: "verse", num: 9, text: "'अशें देवान तुमच्या बापायचीं गोरवां काडून म्हाका दिल्यांत.'" },
    { type: "verse", num: 10, text: "'आनी कळपां गुरवार जाल्ल्या वेळार हांवें सपनांत दोळे उखलून पळयलें, आनी पळय, कळपांक चडपी बोकडां पट्टेदार, ठिपकीं आनी चिरेदार आसलीं.'" },
    { type: "verse", num: 11, text: "'आनी देवाच्या दुतान सपनांत म्हाका म्हणलें, याकोब. आनी हांवें म्हणलें, हांगा हांव.'" },
    { type: "verse", num: 12, text: "'आनी ताणें म्हणलें, तुजे दोळे उखल आनी पळय, कळपांक चडपी सगळे बोकडां पट्टेदार, ठिपकीं आनी चिरेदार; कारण लाबान तुका कितें करता तें सगळें हांवें पळयलां.'" },
    { type: "verse", num: 13, text: "'हांव बेथेलाचो देव, जंय तूं खांबाक तेल ओतलें, जंय तूं म्हाका नवस केलो; आतां ऊठ, ह्या देसांतल्यान भायर सर आनी तुज्या जल्माच्या देसांत परत वच.'" },
    { type: "verse", num: 14, text: "आनी राखेल आनी लेआन ताका जाप दिली, 'आमच्या बापायच्या घरांत आमकां वांटो वा वारसो अजून आसा?'" },
    { type: "verse", num: 15, text: "'ताणें आमकां परक्यांसारक्यो मानलीं ना? कारण ताणें आमकां विकल्यांत आनी आमचें रूपय खाल्लां.'" },
    { type: "verse", num: 16, text: "'कारण देवान आमच्या बापायकडसून काडिल्ली सगळी संपत्ती आमची आनी आमच्या भुरग्यांची; आतां देवान तुका सांगिल्लें तें सगळें कर.'" },
    { type: "verse", num: 17, text: "तेन्ना याकोब उठलो आनी आपल्या भुरग्यांक आनी बायलांक उंटांचेर बसयलें." },
    { type: "verse", num: 18, text: "आनी ताणें आपलीं सगळीं गोरवां आनी आपणें मेळयिल्ली सगळी संपत्ती, ताणें पदन-अरामांत मेळयिल्लीं गोरवां, कनान देसांत आपल्या बापाय इसाकाकडेन वचपाक घेवन गेलो." },
    { type: "verse", num: 19, text: "आनी लाबान आपल्या मेंढरांची लोंकर कातरपाक गेल्लो; आनी राखेलान आपल्या बापायच्यो मुर्त्यो चोरल्यो." },
    { type: "verse", num: 20, text: "आनी याकोबान अरामी लाबानाक फटयलो, कारण ताणें ताका सांगलें ना की तो पळटा." },
    { type: "verse", num: 21, text: "अशें तो आपलें सगळें घेवन पळून गेलो; आनी ताणें उठून न्हंय हुपून गिलादाच्या दोंगराकडेन तोंड केलें." },
    { type: "verse", num: 22, text: "आनी तिसऱ्या दिसा लाबानाक सांगलें, याकोब पळून गेला." },
    { type: "verse", num: 23, text: "आनी ताणें आपल्या भावांक आपणेकडेन घेतलें आनी सात दिसांचो प्रवास ताचो फाटलाग केलो; आनी गिलादाच्या दोंगरांत ताका गांठलो." },
    { type: "verse", num: 24, text: "आनी देव अरामी लाबानाकडेन रातीक सपनांत आयलो आनी ताका म्हणलें, 'जतन कर, याकोबाक बरें वा वायट सांगूंका नाका.'" },
    { type: "verse", num: 25, text: "तेन्ना लाबान याकोबाक गांठलो. आनी याकोबान दोंगरांत आपलो तंबू मारिल्लो; आनी लाबानान आपल्या भावांकडेन गिलादाच्या दोंगरांत तंबू मारलो." },
    { type: "verse", num: 26, text: "आनी लाबानान याकोबाक म्हणलें, 'तूं कितें केलें, म्हाका फटोवन, आनी म्हज्या धुवांक तरवारीन धरिल्ल्या बंदखणीतल्यांसारक्यो व्हरून?'" },
    { type: "verse", num: 27, text: "'तूं चोरून कित्याक पळलो, आनी म्हाका फटयलो, आनी म्हाका सांगलें ना? म्हणचे हांव तुका आनंदान आनी गायनांनी, डफान आनी वीणेन धाडतो.'" },
    { type: "verse", num: 28, text: "'आनी तूं म्हाका म्हज्या पुतांक आनी म्हज्या धुवांक उमो दिवपाक दिलें ना? आतां तूं मुर्खपणान केलें.'" },
    { type: "verse", num: 29, text: "'तुका वायट करपाची शक्त म्हज्या हातांत आसा; पूण तुज्या बापायचो देव काल रातीक म्हाका म्हणलो, जतन कर, याकोबाक बरें वा वायट सांगूंका नाका.'" },
    { type: "verse", num: 30, text: "'आतां तूं गेलो कारण तुज्या बापायच्या घराचें तुका खूब आशेलें; पूण म्हजे देव तूं कित्याक चोरले?'" },
    { type: "verse", num: 31, text: "आनी याकोबान जाप दिली आनी लाबानाक म्हणलें, 'कारण हांव भियेलों; कारण हांवें म्हणलें, तूं तुज्यो धुवो म्हजेकडसून बळान काडतलो.'" },
    { type: "verse", num: 32, text: "'ज्याचेकडेन तुजे देव मेळटात, तो जिवो उरचो ना. आमच्या भावांमुखार पळय, तुजें म्हजेकडेन कितें आसा, तें घे.' कारण राखेलान ते चोरल्यात म्हूण याकोबाक खबर नासली." },
    { type: "verse", num: 33, text: "आनी लाबान याकोबाच्या तंबूंत आनी लेआच्या तंबूंत आनी दोन चाकर्ण्यांच्या तंबूंत गेलो, पूण सोदून मेळ्ळे नात. आनी तो लेआच्या तंबूंतल्यान भायर सरलो आनी राखेलाच्या तंबूंत गेलो." },
    { type: "verse", num: 34, text: "आनी राखेलान मुर्त्यो घेतल्यो आनी उंटाच्या खोगिरांत दवरल्यो आनी तांचेर बसली. आनी लाबानान सगळो तंबू सोदलो पूण मेळ्ळ्यो नात." },
    { type: "verse", num: 35, text: "आनी तिणें आपल्या बापायक म्हणलें, 'म्हज्या धन्याच्या दोळ्यांत राग येवंका नाका, तुजेमुखार उठपाक म्हाका जायना; कारण बायलांची रीत म्हजेर आसा.' आनी ताणें सोदलें पूण मुर्त्यो मेळ्ळ्यो नात." },
    { type: "verse", num: 36, text: "आनी याकोबाक राग आयलो आनी लाबानाकडेन झगडलो. आनी याकोबान जाप दिली आनी लाबानाक म्हणलें, 'म्हजो अपराध कितें? म्हजें पातक कितें, म्हणून तूं म्हजो इतक्या जोरान फाटलाग केलो?'" },
    { type: "verse", num: 37, text: "'तूं म्हज्यो सगळ्यो वस्ती सोदल्या; तुज्या घरांतली कसली वस्त तुका मेळ्ळी? ती हांगा म्हज्या भावांमुखार आनी तुज्या भावांमुखार दवर, म्हणचे ते आमचे दोगांयमदीं न्याय करूंदीत.'" },
    { type: "verse", num: 38, text: "'हीं वीस वर्सां हांव तुजेकडेन आसलों; तुज्यो मेंढऱ्यो आनी तुज्यो बोकड्यो केन्नाच नश्ट जाल्यो नात; आनी तुज्या कळपांतले मेंढे हांवें खाल्ले नात.'" },
    { type: "verse", num: 39, text: "'रानवटी जनावरांनी मारिल्लें हांवें तुजेकडेन हाडलें ना; ताचो लुकसाण हांवेंच सोसलो; दिसा चोरयिल्लें वा राती चोरयिल्लें, तूं म्हजेकडसून मागतालो.'" },
    { type: "verse", num: 40, text: "'अशें आसलें; दिसा उश्णतायेन म्हाका खालें, आनी राती थंडीन; आनी म्हज्या दोळ्यांतल्यान न्हीद पळाली.'" },
    { type: "verse", num: 41, text: "'हीं वीस वर्सां हांव तुज्या घरांत आसलों; तुज्या दोन धुवां खातीर चवदा वर्सां आनी तुज्या कळपां खातीर स वर्सां हांवें तुजी सेवा केली; आनी तूं म्हजो मजूर धा खेपो बदललो.'" },
    { type: "verse", num: 42, text: "'म्हज्या बापायचो देव, अब्राहामाचो देव, आनी इसाकाची भिरांत म्हजेकडेन नासती जाल्यार, तूं आतां खात्रीन म्हाका रिक्या हातांनी धाडतो. म्हजें दूख आनी म्हज्या हातांचें काम देवान पळयलें, आनी काल रातीक तुका दटायलो.'" },
    { type: "verse", num: 43, text: "आनी लाबानान जाप दिली आनी याकोबाक म्हणलें, 'ह्यो धुवो म्हज्यो धुवो, आनी हीं भुरगीं म्हजीं भुरगीं, आनी हीं कळपां म्हजीं कळपां, आनी तूं पळयता तें सगळें म्हजें; आनी म्हज्या ह्या धुवांक वा तांणीं जल्म दिल्ल्या भुरग्यांक आज हांव कितें करतलों?'" },
    { type: "verse", num: 44, text: "'आतां यो, आमी करार करूया, हांव आनी तूं; आनी तो म्हजेमदीं आनी तुजेमदीं साक्ष आसूंदी.'" },
    { type: "verse", num: 45, text: "आनी याकोबान एक फातर घेतलो आनी तो खांब म्हूण उबो केलो." },
    { type: "verse", num: 46, text: "आनी याकोबान आपल्या भावांक म्हणलें, 'फातर एकठांय करात.' आनी तांणीं फातर घेतले आनी राश केली; आनी तांणीं राशीचेर खालें." },
    { type: "verse", num: 47, text: "आनी लाबानान तिका यगर-शहदूथा म्हणलें; आनी याकोबान तिका गलेद म्हणलें." },
    { type: "verse", num: 48, text: "आनी लाबानान म्हणलें, 'ही राश आज म्हजेमदीं आनी तुजेमदीं साक्ष.' देखून ताचें नांव गलेद दवरलें." },
    { type: "verse", num: 49, text: "आनी मिस्पा, कारण ताणें म्हणलें, 'आमी एकामेकांपसून लिपिल्ले आसताना सर्वेस्पर म्हजेमदीं आनी तुजेमदीं पारखो करूंदी.'" },
    { type: "verse", num: 50, text: "'तूं म्हज्या धुवांक कठीण केलें जाल्यार, वा म्हज्या धुवांभायर बायलो घेतल्यो जाल्यार, आमचेकडेन कोणूय मनीस ना; पळय, देव म्हजेमदीं आनी तुजेमदीं साक्षी.'" },
    { type: "verse", num: 51, text: "आनी लाबानान याकोबाक म्हणलें, 'ही राश पळय, आनी हो खांब पळय, जो हांवें म्हजेमदीं आनी तुजेमदीं उबो केला.'" },
    { type: "verse", num: 52, text: "'ही राश साक्ष, आनी हो खांब साक्ष, हांव ह्या राशी वतेन तुजेकडेन वचचों ना, आनी तूं ह्या राशी वतेन आनी ह्या खांबा वतेन म्हजेकडेन येवचो ना, वायटा खातीर.'" },
    { type: "verse", num: 53, text: "'अब्राहामाचो देव आनी नाहोराचो देव, तांच्या बापायचो देव, आमचेमदीं न्याय करूंदी.' आनी याकोबान आपल्या बापाय इसाकाच्या भिरांतीची आण घाल्ली." },
    { type: "verse", num: 54, text: "आनी याकोबान दोंगरांत बली अर्पण केलो, आनी आपल्या भावांक भाकर खावपाक आपयलें; आनी तांणीं भाकर खाली आनी दोंगरांत रात रावले." },
    { type: "verse", num: 55, text: "आनी लाबान सकाळीं उठलो, आनी आपल्या पुतांक आनी धुवांक उमे दिले आनी तांकां आशीर्वाद दिलो; आनी लाबान गेलो आनी आपल्या जाग्यार परत आयलो." },
  ],
  "32": [
    { type: "section", text: "याकोब एसावाक मेळपाक तयार जालो" },
    { type: "verse", num: 1, text: "आनी याकोब आपल्या वाटेन गेलो, आनी देवाचे दूत ताका मेळ्ळे." },
    { type: "verse", num: 2, text: "आनी याकोबान तांकां पळयलें तेन्ना म्हणलें, 'हें देवाचें सैन्य.' आनी ताणें त्या जाग्याचें नांव महनायीम दवरलें." },
    { type: "verse", num: 3, text: "आनी याकोबान आपल्या भावा एसावाकडेन सेईर देसांत, एदोमाच्या शेतांत दूत धाडले." },
    { type: "verse", num: 4, text: "आनी तांकां आज्ञा दिली: 'म्हज्या धन्या एसावाक अशें सांगात: तुजो चाकर याकोब अशें म्हणता, हांव लाबानाकडेन परदेशी जावन आतांमेरेन रावलों.'" },
    { type: "verse", num: 5, text: "'आनी म्हजेकडेन बैल, गाडवां, मेंढरां, चाकर आनी चाकर्ण्यो आसात; आनी हांवें म्हज्या धन्याक सांगपाक धाडलां, म्हणचे तुज्या दोळ्यांत म्हाका कुर्पा मेळटली.'" },
    { type: "verse", num: 6, text: "आनी दूत याकोबाकडेन परत आयले आनी म्हणाले, 'आमी तुज्या भावा एसावाकडेन गेलीं; आनी तो तुका मेळपाक येता, आनी ताचेकडेन चारशें मनीस आसात.'" },
    { type: "verse", num: 7, text: "तेन्ना याकोब खूब भियेलो आनी संकश्टांत पडलो; आनी ताणें आपणेकडेन आशिल्ल्या लोकांक, आनी मेंढरांक, गोरवांक आनी उंटांक दोन गटांनी वांटलें." },
    { type: "verse", num: 8, text: "आनी म्हणलें, 'एसाव एका गटाक येवन मारतलो जाल्यार, उरिल्लो गट पळतलो.'" },
    { type: "verse", num: 9, text: "आनी याकोबान म्हणलें, 'म्हज्या बापाय अब्राहामाच्या देवा आनी म्हज्या बापाय इसाकाच्या देवा, सर्वेस्परा, ज्याणें म्हाका म्हणलें, तुज्या देसांत आनी तुज्या नात्यागोत्यांत परत वच, आनी हांव तुका बरें करतलों;'" },
    { type: "verse", num: 10, text: "'तूं तुज्या चाकराक दाखयिल्ल्या सगळ्या दयेक आनी सगळ्या सताक हांव पावची ना; कारण फकत म्हज्या काठयेन हांव ही यॉर्दन न्हंय हुपलों; आनी आतां हांव दोन गट जालों.'" },
    { type: "verse", num: 11, text: "'म्हज्या भावा एसावाच्या हातांतल्यान म्हाका वाचय; कारण हांव ताचो भिता, तो येवन म्हाका आनी आवयांक भुरग्यांसयत मारतलो.'" },
    { type: "verse", num: 12, text: "'आनी तूं म्हणलें, हांव खात्रीन तुका बरें करतलों, आनी तुजी संतत दर्याच्या रेंवेसारकी करतलों, जी मेजप अशक्य.'" },
    { type: "verse", num: 13, text: "आनी तो त्या राती थंय रावलो; आनी ताणें ताचेकडेन जें आसलें तातूंतलें आपल्या भावा एसावाक दान घेतलें:" },
    { type: "verse", num: 14, text: "दोनशें बोकड्यो आनी वीस बोकडां, दोनशें मेंढऱ्यो आनी वीस मेंढे," },
    { type: "verse", num: 15, text: "तीस दूद दिवपी उंटीणी आनी तांचीं पिलां, चाळीस गायो आनी धा गोंयां, वीस गाडवीणी आनी धा गाडवां." },
    { type: "verse", num: 16, text: "आनी ताणें तीं आपल्या चाकरांच्या हातांत दिलीं, दरेक कळप वेगळें; आनी आपल्या चाकरांक म्हणलें, 'म्हजेमुखार वचात, आनी दरेक कळपामदीं अंतर दवरात.'" },
    { type: "verse", num: 17, text: "आनी पयल्याक आज्ञा दिली: 'म्हजो भाव एसाव तुका मेळटलो तेन्ना तुका विचारतलो, तूं कोणाचो? आनी तूं खंय वता? आनी तुजेमुखार हीं कोणाचीं?'" },
    { type: "verse", num: 18, text: "'तेन्ना तूं म्हणतलो, तुज्या चाकरा याकोबाचीं; तीं म्हज्या धन्या एसावाक दान धाडिल्लीं; आनी पळय, तो आमच्या फाटल्यान आसा.'" },
    { type: "verse", num: 19, text: "आनी दुसऱ्याक, आनी तिसऱ्याक, आनी कळपांफाटल्यान चलपी सगळ्यांक आज्ञा दिली: 'एसावाक तुमी मेळटात तेन्ना ताका अशें सांगात.'" },
    { type: "verse", num: 20, text: "'आनी म्हणात, तुजो चाकर याकोब आमच्या फाटल्यान आसा.' कारण ताणें म्हणलें, 'म्हजेमुखार वचपी दानान ताचें तोंड शांत करतलों; आनी त्या उपरांत ताचें तोंड पळयतलों; कदाचीत तो म्हजो स्वीकार करतलो.'" },
    { type: "verse", num: 21, text: "अशें दान ताचेमुखार गेलें; आनी तो त्या राती छावणींत रावलो." },
    { type: "section", text: "याकोब पनीएलांत झगडलो" },
    { type: "verse", num: 22, text: "आनी तो त्या राती उठलो आनी आपल्यो दोन बायलो, आनी दोन चाकर्ण्यो, आनी आपलीं इकरा भुरगीं घेतलीं आनी याब्बोकाचो हूद हुपलो." },
    { type: "verse", num: 23, text: "आनी ताणें तांकां घेतलें आनी न्हंय हुपयलें, आनी ताचेकडेन जें कितें आसलें तें हुपयलें." },
    { type: "verse", num: 24, text: "आनी याकोब एकलो उरलो; आनी उजवाडमेरेन एक मनीस ताचेकडेन झगडलो." },
    { type: "verse", num: 25, text: "आनी ताणें पळयलें ताचेर ताचो जैत जायना, तेन्ना ताणें ताच्या मांडयेच्या सांध्याक लागलो; आनी याकोबाच्या मांडयेचो सांधो ताचेकडेन झगडटाना भायर आयलो." },
    { type: "verse", num: 26, text: "आनी ताणें म्हणलें, 'म्हाका सोड, कारण उजवाडटा.' आनी ताणें म्हणलें, 'तूं म्हाका आशीर्वाद दिना तोमेरेन हांव तुका सोडचों ना.'" },
    { type: "verse", num: 27, text: "आनी ताणें ताका म्हणलें, 'तुजें नांव कितें?' आनी ताणें म्हणलें, 'याकोब.'" },
    { type: "verse", num: 28, text: "आनी ताणें म्हणलें, 'तुजें नांव आनीक याकोब म्हणचें ना, पूण इस्राएल; कारण तूं देवाकडेन आनी मनशांकडेन झगडला आनी जिकला.'" },
    { type: "verse", num: 29, text: "आनी याकोबान विचारलें, 'तुजें नांव म्हाका सांग.' आनी ताणें म्हणलें, 'तूं म्हजें नांव कित्याक विचारता?' आनी ताणें ताका थंय आशीर्वाद दिलो." },
    { type: "verse", num: 30, text: "आनी याकोबान त्या जाग्याचें नांव पनीएल दवरलें: 'कारण हांवें देवाक तोंडार तोंड पळयलो, आनी म्हजो जीव वाचलो.'" },
    { type: "verse", num: 31, text: "आनी तो पनीएल हुपताना सूर्य ताचेर उदेलो; आनी तो आपल्या मांडयेवयल्यान कुंटत चलतालो." },
    { type: "verse", num: 32, text: "देखून इस्राएलाचे पूत मांडयेच्या सांध्यावयलो शिर खायनात, आज मेरेन; कारण ताणें याकोबाच्या मांडयेच्या सांध्यावयल्या शिराक लागिल्लो." },
  ],
  "33": [
    { type: "section", text: "याकोब एसावाक मेळ्ळो" },
    { type: "verse", num: 1, text: "आनी याकोबान दोळे उकलले आनी पळयलें, आनी पळय, एसाव येतालो, आनी ताचेकडेन चारशें मनीस आसले. आनी ताणें भुरग्यांक लेआकडेन आनी राखेलकडेन आनी दोन चाकर्ण्यांकडेन वांटलीं." },
    { type: "verse", num: 2, text: "आनी चाकर्ण्यांक आनी तांच्या भुरग्यांक सगळ्यांत मुखार दवरलें, आनी लेआक आनी तिच्या भुरग्यांक तांचे फाटल्यान, आनी राखेलक आनी योसेफाक सगळ्यांत फाटल्यान दवरलें." },
    { type: "verse", num: 3, text: "आनी तो तांचेमुखार गेलो, आनी आपल्या भावाकडेन पावमेरेन सात फावट भुंयेमेरेन नमन केलें." },
    { type: "verse", num: 4, text: "आनी एसाव ताका मेळपाक धांवलो, आनी ताका वेंगेंत घेतलें, आनी ताच्या गळ्याक पडलो, आनी ताका उमो दिलो; आनी ते रडले." },
    { type: "verse", num: 5, text: "आनी ताणें दोळे उकलले आनी बायलांक आनी भुरग्यांक पळयलें, आनी म्हणलें, 'तुजेकडेन हे कोण आसात?' आनी ताणें म्हणलें, 'देवान तुज्या चाकराक कुर्पेन दिल्लीं भुरगीं.'" },
    { type: "verse", num: 6, text: "तेन्ना चाकर्ण्यो लागीं आयल्यो, त्यो आनी तांचीं भुरगीं, आनी तांणीं नमन केलें." },
    { type: "verse", num: 7, text: "आनी लेआय आनी तिचीं भुरगीं लागीं आयलीं, आनी तांणीं नमन केलें; आनी त्या उपरांत योसेफ आनी राखेल लागीं आयलीं, आनी तांणीं नमन केलें." },
    { type: "verse", num: 8, text: "आनी ताणें म्हणलें, 'हे सगळे कळप जे म्हाका मेळ्ळे ते कित्याक?' आनी ताणें म्हणलें, 'म्हज्या धन्याच्या दोळ्यांत कुर्पा मेळपाक.'" },
    { type: "verse", num: 9, text: "आनी एसावान म्हणलें, 'म्हजेकडेन पुरो आसा, म्हज्या भावा; तुजें तुजेकडेन आसूंदी.'" },
    { type: "verse", num: 10, text: "आनी याकोबान म्हणलें, 'ना, कुर्पा कर; जर म्हाका तुज्या दोळ्यांत कुर्पा मेळ्ळ्या, तर म्हज्या हातांतल्यान म्हजें दान घे; कारण म्हजे खातीर तुजें तोंड पळोवप म्हणल्यार देवाचें तोंड पळोवप, आनी तूं म्हजो स्वीकार केलो.'" },
    { type: "verse", num: 11, text: "'म्हजो आशीर्वाद घे जो तुका हाडला; कारण देवान म्हजेर कुर्पा केल्या, आनी म्हजेकडेन सगळें आसा.' आनी ताणें ताका बळजबरी केली, आनी ताणें घेतलें." },
    { type: "verse", num: 12, text: "आनी ताणें म्हणलें, 'चल आमी वचूया, आनी हांव तुजेमुखार वतलों.'" },
    { type: "verse", num: 13, text: "आनी ताणें ताका म्हणलें, 'म्हज्या धन्याक कळटा भुरगीं कोमल आसात, आनी म्हजेकडेन दूद दिवपी मेंढऱ्यो आनी गायो आसात; तांकां एक दीस जरी धांवडायल्यार, सगळीं मेंढरां मरतलीं.'" },
    { type: "verse", num: 14, text: "'म्हजो धनी आपल्या चाकरामुखार वचूं; आनी हांव म्हजेमुखार आशिल्ल्या गोरवांच्या आनी भुरग्यांच्या गतीन सवकास वतलों, मेरेन सेईरांत म्हज्या धन्याकडेन पावतलों.'" },
    { type: "verse", num: 15, text: "आनी एसावान म्हणलें, 'म्हजेकडेन आशिल्ले कांय लोक तुजेकडेन दवरूं.' आनी ताणें म्हणलें, 'कित्याक? म्हज्या धन्याच्या दोळ्यांत म्हाका कुर्पा मेळ्ळ्या.'" },
    { type: "verse", num: 16, text: "अशें त्या दिसा एसाव सेईराक आपल्या वाटेन परतलो." },
    { type: "verse", num: 17, text: "आनी याकोब सुक्कोताक गेलो, आनी आपल्याक घर बांदलें, आनी आपल्या गोरवांक छपऱ्यो केल्यो; देखून त्या जाग्याचें नांव सुक्कोत दवरलें." },
    { type: "verse", num: 18, text: "आनी याकोब पद्दन-अरामांतल्यान येतना कनान देसांतल्या शेकेम शारांत सुखरूप पावलो; आनी शारामुखार छावणी केली." },
    { type: "verse", num: 19, text: "आनी ज्या शेतांत ताणें आपलो तंबू लायिल्लो, तें शेत शेकेमाच्या बापाय हमोराच्या पुतांकडल्यान शंबर रुपयांक विकत घेतलें." },
    { type: "verse", num: 20, text: "आनी थंय एक वेदी उबारली आनी तिका एल-एलोहे-इस्राएल म्हूण नांव दवरलें." },
  ],
  "34": [
    { type: "section", text: "दीनाचेर अत्याचार" },
    { type: "verse", num: 1, text: "आनी लेआन याकोबाक जल्मयिल्ली धूव दीना त्या देसांतल्या बायलांक पळोवपाक भायर गेली." },
    { type: "verse", num: 2, text: "आनी हिव्वी हमोराचो पूत शेकेम, जो त्या देसाचो अधिपती आसलो, ताणें तिका पळयली, आनी तिका धरली, आनी तिचेकडेन निदलो आनी तिचें अपमान केलें." },
    { type: "verse", num: 3, text: "आनी ताचो जीव याकोबाच्या धुवे दीनाक चिकटलो, आनी ताणें चलयेक मोगान उतरां उलयलीं." },
    { type: "verse", num: 4, text: "आनी शेकेमान आपल्या बापाय हमोराक म्हणलें, 'ही चली म्हाका बायल करून दी.'" },
    { type: "verse", num: 5, text: "आनी याकोबान आयकलें ताणें ताची धूव दीना बिगडायल्या; आनी ताचे पूत शेतांत ताच्या गोरवांकडेन आसले; आनी ते येमेरेन याकोब वोगी रावलो." },
    { type: "verse", num: 6, text: "आनी शेकेमाचो बापय हमोर याकोबाकडेन ताचेकडेन उलोवपाक भायर गेलो." },
    { type: "verse", num: 7, text: "आनी याकोबाचे पूत शेतांतल्यान आयकून आयले; आनी ते मनीस दुख्खी जाले आनी खूब रागावले, कारण ताणें याकोबाच्या धुवेकडेन निदून इस्राएलांत मूर्खपण केल्लें; अशें करूंक नासलें." },
    { type: "verse", num: 8, text: "आनी हमोरान तांकां सांगलें, 'म्हज्या पुताच्या शेकेमाच्या जिवाक तुमच्या धुवेची ओड लागल्या; ती ताका बायल करून दियात.'" },
    { type: "verse", num: 9, text: "'आनी आमचेकडेन लग्नां करात; तुमच्यो धुवो आमकां दियात, आनी आमच्यो धुवो तुमी घेयात.'" },
    { type: "verse", num: 10, text: "'आनी आमचेकडेन रावात; देस तुमचेमुखार आसा; ताचेंत रावात आनी वेपार करात आनी ताचेंत जमीन घेयात.'" },
    { type: "verse", num: 11, text: "आनी शेकेमान तिच्या बापायक आनी तिच्या भावांक म्हणलें, 'तुमच्या दोळ्यांत म्हाका कुर्पा मेळूंदी, आनी तुमी म्हाका सांगतात तें हांव दितलों.'" },
    { type: "verse", num: 12, text: "'म्हजेर खूब व्हड हुंडो आनी दान घालात, आनी तुमी म्हाका सांगतात तें हांव दितलों; पूण चली म्हाका बायल करून दियात.'" },
    { type: "verse", num: 13, text: "आनी याकोबाच्या पुतांनी शेकेमाक आनी ताच्या बापाय हमोराक कपटान जाप दिली, कारण ताणें तांची भयण दीना बिगडायिल्ली." },
    { type: "verse", num: 14, text: "आनी तांणीं तांकां म्हणलें, 'अशें करपाक आमकां जायना, सुनत नाशिल्ल्या मनशाक आमची भयण दिवपाक; कारण तें आमकां अपमानाचें.'" },
    { type: "verse", num: 15, text: "'पूण ह्या अटीचेर आमी तुमकां मानतले: तुमचे सगळे दादले सुनत जाल्यार, आमच्यासारके जातात जाल्यार.'" },
    { type: "verse", num: 16, text: "'तेन्ना आमी आमच्यो धुवो तुमकां दितले, आनी तुमच्यो धुवो आमी घेतले, आनी आमी तुमचेकडेन रावतले, आनी आमी एक लोक जातले.'" },
    { type: "verse", num: 17, text: "'पूण तुमी आमचें आयकिनात जाल्यार, सुनत करपाक, तेन्ना आमी आमची धूव घेवन वतले.'" },
    { type: "verse", num: 18, text: "आनी तांचीं उतरां हमोराक आनी हमोराच्या पुता शेकेमाक बरीं दिसलीं." },
    { type: "verse", num: 19, text: "आनी तरणाट्यान ती गजाल करपाक उसार केलें ना, कारण ताका याकोबाच्या धुवेचेर मोग आसलो; आनी तो आपल्या बापायच्या घरांत सगळ्यांत मानाचो आसलो." },
    { type: "verse", num: 20, text: "आनी हमोर आनी ताचो पूत शेकेम तांच्या शाराच्या दारांत आयले, आनी तांच्या शाराच्या मनशांक उलयले:" },
    { type: "verse", num: 21, text: "'हे मनीस आमचेकडेन शांतीन आसात; तांकां देसांत रावंदीत आनी वेपार करूंदीत; कारण देस तांचे खातीर पुरो व्हड आसा; तांच्यो धुवो आमी बायलांक घेवया, आनी आमच्यो धुवो तांकां दिवया.'" },
    { type: "verse", num: 22, text: "'पूण एकाच अटीचेर ते मनीस आमचेकडेन रावपाक तयार आसात, आमी एक लोक जावपाक: आमचे सगळे दादले सुनत जावंक जाय, तांचेसारके.'" },
    { type: "verse", num: 23, text: "'तांचीं गोरवां आनी संपत्ती आनी सगळीं जनावरां आमचीं जावचीं ना? फकत तांकां मानूया, आनी ते आमचेकडेन रावतले.'" },
    { type: "verse", num: 24, text: "आनी शाराच्या दारांतल्यान भायर वचपी सगळ्यांनी हमोराचें आनी ताच्या पुता शेकेमाचें आयकलें; आनी शाराच्या दारांतल्यान भायर वचपी सगळे दादले सुनत जाले." },
    { type: "verse", num: 25, text: "आनी तिसऱ्या दिसा, ते दुखतात तेन्ना, याकोबाच्या दोन पुतांनी, शिमोन आनी लेवीन, दीनाच्या भावांनी, दरेकल्यान आपली तरवार घेतली, आनी धिटायेन शारांत गेले, आनी सगळे दादले मारले." },
    { type: "verse", num: 26, text: "आनी हमोराक आनी ताच्या पुता शेकेमाक तरवारीन मारले, आनी शेकेमाच्या घरांतल्यान दीनाक घेतली, आनी गेले." },
    { type: "verse", num: 27, text: "याकोबाचे पूत मेल्ल्यांचेर आयले, आनी शार लुटलें, कारण तांणीं तांची भयण बिगडायिल्ली." },
    { type: "verse", num: 28, text: "तांचीं मेंढरां, गोरवां, गाडवां, शारांतलें आनी शेतांतलें तांणीं घेतलें." },
    { type: "verse", num: 29, text: "आनी तांची सगळी संपत्ती, आनी तांचीं सगळीं भुरगीं, आनी तांच्यो बायलो बंदी केल्यो, आनी घरांत जें कितें आसलें तें सगळें लुटलें." },
    { type: "verse", num: 30, text: "आनी याकोबान शिमोन आनी लेवीक म्हणलें, 'तुमी म्हाका संकश्टांत घाला, म्हाका ह्या देसांतल्या लोकांमदीं, कनानी आनी परिज्जी हांचेमदीं, घाणीत करून; आनी हांव थोड्या मनशांचो आसां, आनी ते म्हजेआड एकठांय जातले आनी म्हाका मारतले; आनी म्हजो आनी म्हज्या घराचो नाश जातलो.'" },
    { type: "verse", num: 31, text: "आनी तांणीं म्हणलें, 'ताणें आमच्या भयणीक वेश्येसारकी करचीय आसली?'" },
  ],
  "35": [
    { type: "section", text: "याकोब बेथेलाक परतलो" },
    { type: "verse", num: 1, text: "आनी देवान याकोबाक म्हणलें, 'उठ, बेथेलाक वच, आनी थंय राव; आनी थंय देवाक वेदी बांद, जो तूं तुज्या भावा एसावामुखार पळटालो तेन्ना तुका दिसिल्लो.'" },
    { type: "verse", num: 2, text: "तेन्ना याकोबान आपल्या घरच्यांक आनी आपणेकडेन आशिल्ल्या सगळ्यांक म्हणलें, 'तुमचेमदीं आशिल्ले परके देव काडून उडयात, आनी शुद्ध जायात, आनी तुमचीं वस्त्रां बदलात.'" },
    { type: "verse", num: 3, text: "'आनी आमी उठून बेथेलाक वचूया; आनी थंय हांव देवाक वेदी बांदतलों, जो म्हज्या संकश्टाच्या दिसा म्हाका आयकलो, आनी हांव गेल्ल्या वाटेर म्हजेकडेन आसलो.'" },
    { type: "verse", num: 4, text: "आनी तांणीं तांचेकडेन आशिल्ले सगळे परके देव आनी तांच्या कानांतलीं कानफुलां याकोबाक दिलीं; आनी याकोबान तीं शेकेमालागीं आशिल्ल्या एका ओकाच्या झाडापंदा पुरलीं." },
    { type: "verse", num: 5, text: "आनी ते वाटेक लागले; आनी भोंवतणच्या शारांचेर देवाची भिरांत पडली, आनी तांणीं याकोबाच्या पुतांफाटल्यान लागलें ना." },
    { type: "verse", num: 6, text: "अशें याकोब कनान देसांतल्या लूजाक, म्हणल्यार बेथेलाक, पावलो, तो आनी ताचेकडेन आशिल्ले सगळे लोक." },
    { type: "verse", num: 7, text: "आनी ताणें थंय एक वेदी बांदली, आनी त्या जाग्याक एल-बेथेल म्हणलें; कारण तो आपल्या भावामुखार पळटालो तेन्ना देव ताका थंय दिसिल्लो." },
    { type: "verse", num: 8, text: "आनी रिबकाची दाई दबोरा मेली, आनी तिका बेथेलसकयल एका ओकाच्या झाडापंदा पुरली; आनी ताचें नांव अल्लोन-बाकूत दवरलें." },
    { type: "verse", num: 9, text: "आनी याकोब पद्दन-अरामांतल्यान आयलो तेन्ना देव ताका परत दिसलो, आनी ताका आशीर्वाद दिलो." },
    { type: "verse", num: 10, text: "आनी देवान ताका म्हणलें, 'तुजें नांव याकोब; तुजें नांव आनीक याकोब म्हणचें ना, पूण तुजें नांव इस्राएल आसतलें.' आनी ताणें ताचें नांव इस्राएल दवरलें." },
    { type: "verse", num: 11, text: "आनी देवान ताका म्हणलें, 'हांव सर्वशक्तिमान देव; फळां दी आनी वाड; एक राश्ट्र आनी राश्ट्रांचो समुदाय तुजेपसून जातलो, आनी राजा तुज्या कुशींतल्यान येतले.'" },
    { type: "verse", num: 12, text: "'आनी अब्राहाम आनी इसाकाक दिल्लो देस हांव तुका दितलों, आनी तुज्या उपरांत तुज्या संततीक तो देस दितलों.'" },
    { type: "verse", num: 13, text: "आनी ज्या जाग्यार ताणें ताचेकडेन उलयिल्लें, त्या जाग्यापसून देव वयर गेलो." },
    { type: "verse", num: 14, text: "आनी याकोबान ज्या जाग्यार ताणें ताचेकडेन उलयिल्लें, त्या जाग्यार एक फातराचो खांबो उबारलो; आनी ताचेर पेय अर्पण ओतलें, आनी ताचेर तेल ओतलें." },
    { type: "verse", num: 15, text: "आनी ज्या जाग्यार देवान ताचेकडेन उलयिल्लें, त्या जाग्याक याकोबान बेथेल म्हणलें." },
    { type: "section", text: "राखेलाचो मरण" },
    { type: "verse", num: 16, text: "आनी ते बेथेलांतल्यान वाटेक लागले; आनी एफ्राताक पावपाक अजून थोडी वाट आसताना राखेलाक प्रसूत जालें, आनी तिका खूब कठीण प्रसूत जालें." },
    { type: "verse", num: 17, text: "आनी प्रसूत कठीण जाताना, सुयणेन तिका म्हणलें, 'भियेंव नाका; कारण हो तुका अजून एक पूत.'" },
    { type: "verse", num: 18, text: "आनी तिचो प्राण वतालो — कारण ती मरताली — तिणें ताचें नांव बेन-ओनी दवरलें; पूण ताच्या बापायन ताका बिन्यामीन म्हणलें." },
    { type: "verse", num: 19, text: "आनी राखेल मेली, आनी एफ्राताच्या, म्हणल्यार बेथलेहेमाच्या वाटेर तिका पुरली." },
    { type: "verse", num: 20, text: "आनी याकोबान तिच्या थडग्याचेर एक खांबो उबारलो; तो राखेलाच्या थडग्याचो खांबो आज मेरेन आसा." },
    { type: "verse", num: 21, text: "आनी इस्राएल वाटेक लागलो आनी मिग्दल-एदेर पलतडीं आपलो तंबू लायलो." },
    { type: "verse", num: 22, text: "आनी इस्राएल त्या देसांत रावतालो तेन्ना, रऊबेन ताच्या बापायच्या उपपत्नी बिल्हाकडेन निदलो; आनी इस्राएलान तें आयकलें. याकोबाचे बारा पूत आसले:" },
    { type: "verse", num: 23, text: "लेआचे पूत: याकोबाचो ज्येश्ट पूत रऊबेन, आनी शिमोन, लेवी, यहूदा, इस्साखार आनी जबुलोन." },
    { type: "verse", num: 24, text: "राखेलाचे पूत: योसेफ आनी बिन्यामीन." },
    { type: "verse", num: 25, text: "आनी राखेलाच्या चाकर्णीच्या बिल्हाचे पूत: दान आनी नफ्ताली." },
    { type: "verse", num: 26, text: "आनी लेआच्या चाकर्णीच्या जिल्पाचे पूत: गाद आनी आशेर. हे याकोबाचे पूत, जे ताका पद्दन-अरामांत जल्मले." },
    { type: "verse", num: 27, text: "आनी याकोब आपल्या बापाय इसाकाकडेन मम्रेंत, किर्यथ-अर्बाक, म्हणल्यार हेब्रोनाक पावलो, जंय अब्राहाम आनी इसाक परदेशी जावन रावले." },
    { type: "verse", num: 28, text: "आनी इसाकाचीं दिसां एकशें ऐंशीं वर्सां जालीं." },
    { type: "verse", num: 29, text: "आनी इसाक प्राण सोडून मेलो, आनी आपल्या लोकांक मेळ्ळो, म्हातारो आनी भरिल्ल्या दिसांचो; आनी ताच्या पुतांनी एसाव आनी याकोबान ताका पुरलो." },
  ],
  "36": [
    { type: "section", text: "एसावाची वंशावळ" },
    { type: "verse", num: 1, text: "एसावाची, म्हणल्यार एदोमाची वंशावळ अशी." },
    { type: "verse", num: 2, text: "एसावान कनानी बायलां घेतल्यो: हित्ती एलोनाची धूव आदा, आनी हिव्वी सिबोनाची धूव अना हिची धूव ओहोलीबामा," },
    { type: "verse", num: 3, text: "आनी इश्माएलाची धूव बासमत, नबायोताची भयण." },
    { type: "verse", num: 4, text: "आनी आदान एसावाक एलीफज जल्मयलो; आनी बासमतान रगुएल जल्मयलो." },
    { type: "verse", num: 5, text: "आनी ओहोलीबामान यऊश, यालाम आनी कोरह जल्मयले. हे एसावाचे पूत, जे ताका कनान देसांत जल्मले." },
    { type: "verse", num: 6, text: "आनी एसावान आपल्यो बायलो, पूत, धुवो, आनी ताच्या घरांतले सगळे जीव, आनी आपलीं गोरवां, आनी आपलीं सगळीं जनावरां, आनी कनान देसांत ताणें जोडिल्ली सगळी संपत्ती घेतली, आनी आपल्या भावा याकोबामुखार दुसऱ्या देसांत गेलो." },
    { type: "verse", num: 7, text: "कारण तांची संपत्ती इतली आसली की ते एकठांय रावंक शकनासले; आनी तांच्या गोरवांक लागून तांचो परदेशी वसतीचो देस तांकां पुरो जालो ना." },
    { type: "verse", num: 8, text: "अशें एसाव सेईर दोंगराचेर रावलो; एसाव म्हणल्यार एदोम." },
    { type: "verse", num: 9, text: "आनी सेईर दोंगराचेर एदोमी एसावाची वंशावळ अशी." },
    { type: "verse", num: 10, text: "एसावाच्या पुतांचीं नांवां हीं: एसावाच्या बायलेच्या आदाचो पूत एलीफज, एसावाच्या बायलेच्या बासमताचो पूत रगुएल." },
    { type: "verse", num: 11, text: "आनी एलीफजाचे पूत: तेमान, ओमार, सफो, गाताम आनी कनज." },
    { type: "verse", num: 12, text: "आनी तिम्ना एसावाच्या पुता एलीफजाची उपपत्नी आसली; आनी तिणें एलीफजाक अमालेक जल्मयलो. हे एसावाच्या बायलेच्या आदाचे पूत." },
    { type: "verse", num: 13, text: "आनी रगुएलाचे पूत हे: नहत, जेरह, शम्मा आनी मिज्जा. हे एसावाच्या बायलेच्या बासमताचे पूत." },
    { type: "verse", num: 14, text: "आनी सिबोनाची धूव अना हिची धूव एसावाची बायल ओहोलीबामा हिचे पूत हे: तिणें एसावाक यऊश, यालाम आनी कोरह जल्मयले." },
    { type: "verse", num: 15, text: "एसावाच्या पुतांचे मुखेली हे: एसावाचो ज्येश्ट पूत एलीफजाचे पूत: मुखेली तेमान, मुखेली ओमार, मुखेली सफो, मुखेली कनज," },
    { type: "verse", num: 16, text: "मुखेली कोरह, मुखेली गाताम, मुखेली अमालेक. हे एदोम देसांत एलीफजाचे मुखेली; हे आदाचे पूत." },
    { type: "verse", num: 17, text: "आनी एसावाचो पूत रगुएलाचे पूत हे: मुखेली नहत, मुखेली जेरह, मुखेली शम्मा, मुखेली मिज्जा. हे एदोम देसांत रगुएलाचे मुखेली; हे एसावाच्या बायलेच्या बासमताचे पूत." },
    { type: "verse", num: 18, text: "आनी एसावाच्या बायलेच्या ओहोलीबामाचे पूत हे: मुखेली यऊश, मुखेली यालाम, मुखेली कोरह. हे अनाची धूव एसावाची बायल ओहोलीबामा हिचे मुखेली." },
    { type: "verse", num: 19, text: "हे एसावाचे, म्हणल्यार एदोमाचे पूत, आनी हे तांचे मुखेली." },
    { type: "verse", num: 20, text: "त्या देसांत रावपी होरी सेईराचे पूत हे: लोतान, शोबाल, सिबोन, अना," },
    { type: "verse", num: 21, text: "दिशोन, एसेर आनी दिशान. हे सेईराचे पूत, एदोम देसांत होरी मुखेली." },
    { type: "verse", num: 22, text: "आनी लोतानाचे पूत होरी आनी हेमाम; आनी लोतानाची भयण तिम्ना." },
    { type: "verse", num: 23, text: "आनी शोबालाचे पूत हे: अल्वान, मानहत, एबाल, शफो आनी ओनाम." },
    { type: "verse", num: 24, text: "आनी सिबोनाचे पूत हे: अय्या आनी अना; हो तो अना जाका रानांत आपल्या बापाय सिबोनाच्या गाडवांक चरयतना गरम उदकाचे झरे मेळ्ळे." },
    { type: "verse", num: 25, text: "आनी अनाचीं भुरगीं हीं: दिशोन आनी अनाची धूव ओहोलीबामा." },
    { type: "verse", num: 26, text: "आनी दिशोनाचे पूत हे: हेमदान, एशबान, यित्रान आनी करान." },
    { type: "verse", num: 27, text: "एसेराचे पूत हे: बिल्हान, जावान आनी आकान." },
    { type: "verse", num: 28, text: "दिशानाचे पूत हे: ऊस आनी अरान." },
    { type: "verse", num: 29, text: "होरी मुखेली हे: मुखेली लोतान, मुखेली शोबाल, मुखेली सिबोन, मुखेली अना," },
    { type: "verse", num: 30, text: "मुखेली दिशोन, मुखेली एसेर, मुखेली दिशान. हे सेईर देसांत तांच्या मुखेलींप्रमाणें होरी मुखेली." },
    { type: "verse", num: 31, text: "आनी इस्राएलाच्या पुतांचेर कोणूय राजा राज करपापयलीं एदोम देसांत राज केल्ले राजा हे:" },
    { type: "verse", num: 32, text: "बओराचो पूत बेला एदोमांत राज करतालो; आनी ताच्या शाराचें नांव दिन्हाबा." },
    { type: "verse", num: 33, text: "आनी बेला मेलो, आनी बोज्राचो जेरह पुत योबाब ताचे सुवातेर राज करपाक लागलो." },
    { type: "verse", num: 34, text: "आनी योबाब मेलो, आनी तेमानी देसांतलो हूशाम ताचे सुवातेर राज करपाक लागलो." },
    { type: "verse", num: 35, text: "आनी हूशाम मेलो, आनी बदादाचो पूत हदद, जाणें मोआबाच्या शेतांत मिद्यानाक मारलें, तो ताचे सुवातेर राज करपाक लागलो; आनी ताच्या शाराचें नांव अवीत." },
    { type: "verse", num: 36, text: "आनी हदद मेलो, आनी मस्रेकांतलो सम्ला ताचे सुवातेर राज करपाक लागलो." },
    { type: "verse", num: 37, text: "आनी सम्ला मेलो, आनी न्हंयेवयलो रहोबोतांतलो शाऊल ताचे सुवातेर राज करपाक लागलो." },
    { type: "verse", num: 38, text: "आनी शाऊल मेलो, आनी अक्बोराचो पूत बाल-हानान ताचे सुवातेर राज करपाक लागलो." },
    { type: "verse", num: 39, text: "आनी अक्बोराचो पूत बाल-हानान मेलो, आनी हदर ताचे सुवातेर राज करपाक लागलो; आनी ताच्या शाराचें नांव पाऊ; आनी ताच्या बायलेचें नांव महेतबेल, ती मेजाहाबाची धूव मत्रेदाची धूव." },
    { type: "verse", num: 40, text: "आनी तांच्या कुळांप्रमाणें, तांच्या जाग्यांप्रमाणें, तांच्या नांवांप्रमाणें एसावाच्या मुखेलींचीं नांवां हीं: मुखेली तिम्ना, मुखेली अल्वा, मुखेली यतेत," },
    { type: "verse", num: 41, text: "मुखेली ओहोलीबामा, मुखेली एला, मुखेली पीनोन," },
    { type: "verse", num: 42, text: "मुखेली कनज, मुखेली तेमान, मुखेली मिब्सार," },
    { type: "verse", num: 43, text: "मुखेली मग्दीएल, मुखेली ईराम. तांच्या वसतीच्या देसांत तांच्या जाग्यांप्रमाणें हे एदोमाचे मुखेली. हो एदोमींचो बापय एसाव." },
  ],
  "37": [
    { type: "section", text: "योसेफाचीं सपनां" },
    { type: "verse", num: 1, text: "आनी याकोब कनान देसांत, आपल्या बापायच्या परदेशी वसतीच्या देसांत रावलो." },
    { type: "verse", num: 2, text: "याकोबाच्या वंशाची गजाल अशी. योसेफ सतरा वर्सांचो आसताना, आपल्या भावांकडेन मेंढरां चरयतालो; आनी तो तरणाटो आपल्या बापायच्या बायलांच्या बिल्हा आनी जिल्पा हांच्या पुतांकडेन आसतालो; आनी योसेफान तांची वायट खबर आपल्या बापायक सांगली." },
    { type: "verse", num: 3, text: "आनी इस्राएलाक योसेफाचेर सगळ्या पुतांपरस चड मोग आसलो, कारण तो ताच्या म्हातारपणाचो पूत; आनी ताणें ताका रंगीबेरंगी अंगरखो केलो." },
    { type: "verse", num: 4, text: "आनी ताच्या भावांनी पळयलें तांचो बापय ताचेर सगळ्यांपरस चड मोग करता, तेन्ना ते ताचो द्वेश करपाक लागले, आनी ताचेकडेन शांतीन उलोवपाक शकले नात." },
    { type: "verse", num: 5, text: "आनी योसेफान एक सपन पळयलें, आनी ताणें तें आपल्या भावांक सांगलें; आनी ते ताचो अजून चड द्वेश करपाक लागले." },
    { type: "verse", num: 6, text: "आनी ताणें तांकां म्हणलें, 'हें सपन हांवें पळयलें तें आयकात:'" },
    { type: "verse", num: 7, text: "'पळय, आमी शेतांत पेंडे बांदतालीं; आनी पळय, म्हजो पेंडो उठलो आनी उबो रावलो; आनी पळय, तुमचे पेंडे भोंवतणीं येवन म्हज्या पेंड्याक नमन केलें.'" },
    { type: "verse", num: 8, text: "आनी ताच्या भावांनी ताका म्हणलें, 'तूं खरेंच आमचेर राज करतलो? तूं खरेंच आमचेर सत्ता गाजयतलो?' आनी ताच्या सपनांक लागून आनी ताच्या उतरांक लागून ते ताचो अजून चड द्वेश करपाक लागले." },
    { type: "verse", num: 9, text: "आनी ताणें अजून एक सपन पळयलें, आनी आपल्या भावांक सांगलें, आनी म्हणलें, 'पळय, हांवें अजून एक सपन पळयलें; आनी पळय, सूर्य आनी चंद्र आनी इकरा नखेत्रांनी म्हाका नमन केलें.'" },
    { type: "verse", num: 10, text: "आनी ताणें आपल्या बापायक आनी आपल्या भावांक सांगलें; आनी ताच्या बापायन ताका रागावलो आनी म्हणलें, 'तूं कसलें सपन पळयलां? हांव आनी तुजी आवय आनी तुजे भाव खरेंच तुजेमुखार भुंयेमेरेन नमन करपाक येतले?'" },
    { type: "verse", num: 11, text: "आनी ताचे भाव ताचो मत्सर करताले; पूण ताच्या बापायन ती गजाल मनांत दवरली." },
    { type: "section", text: "योसेफाक विकलो" },
    { type: "verse", num: 12, text: "आनी ताचे भाव शेकेमांत आपल्या बापायचीं मेंढरां चरोवपाक गेले." },
    { type: "verse", num: 13, text: "आनी इस्राएलान योसेफाक म्हणलें, 'तुजे भाव शेकेमांत मेंढरां चरयतात ना? यो, हांव तुका तांचेकडेन धाडतलों.' आनी ताणें म्हणलें, 'हांव तयार आसां.'" },
    { type: "verse", num: 14, text: "आनी ताणें ताका म्हणलें, 'वच, तुजे भाव बरे आसात आनी मेंढरां बरीं आसात काय पळय, आनी म्हाका खबर हाड.' आनी ताणें ताका हेब्रोनाच्या दऱ्यांतल्यान धाडलो; आनी तो शेकेमाक पावलो." },
    { type: "verse", num: 15, text: "आनी एका मनशान ताका शेतांत भोंवतना मेळयलो; आनी त्या मनशान ताका विचारलें, 'तूं कितें सोदता?'" },
    { type: "verse", num: 16, text: "आनी ताणें म्हणलें, 'हांव म्हज्या भावांक सोदतां; म्हाका सांग, ते खंय मेंढरां चरयतात.'" },
    { type: "verse", num: 17, text: "आनी त्या मनशान म्हणलें, 'ते हांगासून गेले; कारण हांवें तांकां म्हणताना आयकलें, आमी दोथानाक वचूया.' आनी योसेफ आपल्या भावांफाटल्यान गेलो आनी तांकां दोथानांत मेळयलें." },
    { type: "verse", num: 18, text: "आनी ते पयसूल्यान ताका पळोवपापयलीं, तो तांचेलागीं पावपापयलीं, ताका मारपाचो कट केलो." },
    { type: "verse", num: 19, text: "आनी तांणीं एकामेकांक म्हणलें, 'पळय, हो सपनकार येता.'" },
    { type: "verse", num: 20, text: "'चलात, ताका मारूया आनी एका खड्ड्यांत उडोवया; आनी सांगूया, एका रानवटी जनावरान ताका खालो; आनी ताचीं सपनां कितें जातात तें पळोवया.'" },
    { type: "verse", num: 21, text: "आनी रऊबेनान तें आयकलें, आनी ताका तांच्या हातांतल्यान सोडयलो; आनी म्हणलें, 'ताचो जीव घेवंका नाका.'" },
    { type: "verse", num: 22, text: "आनी रऊबेनान तांकां म्हणलें, 'रगत व्हारिनाकात; ह्या खड्ड्यांत ताका उडयात जो रानांत आसा, पूण ताचेर हात घालिनाकात'; ताका तांच्या हातांतल्यान सोडोवन आपल्या बापायकडेन परत हाडपाक." },
    { type: "verse", num: 23, text: "आनी योसेफ आपल्या भावांकडेन पावलो तेन्ना, तांणीं ताचो अंगरखो, रंगीबेरंगी अंगरखो जो ताणें घातिल्लो, तो काडलो." },
    { type: "verse", num: 24, text: "आनी ताका धरलो आनी खड्ड्यांत उडयलो; आनी खड्डो रितो आसलो, ताचेंत उदक नासलें." },
    { type: "verse", num: 25, text: "आनी ते जेवपाक बसले; आनी तांणीं दोळे उकलून पळयलें, आनी पळय, इश्माएली कारवान गिलआदांतल्यान येतालो, तांच्या उंटांचेर मसाले आनी बाम आनी गंधरस, तें ईजिप्ताक व्हरपाक." },
    { type: "verse", num: 26, text: "आनी यहूदान आपल्या भावांक म्हणलें, 'आमी आमच्या भावाक मारून ताचें रगत लिपयल्यार कसलो फायदो?'" },
    { type: "verse", num: 27, text: "'चलात, ताका इश्माएलींक विकूया, आनी आमचे हात ताचेर आसूंक फावना; कारण तो आमचो भाव आनी आमचें मांस.' आनी ताच्या भावांनी आयकलें." },
    { type: "verse", num: 28, text: "आनी मिद्यानी वेपारी तांचेसरशीं गेले तेन्ना, तांणीं योसेफाक खड्ड्यांतल्यान वयर ओडून काडलो, आनी वीस रुपयांक इश्माएलींक विकलो; आनी ते योसेफाक ईजिप्ताक व्हरून गेले." },
    { type: "verse", num: 29, text: "आनी रऊबेन खड्ड्याकडेन परतलो; आनी पळय, योसेफ खड्ड्यांत नासलो; आनी ताणें आपलीं वस्त्रां फाडलीं." },
    { type: "verse", num: 30, text: "आनी तो आपल्या भावांकडेन परतलो आनी म्हणलें, 'भुरगो ना; आनी हांव खंय वचूं?'" },
    { type: "verse", num: 31, text: "आनी तांणीं योसेफाचो अंगरखो घेतलो, आनी एक बोकडो मारून, अंगरखो रगतांत बुडयलो." },
    { type: "verse", num: 32, text: "आनी रंगीबेरंगी अंगरखो आपल्या बापायक धाडलो, आनी म्हणलें, 'हो आमकां मेळ्ळो; पळय, हो तुज्या पुताचो अंगरखो काय ना?'" },
    { type: "verse", num: 33, text: "आनी ताणें ताका वळखलो आनी म्हणलें, 'म्हज्या पुताचो अंगरखो; रानवटी जनावरान ताका खालो; योसेफाक खात्रीन फाडून उडयलो.'" },
    { type: "verse", num: 34, text: "आनी याकोबान आपलीं वस्त्रां फाडलीं, आनी आपल्या कमरेर तांतड बांदलो, आनी आपल्या पुताक लागून जायते दीस शोक केलो." },
    { type: "verse", num: 35, text: "आनी ताचे सगळे पूत आनी सगळ्यो धुवो ताका भुजोवपाक आयलीं; पूण ताणें भुजावणी घेवपाक न्हय केलें; आनी म्हणलें, 'हांव शोक करीत म्हज्या पुताकडेन थडग्यांत देंवतलों.' अशें ताचो बापय ताका लागून रडलो." },
    { type: "verse", num: 36, text: "आनी मिद्यानींनी ताका ईजिप्तांत, फारोच्या अधिकारी पोतीफाराक, राखणदारांच्या सरदाराक विकलो." },
  ],
  "38": [
    { type: "section", text: "यहूदा आनी तामार" },
    { type: "verse", num: 1, text: "आनी त्या वेळार यहूदा आपल्या भावांकडल्यान देंवलो, आनी अदुल्लामी हीरा नांवाच्या एका मनशाकडेन गेलो." },
    { type: "verse", num: 2, text: "आनी यहूदान थंय शूआ नांवाच्या कनानी मनशाची धूव पळयली; आनी तिका घेतली, आनी तिचेकडेन गेलो." },
    { type: "verse", num: 3, text: "आनी ती गुरवार जाली आनी तिणें एक पूत जल्मयलो; आनी ताणें ताचें नांव एर दवरलें." },
    { type: "verse", num: 4, text: "आनी ती परत गुरवार जाली आनी पूत जल्मयलो; आनी ताणें ताचें नांव ओनान दवरलें." },
    { type: "verse", num: 5, text: "आनी तिणें अजून एक पूत जल्मयलो; आनी ताचें नांव शेला दवरलें. तो जल्मलो तेन्ना तो कजीबांत आसलो." },
    { type: "verse", num: 6, text: "आनी यहूदान आपल्या ज्येश्ट पुता एराक तामार नांवाची बायल घेतली." },
    { type: "verse", num: 7, text: "आनी यहूदाचो ज्येश्ट पूत एर सर्वेस्पराच्या दोळ्यांत वायट आसलो; आनी सर्वेस्परान ताका मारलो." },
    { type: "verse", num: 8, text: "आनी यहूदान ओनानाक म्हणलें, 'तुज्या भावाच्या बायलेकडेन वच, आनी तिका देवर म्हूण लग्न कर, आनी तुज्या भावाक संतत उबी कर.'" },
    { type: "verse", num: 9, text: "आनी ओनानाक कळटालें ती संतत ताची जावची ना; आनी आपल्या भावाच्या बायलेकडेन वतालो तेन्ना, आपल्या भावाक संतत दिवंक नजो म्हूण भुंयेर व्हारतालो." },
    { type: "verse", num: 10, text: "आनी ताणें जें केलें तें सर्वेस्पराच्या दोळ्यांत वायट आसलें; आनी ताणें ताकाय मारलो." },
    { type: "verse", num: 11, text: "तेन्ना यहूदान आपली सुनो तामारीक म्हणलें, 'म्हजो पूत शेला व्हड जाईमेरेन तुज्या बापायच्या घरांत विधवा जावन राव.' कारण ताणें म्हणलें, 'ताच्या भावांसारको तोय मरत.' आनी तामार वचून आपल्या बापायच्या घरांत रावली." },
    { type: "verse", num: 12, text: "जायते दीस जालें उपरांत, शूआची धूव यहूदाची बायल मेली; आनी यहूदान शोक सोपयलो, आनी आपल्या मेंढरांच्या लोंव कातरप्यांकडेन तिम्नाताक वयर गेलो, तो आनी ताचो इश्ट अदुल्लामी हीरा." },
    { type: "verse", num: 13, text: "आनी तामारीक सांगलें, 'पळय, तुजो सासरो मेंढरांची लोंव कातरपाक तिम्नाताक वयर वता.'" },
    { type: "verse", num: 14, text: "आनी तिणें आपल्या विधवापणाचीं वस्त्रां काडलीं, आनी वोडणी ओडून तोंड झाकलें, आनी तिम्नाताच्या वाटेर एनयीमाच्या दारांत बसली; कारण तिणें पळयलें शेला व्हड जालो, आनी तिका ताका बायल करून दिवंक ना." },
    { type: "verse", num: 15, text: "आनी यहूदान तिका पळयली तेन्ना, तिणें तोंड झाकिल्ले खातीर, तिका वेश्या मानली." },
    { type: "verse", num: 16, text: "आनी तो वाटेवयल्यान तिचेकडेन गेलो आनी म्हणलें, 'यो, म्हाका तुजेकडेन येवंदी'; कारण ती ताची सुनो म्हूण ताका कळ्ळें ना. आनी तिणें म्हणलें, 'तूं म्हजेकडेन आयल्यार कितें दितलो?'" },
    { type: "verse", num: 17, text: "आनी ताणें म्हणलें, 'हांव कळपांतल्यान एक बोकडाचें पिलूं धाडतलों.' आनी तिणें म्हणलें, 'तूं धाडमेरेन तारण दितलो?'" },
    { type: "verse", num: 18, text: "आनी ताणें म्हणलें, 'कसलें तारण तुका दिवं?' आनी तिणें म्हणलें, 'तुजी मुद्रा, तुजी दोरी आनी तुज्या हातांतली काठी.' आनी ताणें तिका दिलें, आनी तिचेकडेन गेलो, आनी ती ताचेपसून गुरवार जाली." },
    { type: "verse", num: 19, text: "आनी ती उठून गेली, आनी आपली वोडणी काडली, आनी आपल्या विधवापणाचीं वस्त्रां घातलीं." },
    { type: "verse", num: 20, text: "आनी यहूदान बायलेच्या हातांतल्यान तारण परत घेवपाक आपल्या इश्टा अदुल्लामी हीराच्या हातांतल्यान बोकडाचें पिलूं धाडलें; पूण ताका ती मेळ्ळी ना." },
    { type: "verse", num: 21, text: "तेन्ना ताणें त्या जाग्याच्या मनशांक विचारलें, 'एनयीमांत वाटेवयल्यान आशिल्ली वेश्या खंय आसा?' आनी तांणीं म्हणलें, 'हांगा कसलीच वेश्या नासली.'" },
    { type: "verse", num: 22, text: "आनी तो यहूदाकडेन परतलो आनी म्हणलें, 'ती म्हाका मेळ्ळी ना; आनी त्या जाग्याच्या मनशांनी म्हणलें, हांगा कसलीच वेश्या नासली.'" },
    { type: "verse", num: 23, text: "आनी यहूदान म्हणलें, 'तिका तें आसूंदी, नाजाल्यार आमी हांसपाचे जातले. पळय, हें पिलूं हांवें धाडलें, पूण तुका ती मेळ्ळी ना.'" },
    { type: "verse", num: 24, text: "आनी तीन म्हयन्यांउपरांत यहूदाक सांगलें, 'तुजी सुनो तामार वेश्याकर्म केलां; आनी पळय, ती वेश्याकर्मापसून गुरवार आसा.' आनी यहूदान म्हणलें, 'तिका भायर हाडात, आनी तिका जळयात.'" },
    { type: "verse", num: 25, text: "तिका भायर हाडटाना, तिणें आपल्या सासऱ्याक निरोप धाडलो, 'ज्या मनशाच्यो ह्यो वस्तू, ताचेपसून हांव गुरवार आसां.' आनी म्हणलें, 'ओळख, ही मुद्रा, ही दोरी आनी ही काठी कोणाची तें.'" },
    { type: "verse", num: 26, text: "आनी यहूदान तीं वळखलीं, आनी म्हणलें, 'ती म्हजेपरस न्यायी; कारण हांवें तिका म्हज्या पुता शेलाक दिली ना.' आनी ताणें तिका आनीक वळखलें ना." },
    { type: "verse", num: 27, text: "आनी तिच्या प्रसूतीच्या वेळार, पळय, तिच्या गर्भांत जुळीं आसलीं." },
    { type: "verse", num: 28, text: "आनी प्रसूत जाताना, एकल्यान हात भायर काडलो; आनी सुयणेन ताच्या हाताक एक तांबडो दोरो बांदलो आनी म्हणलें, 'हो पयलो भायर आयलो.'" },
    { type: "verse", num: 29, text: "आनी ताणें आपलो हात परत भितर ओडलो, आनी पळय, ताचो भाव भायर आयलो; आनी तिणें म्हणलें, 'तूं कशें फोडून भायर आयलो?' देखून ताचें नांव पेरेस दवरलें." },
    { type: "verse", num: 30, text: "आनी त्या उपरांत ताचो भाव भायर आयलो, ज्याच्या हाताक तांबडो दोरो आसलो; आनी ताचें नांव जेरह दवरलें." },
  ],
  "39": [
    { type: "section", text: "योसेफ पोतीफाराच्या घरांत" },
    { type: "verse", num: 1, text: "आनी योसेफाक ईजिप्ताक व्हरून गेले; आनी फारोचो अधिकारी, राखणदारांचो सरदार पोतीफार, एक ईजिप्ती मनशान, ताका थंय व्हरिल्ल्या इश्माएलींकडल्यान विकत घेतलो." },
    { type: "verse", num: 2, text: "आनी सर्वेस्पर योसेफाकडेन आसलो, आनी तो भाग्यवान मनीस जालो; आनी तो आपल्या ईजिप्ती धन्याच्या घरांत आसलो." },
    { type: "verse", num: 3, text: "आनी ताच्या धन्यान पळयलें सर्वेस्पर ताचेकडेन आसा, आनी तो कितेंय करता तें सगळें सर्वेस्पर ताच्या हातांत यशस्वी करता." },
    { type: "verse", num: 4, text: "आनी योसेफाक ताच्या दोळ्यांत कुर्पा मेळ्ळी, आनी ताणें ताची सेवा केली; आनी ताणें ताका आपल्या घरावयलो मुखेली केलो, आनी ताचेकडेन जें कितें आसलें तें सगळें ताच्या हातांत दवरलें." },
    { type: "verse", num: 5, text: "आनी ताणें ताका आपल्या घरावयलो आनी ताचेकडेन जें कितें आसलें ताचेवयलो मुखेली केल्लो त्या वेळासावन, सर्वेस्परान ईजिप्ती मनशाच्या घराक योसेफाक लागून आशीर्वाद दिलो; आनी सर्वेस्पराचो आशीर्वाद ताचेकडेन जें कितें आसलें ताचेर, घरांत आनी शेतांत आसलो." },
    { type: "verse", num: 6, text: "आनी ताणें ताचेकडेन जें कितें आसलें तें सगळें योसेफाच्या हातांत दवरलें; आनी तो खाता ती भाकर सोडून ताका कसल्याच गजालीची चिंता नासली. आनी योसेफ सुंदर रुपाचो आनी सोबीत आसलो." },
    { type: "verse", num: 7, text: "आनी ह्या गजालींउपरांत ताच्या धन्याच्या बायलेन योसेफाचेर दोळो दवरलो, आनी म्हणलें, 'म्हजेकडेन निद.'" },
    { type: "verse", num: 8, text: "पूण ताणें न्हय केलें, आनी आपल्या धन्याच्या बायलेक म्हणलें, 'पळय, म्हजो धनी म्हजेकडेन घरांत कितें आसा तें पळयना, आनी ताचेकडेन जें कितें आसा तें सगळें म्हज्या हातांत दवरलां.'" },
    { type: "verse", num: 9, text: "'ह्या घरांत म्हजेपरस व्हड कोण ना; आनी तूं ताची बायल, तुका सोडून ताणें म्हजेपसून कांयच आडायलें ना; तेन्ना हांव हें व्हड वायटपण कशें करूं आनी देवाआड पातक करूं?'" },
    { type: "verse", num: 10, text: "आनी ती दिसानदीस योसेफाकडेन उलयताली, पूण ताणें तिचें आयकलें ना, तिचेकडेन निदपाक वा तिचेकडेन आसपाक." },
    { type: "verse", num: 11, text: "आनी असो एक दीस ताणें घरांत आपलें काम करपाक भितर गेलो, आनी घरांत भितर कोणूच घरचो मनीस नासलो." },
    { type: "verse", num: 12, text: "आनी तिणें ताचो अंगरखो धरलो, आनी म्हणलें, 'म्हजेकडेन निद.' आनी ताणें आपलो अंगरखो तिच्या हातांत सोडलो, आनी पळून भायर गेलो." },
    { type: "verse", num: 13, text: "आनी तिणें पळयलें ताणें आपलो अंगरखो तिच्या हातांत सोडलो आनी भायर पळालो," },
    { type: "verse", num: 14, text: "तिणें आपल्या घरच्या मनशांक आपयलें, आनी तांकां सांगलें, 'पळयात, ताणें आमकां हेब्री मनीस हाडलो, आमचेकडेन खेळपाक; तो म्हजेकडेन निदपाक भितर आयलो, आनी हांवें व्हडल्यान बोबाटलें.'" },
    { type: "verse", num: 15, text: "'आनी हांवें व्हडल्यान बोबाटलें तें ताणें आयकलें, आनी ताणें आपलो अंगरखो म्हजेकडेन सोडलो, आनी पळून भायर गेलो.'" },
    { type: "verse", num: 16, text: "आनी ताचो धनी घरा येमेरेन तिणें ताचो अंगरखो आपणेलागीं दवरलो." },
    { type: "verse", num: 17, text: "आनी तिणें ताका ह्याच उतरांनी सांगलें, 'तूं आमकां हाडिल्लो हेब्री चाकर म्हजेकडेन खेळपाक भितर आयलो.'" },
    { type: "verse", num: 18, text: "'आनी हांवें व्हडल्यान बोबाटलें तेन्ना, ताणें आपलो अंगरखो म्हजेकडेन सोडलो आनी भायर पळालो.'" },
    { type: "verse", num: 19, text: "आनी ताच्या धन्यान आपल्या बायलेचीं उतरां आयकलीं, जीं ती ताका उलयली, 'तुज्या चाकरान म्हाका अशें केलें'; आनी ताचो राग पेटलो." },
    { type: "verse", num: 20, text: "आनी योसेफाच्या धन्यान ताका धरलो, आनी बंदखणींत, जंय राजाचे बंदी बांदिल्ले आसले, थंय ताका घालो; आनी तो थंय बंदखणींत आसलो." },
    { type: "verse", num: 21, text: "पूण सर्वेस्पर योसेफाकडेन आसलो, आनी ताचेर दया दाखयली, आनी बंदखणीच्या मुखेल्याच्या दोळ्यांत ताका कुर्पा दिली." },
    { type: "verse", num: 22, text: "आनी बंदखणीच्या मुखेल्यान बंदखणींतल्या सगळ्या बंद्यांक योसेफाच्या हातांत दवरलें; आनी थंय जें कितें करताले तें सगळें तोच करतालो." },
    { type: "verse", num: 23, text: "बंदखणीचो मुखेली ताच्या हातांतलें कांयच पळयनासलो, कारण सर्वेस्पर ताचेकडेन आसलो; आनी तो कितेंय करतालो तें सर्वेस्पर यशस्वी करतालो." },
  ],
  "40": [
    { type: "section", text: "योसेफान बंदखणींत सपनांचो अर्थ सांगलो" },
    { type: "verse", num: 1, text: "ह्या गजालींउपरांत, ईजिप्ताच्या राजाचो पेयवालो आनी भाकरवालो आपल्या धन्या ईजिप्ताच्या राजाआड चुकले." },
    { type: "verse", num: 2, text: "आनी फारो आपल्या दोन अधिकाऱ्यांचेर, मुखेल पेयवाल्याचेर आनी मुखेल भाकरवाल्याचेर रागावलो." },
    { type: "verse", num: 3, text: "आनी ताणें तांकां राखणदारांच्या सरदाराच्या घरांत बंदखणींत घालें, जंय योसेफ बंदी आसलो." },
    { type: "verse", num: 4, text: "आनी राखणदारांच्या सरदारान योसेफाक तांचेकडेन नेमलो, आनी ताणें तांची सेवा केली; आनी ते कांय दीस बंदखणींत आसले." },
    { type: "verse", num: 5, text: "आनी दोगांयनीं एकाच राती सपन पळयलें, दरेकल्यान आपलें सपन, आपापल्या अर्थाप्रमाणें, ईजिप्ताच्या राजाचो पेयवालो आनी भाकरवालो, जे बंदखणींत बंदी आसले." },
    { type: "verse", num: 6, text: "आनी योसेफ सकाळीं तांचेकडेन आयलो, आनी तांकां पळयलें, आनी पळय, ते उदास आसले." },
    { type: "verse", num: 7, text: "आनी ताणें फारोच्या अधिकाऱ्यांक, जे ताचेकडेन ताच्या धन्याच्या घरांत बंदखणींत आसले, तांकां विचारलें, 'तुमचीं तोंडां आज कित्याक उदास आसात?'" },
    { type: "verse", num: 8, text: "आनी तांणीं ताका म्हणलें, 'आमी सपन पळयलां, आनी ताचो अर्थ सांगपी कोण ना.' आनी योसेफान तांकां म्हणलें, 'अर्थ सांगप देवाचे ना? म्हाका सांगात.'" },
    { type: "verse", num: 9, text: "आनी मुखेल पेयवाल्यान आपलें सपन योसेफाक सांगलें, आनी ताका म्हणलें, 'म्हज्या सपनांत, पळय, म्हजेमुखार एक द्राक्षवेल आसलो.'" },
    { type: "verse", num: 10, text: "'आनी द्राक्षवेलाक तीन फांदे आसले; आनी तो कोंब फुटिल्लोसारको जालो, ताका फुलां आयलीं, आनी ताच्या घडांनी पिकिल्ले द्राक्ष दिले.'" },
    { type: "verse", num: 11, text: "'आनी फारोचो प्याला म्हज्या हातांत आसलो; आनी हांवें द्राक्ष घेतले आनी फारोच्या प्याल्यांत निचोडले, आनी प्याला फारोच्या हातांत दिलो.'" },
    { type: "verse", num: 12, text: "आनी योसेफान ताका म्हणलें, 'ताचो अर्थ हो: तीन फांदे म्हणल्यार तीन दीस.'" },
    { type: "verse", num: 13, text: "'तीन दिसांभितर फारो तुजें तकलें उकलतलो, आनी तुका तुज्या जाग्यार परत दवरतलो; आनी तूं पयलीं ताचो पेयवालो आसताना करतालो तशें फारोचो प्याला ताच्या हातांत दितलो.'" },
    { type: "verse", num: 14, text: "'पूण तुजें बरें जातलें तेन्ना म्हजो उगडास कर, आनी म्हजेर दया कर, आनी फारोक म्हजी गजाल सांग, आनी म्हाका ह्या घरांतल्यान भायर काड.'" },
    { type: "verse", num: 15, text: "'कारण म्हाका हेब्री लोकांच्या देसांतल्यान चोरून हाडलो; आनी हांगाय हांवें कांयच केल्लें ना, तांणीं म्हाका ह्या खड्ड्यांत घालचें.'" },
    { type: "verse", num: 16, text: "आनी मुखेल भाकरवाल्यान पळयलें अर्थ बरो आसा, तेन्ना योसेफाक म्हणलें, 'हांवूय म्हज्या सपनांत पळयलें; आनी पळय, म्हज्या तकलेर तीन धव्या भाकरेच्यो दालयो आसल्यो.'" },
    { type: "verse", num: 17, text: "'आनी सगळ्यांत वयल्या दालयेंत फारोक लागून सगळे तरेचें भाकरवाल्याचें खाण आसलें; आनी सुकणीं म्हज्या तकलेवयल्या दालयेंतल्यान खाताली.'" },
    { type: "verse", num: 18, text: "आनी योसेफान जाप दिली, 'ताचो अर्थ हो: तीन दालयो म्हणल्यार तीन दीस.'" },
    { type: "verse", num: 19, text: "'तीन दिसांभितर फारो तुजें तकलें तुजेपसून उकलतलो, आनी तुका झाडाक उमकळायतलो; आनी सुकणीं तुजें मांस तुजेवयल्यान खातलीं.'" },
    { type: "verse", num: 20, text: "आनी तिसऱ्या दिसा, फारोचो जल्मदीस आसलो, आनी ताणें आपल्या सगळ्या चाकरांक जेवण दिलें; आनी ताणें मुखेल पेयवाल्याचें आनी मुखेल भाकरवाल्याचें तकलें आपल्या चाकरांमदीं उकललें." },
    { type: "verse", num: 21, text: "आनी ताणें मुखेल पेयवाल्याक ताच्या पेयवाल्याच्या जाग्यार परत दवरलो; आनी ताणें फारोच्या हातांत प्याला दिलो." },
    { type: "verse", num: 22, text: "पूण मुखेल भाकरवाल्याक ताणें उमकळायलो, योसेफान तांकां अर्थ सांगिल्लेप्रमाणें." },
    { type: "verse", num: 23, text: "तरी मुखेल पेयवाल्यान योसेफाचो उगडास केलो ना; ताणें ताका विसरलो." },
  ],
  "41": [
    { type: "section", text: "फारोचीं सपनां" },
    { type: "verse", num: 1, text: "आनी पुराय दोन वर्सां जालीं उपरांत फारोन सपन पळयलें; आनी पळय, तो न्हंयेलागीं उबो आसलो." },
    { type: "verse", num: 2, text: "आनी पळय, न्हंयेंतल्यान सात सोबीत आनी पुश्ट गायो वयर आयल्यो, आनी गवतांत चरपाक लागल्यो." },
    { type: "verse", num: 3, text: "आनी पळय, तांचे फाटल्यान अजून सात गायो न्हंयेंतल्यान वयर आयल्यो, कुरूप आनी सुकिल्ल्यो; आनी त्यो न्हंयेच्या देगेर हेर गायांलागीं उब्यो रावल्यो." },
    { type: "verse", num: 4, text: "आनी कुरूप आनी सुकिल्ल्या गायांनी सात सोबीत आनी पुश्ट गायो खाल्यो. आनी फारो जागो जालो." },
    { type: "verse", num: 5, text: "आनी तो निदलो आनी दुसरे फावट सपन पळयलें; आनी पळय, एका काडयेर सात कणसां, पुश्ट आनी बरीं, उगवलीं." },
    { type: "verse", num: 6, text: "आनी पळय, तांचे उपरांत सात कणसां, सुकिल्लीं आनी उदेंत वाऱ्यान कोमशिल्लीं, उगवलीं." },
    { type: "verse", num: 7, text: "आनी सुकिल्ल्या कणसांनी सात पुश्ट आनी भरिल्लीं कणसां गिळून घेतलीं. आनी फारो जागो जालो; आनी पळय, तें सपन आसलें." },
    { type: "verse", num: 8, text: "आनी सकाळीं ताचो आत्मो अस्वस्थ जालो; आनी ताणें ईजिप्तांतल्या सगळ्या जादूगारांक आनी सगळ्या शाण्या मनशांक आपोवन धाडलें; आनी फारोन तांकां आपलीं सपनां सांगलीं; पूण फारोक ताचो अर्थ सांगपी कोण नासलो." },
    { type: "verse", num: 9, text: "तेन्ना मुखेल पेयवाल्यान फारोक सांगलें, 'म्हजीं चुकां आज हांव उगडास करतां.'" },
    { type: "verse", num: 10, text: "'फारो आपल्या चाकरांचेर रागावलो, आनी म्हाका आनी मुखेल भाकरवाल्याक राखणदारांच्या सरदाराच्या घरांत बंदखणींत घालो.'" },
    { type: "verse", num: 11, text: "'आनी आमी एकाच राती सपन पळयलें, हांवें आनी ताणें; दरेकल्यान आपापल्या अर्थाप्रमाणें सपन पळयलें.'" },
    { type: "verse", num: 12, text: "'आनी थंय आमचेकडेन एक हेब्री तरणाटो आसलो, राखणदारांच्या सरदाराचो चाकर; आनी आमी ताका सांगलें, आनी ताणें आमच्या सपनांचो अर्थ सांगलो; दरेकल्याक ताच्या सपनाप्रमाणें ताणें अर्थ सांगलो.'" },
    { type: "verse", num: 13, text: "'आनी ताणें आमकां सांगिल्लेप्रमाणें तशें जालें; म्हाका म्हज्या जाग्यार परत दवरलो, आनी ताका उमकळायलो.'" },
    { type: "verse", num: 14, text: "तेन्ना फारोन धाडून योसेफाक आपयलो, आनी ताका बेगीन खड्ड्यांतल्यान भायर काडलो; आनी ताणें दाडी करली आनी वस्त्रां बदललीं, आनी फारोमुखार आयलो." },
    { type: "verse", num: 15, text: "आनी फारोन योसेफाक म्हणलें, 'हांवें एक सपन पळयलां, आनी ताचो अर्थ सांगपी कोण ना; आनी हांवें तुजेविशीं आयकलां, तूं सपन आयकून ताचो अर्थ सांगता.'" },
    { type: "verse", num: 16, text: "आनी योसेफान फारोक जाप दिली, 'म्हजेपसून न्हय; देव फारोक बरी जाप दितलो.'" },
    { type: "verse", num: 17, text: "आनी फारोन योसेफाक सांगलें, 'म्हज्या सपनांत, पळय, हांव न्हंयेच्या देगेर उबो आसलों.'" },
    { type: "verse", num: 18, text: "'आनी पळय, न्हंयेंतल्यान सात पुश्ट आनी सोबीत गायो वयर आयल्यो, आनी गवतांत चरपाक लागल्यो.'" },
    { type: "verse", num: 19, text: "'आनी पळय, तांचे फाटल्यान अजून सात गायो वयर आयल्यो, सुकिल्ल्यो, खूब कुरूप आनी अशक्त; ईजिप्ताच्या सगळ्या देसांत हांवें अशो वायट कधींच पळोवंक नासल्यो.'" },
    { type: "verse", num: 20, text: "'आनी सुकिल्ल्या आनी कुरूप गायांनी पयल्यो सात पुश्ट गायो खाल्यो.'" },
    { type: "verse", num: 21, text: "'आनी तांणीं तांकां खाल्यो तरी तांकां खाल्ल्यो म्हूण कळ्ळें ना; कारण त्यो पयलीं सारक्योच कुरूप दिसताल्यो. आनी हांव जागो जालों.'" },
    { type: "verse", num: 22, text: "'आनी हांवें म्हज्या सपनांत पळयलें; आनी पळय, एका काडयेर सात कणसां, भरिल्लीं आनी बरीं, उगवलीं.'" },
    { type: "verse", num: 23, text: "'आनी पळय, तांचे उपरांत सात कणसां, सुकिल्लीं, सुकलीं आनी उदेंत वाऱ्यान कोमशिल्लीं, उगवलीं.'" },
    { type: "verse", num: 24, text: "'आनी सुकिल्ल्या कणसांनी सात बरीं कणसां गिळून घेतलीं. आनी हांवें जादूगारांक सांगलें; पूण म्हाका सांगपी कोण नासलो.'" },
    { type: "verse", num: 25, text: "आनी योसेफान फारोक म्हणलें, 'फारोचें सपन एकच; देव कितें करतलो तें फारोक दाखयलां.'" },
    { type: "verse", num: 26, text: "'सात बऱ्यो गायो म्हणल्यार सात वर्सां; आनी सात बरीं कणसां म्हणल्यार सात वर्सां; सपन एकच.'" },
    { type: "verse", num: 27, text: "'आनी तांचे उपरांत वयर आयिल्ल्यो सात सुकिल्ल्यो आनी कुरूप गायो म्हणल्यार सात वर्सां; आनी उदेंत वाऱ्यान कोमशिल्लीं सात रितीं कणसां म्हणल्यार सात वर्सां दुकळाचीं.'" },
    { type: "verse", num: 28, text: "'हांवें फारोक सांगिल्लेप्रमाणें; देव कितें करतलो तें फारोक दाखयलां.'" },
    { type: "verse", num: 29, text: "'पळय, सगळ्या ईजिप्त देसांत सात वर्सां खूब बरकत येतली.'" },
    { type: "verse", num: 30, text: "'आनी तांचे उपरांत सात वर्सां दुकळाचीं येतलीं; आनी ईजिप्त देसांत सगळी बरकत विसरतलीं; आनी दुकळ देस नाश करतलो.'" },
    { type: "verse", num: 31, text: "'आनी त्या दुकळाक लागून त्या उपरांत येतल्या देसांतली बरकत कळची ना; कारण तो दुकळ खूब कठीण आसतलो.'" },
    { type: "verse", num: 32, text: "'आनी फारोक सपन दोन फावट आयलें हाचो अर्थ, ही गजाल देवान थीर केल्या, आनी देव ती बेगीन करतलो.'" },
    { type: "section", text: "योसेफ ईजिप्ताचेर अधिकारी जालो" },
    { type: "verse", num: 33, text: "'आतां फारोन एक शाणो आनी बुदवंत मनीस सोदून काडचो, आनी ताका ईजिप्त देसाचेर मुखेली करचो.'" },
    { type: "verse", num: 34, text: "'फारोन हें करचें, आनी देसाचेर अधिकारी नेमचे; आनी सात वर्सां बरकतीच्या काळांत ईजिप्त देसांतली पांचवी वांटणी घेवची.'" },
    { type: "verse", num: 35, text: "'आनी ह्या बऱ्या वर्सांत सगळें अन्न जमा करचें, आनी फारोच्या हाताखाला शारांनी धान्य सांठोवन दवरचें, आनी ताची राखण करची.'" },
    { type: "verse", num: 36, text: "'आनी तें अन्न ईजिप्त देसांत येतल्या सात वर्सां दुकळाक लागून सांठोवन दवरचें; म्हणचे देस दुकळान नाश जावचो ना.'" },
    { type: "verse", num: 37, text: "आनी ही गजाल फारोच्या आनी ताच्या सगळ्या चाकरांच्या दोळ्यांत बरी दिसली." },
    { type: "verse", num: 38, text: "आनी फारोन आपल्या चाकरांक म्हणलें, 'ज्या मनशाचे थंय देवाचो आत्मो आसा, असो मनीस आमकां मेळत काय?'" },
    { type: "verse", num: 39, text: "आनी फारोन योसेफाक म्हणलें, 'देवान तुका हें सगळें दाखयलां देखून, तुजेसारको शाणो आनी बुदवंत कोणूच ना.'" },
    { type: "verse", num: 40, text: "'तूं म्हज्या घरावयलो आसतलो, आनी तुज्या उतराप्रमाणें म्हजे सगळे लोक चलतले; फकत सिंहासनाविशीं हांव तुजेपरस व्हड आसतलों.'" },
    { type: "verse", num: 41, text: "आनी फारोन योसेफाक म्हणलें, 'पळय, हांवें तुका सगळ्या ईजिप्त देसाचेर नेमलां.'" },
    { type: "verse", num: 42, text: "आनी फारोन आपल्या हातांतली मुद्रा काडून योसेफाच्या हातांत घाली; आनी ताका तलम तागाचीं वस्त्रां न्हेसयलीं, आनी ताच्या गळ्यांत भांगराची साखळी घाली." },
    { type: "verse", num: 43, text: "आनी आपल्या दुसऱ्या रथांत ताका बसयलो; आनी तांणीं ताचेमुखार बोबाटलें, 'दिंडे तेकात!' अशें ताका सगळ्या ईजिप्त देसाचेर नेमलो." },
    { type: "verse", num: 44, text: "आनी फारोन योसेफाक म्हणलें, 'हांव फारो; पूण तुजे बगर सगळ्या ईजिप्त देसांत कोणूय आपलो हात वा पांय उकलचो ना.'" },
    { type: "verse", num: 45, text: "आनी फारोन योसेफाचें नांव सापनत-पानेआह दवरलें; आनी ओनाच्या याजक पोतीफेराची धूव आसनत ताका बायल दिली. आनी योसेफ ईजिप्त देसाचेर भोंवलो." },
    { type: "verse", num: 46, text: "आनी योसेफ ईजिप्ताचो राजा फारो हाचेमुखार उबो रावलो तेन्ना तीस वर्सांचो आसलो. आनी योसेफ फारोमुखार भायर गेलो, आनी सगळ्या ईजिप्त देसांत भोंवलो." },
    { type: "verse", num: 47, text: "आनी बरकतीच्या सात वर्सांत पृथ्वीन भरपूर उत्पन्न दिलें." },
    { type: "verse", num: 48, text: "आनी ताणें ईजिप्त देसांत सात वर्सांत जें अन्न आसलें तें सगळें जमा केलें, आनी शारांनी अन्न सांठयलें; दरेक शाराभोंवतणच्या शेतांतलें अन्न त्या शारांत सांठयलें." },
    { type: "verse", num: 49, text: "आनी योसेफान दर्याच्या रेंवेसारकें खूब धान्य सांठयलें, मेरेन तो मेजप सोडलें; कारण तें मेजपा भायर आसलें." },
    { type: "verse", num: 50, text: "आनी दुकळाचीं वर्सां येवपापयलीं, योसेफाक दोन पूत जल्मले, जे ओनाचो याजक पोतीफेराची धूव आसनत हिणें ताका जल्मयले." },
    { type: "verse", num: 51, text: "आनी योसेफान ज्येश्टाचें नांव मनश्शे दवरलें: 'कारण देवान म्हाका म्हजी सगळी दुख्ख आनी म्हज्या बापायचें सगळें घर विसरपाक लायलां.'" },
    { type: "verse", num: 52, text: "आनी दुसऱ्याचें नांव एफ्रायीम दवरलें: 'कारण देवान म्हाका म्हज्या दुख्खाच्या देसांत फळां दिल्यांत.'" },
    { type: "verse", num: 53, text: "आनी ईजिप्त देसांत बरकतीचीं सात वर्सां सोपलीं." },
    { type: "verse", num: 54, text: "आनी दुकळाचीं सात वर्सां सुरू जालीं, योसेफान सांगिल्लेप्रमाणें; आनी सगळ्या देसांनी दुकळ आसलो; पूण सगळ्या ईजिप्त देसांत भाकर आसली." },
    { type: "verse", num: 55, text: "आनी सगळो ईजिप्त देस भुकेलो तेन्ना, लोकांनी फारोकडेन भाकरेखातीर बोबाटलें; आनी फारोन सगळ्या ईजिप्ती लोकांक म्हणलें, 'योसेफाकडेन वचात; तो तुमकां सांगता तें करात.'" },
    { type: "verse", num: 56, text: "आनी दुकळ सगळ्या पृथ्वीचेर पसरलो; आनी योसेफान सगळीं कोठारां उगतीं केलीं, आनी ईजिप्ती लोकांक विकलें; आनी ईजिप्त देसांत दुकळ कठीण जालो." },
    { type: "verse", num: 57, text: "आनी सगळ्या देसांतले लोक योसेफाकडेन ईजिप्ताक धान्य विकत घेवपाक आयले; कारण सगळ्या पृथ्वीचेर दुकळ कठीण आसलो." },
  ],
  "42": [
    { type: "section", text: "योसेफाचे भाव ईजिप्ताक गेले" },
    { type: "verse", num: 1, text: "आनी ईजिप्तांत धान्य आसा म्हूण याकोबान पळयलें तेन्ना, याकोबान आपल्या पुतांक म्हणलें, 'तुमी एकामेकांक कित्याक पळयतात?'" },
    { type: "verse", num: 2, text: "आनी ताणें म्हणलें, 'पळय, ईजिप्तांत धान्य आसा म्हूण हांवें आयकलां; थंय देंवात आनी आमचे खातीर धान्य विकत घेयात, म्हणचे आमी जगूया आनी मरचीं ना.'" },
    { type: "verse", num: 3, text: "आनी योसेफाचे धा भाव ईजिप्तांत धान्य विकत घेवपाक देंवले." },
    { type: "verse", num: 4, text: "पूण योसेफाच्या भावा बिन्यामीनाक याकोबान ताच्या भावांकडेन धाडलो ना; कारण ताणें म्हणलें, 'ताका कांय विघ्न येत.'" },
    { type: "verse", num: 5, text: "आनी इस्राएलाचे पूत विकत घेवप्यांमदीं धान्य विकत घेवपाक आयले; कारण कनान देसांत दुकळ आसलो." },
    { type: "verse", num: 6, text: "आनी योसेफ देसाचेर अधिकारी आसलो; तोच देसांतल्या सगळ्या लोकांक विकतालो. आनी योसेफाचे भाव आयले, आनी भुंयेमेरेन तोंडार ताका नमन केलें." },
    { type: "verse", num: 7, text: "आनी योसेफान आपल्या भावांक पळयलें, आनी तांकां वळखलें, पूण तांचेमुखार आपूण परको जालो, आनी तांकां कठोरपणान उलयलो; आनी तांकां म्हणलें, 'तुमी खंयसून आयलात?' आनी तांणीं म्हणलें, 'कनान देसांतल्यान अन्न विकत घेवपाक.'" },
    { type: "verse", num: 8, text: "आनी योसेफान आपल्या भावांक वळखलें, पूण तांणीं ताका वळखलो ना." },
    { type: "verse", num: 9, text: "आनी तांचेविशीं पळयिल्लीं सपनां योसेफाक याद जालीं; आनी ताणें तांकां म्हणलें, 'तुमी हेर आसात; देसाची उक्ती सुवात पळोवपाक तुमी आयलात.'" },
    { type: "verse", num: 10, text: "आनी तांणीं ताका म्हणलें, 'ना, म्हज्या धन्या, तुजे चाकर अन्न विकत घेवपाक आयलात.'" },
    { type: "verse", num: 11, text: "'आमी सगळे एका मनशाचे पूत; आमी सत्य मनीस; तुजे चाकर हेर न्हय.'" },
    { type: "verse", num: 12, text: "आनी ताणें तांकां म्हणलें, 'ना; देसाची उक्ती सुवात पळोवपाक तुमी आयलात.'" },
    { type: "verse", num: 13, text: "आनी तांणीं म्हणलें, 'तुजे चाकर बारा भाव, कनान देसांतल्या एका मनशाचे पूत; आनी पळय, सगळ्यांत ल्हान आज आमच्या बापायकडेन आसा, आनी एक ना.'" },
    { type: "verse", num: 14, text: "आनी योसेफान तांकां म्हणलें, 'हांवें तुमकां सांगिल्लेप्रमाणें, तुमी हेर आसात.'" },
    { type: "verse", num: 15, text: "'ह्या प्रमाणें तुमची परीक्षा जातली: फारोच्या जिविताची शपत, जोमेरेन तुमचो सगळ्यांत ल्हान भाव हांगा येना तोमेरेन तुमी हांगासून भायर वचचे ना.'" },
    { type: "verse", num: 16, text: "'तुमच्यांतल्या एकल्याक धाडात, तो तुमच्या भावाक हाडूं; आनी तुमी बंदी आसतलात, तुमचीं उतरां खरीं आसात काय तें पळोवपाक; नाजाल्यार, फारोच्या जिविताची शपत, तुमी हेर आसात.'" },
    { type: "verse", num: 17, text: "आनी ताणें तांकां तीन दीस एकठांय बंदखणींत घालें." },
    { type: "verse", num: 18, text: "आनी तिसऱ्या दिसा योसेफान तांकां म्हणलें, 'हें करात आनी जगात; कारण हांव देवाक भिता.'" },
    { type: "verse", num: 19, text: "'तुमी सत्य मनीस आसात जाल्यार, तुमच्या भावांतलो एकलो बंदखणींत बंदी आसूंदी; आनी तुमी वचात आनी तुमच्या घरांच्या भुकेक लागून धान्य व्हरात.'" },
    { type: "verse", num: 20, text: "'आनी तुमचो सगळ्यांत ल्हान भाव म्हजेकडेन हाडात; अशें तुमचीं उतरां खरीं जातलीं, आनी तुमी मरचे ना.' आनी तांणीं तशें केलें." },
    { type: "verse", num: 21, text: "आनी तांणीं एकामेकांक म्हणलें, 'खरेंच आमी आमच्या भावाविशीं दोशी; कारण ताणें आमकां विनवणी केली तेन्ना ताच्या जिवाची वेदना आमी पळयली, पूण आमी आयकलें ना; देखून ही दुख्ख आमचेर आयल्या.'" },
    { type: "verse", num: 22, text: "आनी रऊबेनान तांकां जाप दिली, 'हांवें तुमकां सांगलें न्हय, भुरग्याआड पातक करिनाकात; पूण तुमी आयकलें ना; आनी पळय, ताच्या रगताचो हिसोब लागता.'" },
    { type: "verse", num: 23, text: "आनी योसेफ तांचें आयकता म्हूण तांकां कळ्ळें ना; कारण तांचेमदीं दुभाशी आसलो." },
    { type: "verse", num: 24, text: "आनी तो तांचेपसून पलतडीं गेलो आनी रडलो; आनी तांचेकडेन परतलो आनी तांकां उलयलो; आनी तांचेमदल्या शिमोनाक धरलो आनी तांच्या दोळ्यांमुखार ताका बांदलो." },
    { type: "verse", num: 25, text: "आनी योसेफान आज्ञा दिली तांच्यो वोजो धान्यान भरपाक, आनी दरेकल्याचे पयशे ताच्या वोजेंत परत दवरपाक, आनी तांकां वाटेक लागून खाणावळ दिवपाक; आनी तांकां तशें केलें." },
    { type: "verse", num: 26, text: "आनी तांणीं आपलें धान्य आपल्या गाडवांचेर चडयलें, आनी थंयसून गेले." },
    { type: "verse", num: 27, text: "आनी एकल्यान आपल्या गाडवाक खावपाक दिवपाक धर्मशाळेंत आपली वोजी उगती केली तेन्ना, ताणें आपले पयशे पळयले; आनी पळय, ते ताच्या वोजेच्या तोंडांत आसले." },
    { type: "verse", num: 28, text: "आनी ताणें आपल्या भावांक म्हणलें, 'म्हजे पयशे परत आयलात; आनी पळय, ते म्हज्या वोजेंत आसात.' आनी तांचें काळीज बुडलें, आनी ते भियान एकामेकांक म्हणाले, 'देवान आमकां कितें केलें?'" },
    { type: "verse", num: 29, text: "आनी ते कनान देसांत आपल्या बापाय याकोबाकडेन आयले, आनी तांकां जें जालें तें सगळें ताका सांगलें:" },
    { type: "verse", num: 30, text: "'त्या देसाचो धनी आमकां कठोरपणान उलयलो, आनी आमकां देसाचे हेर मानलें.'" },
    { type: "verse", num: 31, text: "'आनी आमी ताका म्हणलें, आमी सत्य मनीस; आमी हेर न्हय.'" },
    { type: "verse", num: 32, text: "'आमी बारा भाव, एका बापायचे पूत; एक ना, आनी सगळ्यांत ल्हान आज कनान देसांत आमच्या बापायकडेन आसा.'" },
    { type: "verse", num: 33, text: "'आनी त्या देसाच्या धन्यान आमकां म्हणलें, ह्या प्रमाणें हांव जाणतलों तुमी सत्य मनीस म्हूण: तुमच्या भावांतल्या एकल्याक म्हजेकडेन दवरात, आनी तुमच्या घरांच्या भुकेक लागून धान्य घेवन वचात.'" },
    { type: "verse", num: 34, text: "'आनी तुमचो सगळ्यांत ल्हान भाव म्हजेकडेन हाडात; तेन्ना हांव जाणतलों तुमी हेर न्हय, पूण सत्य मनीस; तेन्ना तुमचो भाव तुमकां दितलों, आनी तुमी देसांत वेपार करतलात.'" },
    { type: "verse", num: 35, text: "आनी तांणीं आपल्यो वोजो रित्यो करताना, पळय, दरेकल्याची पयशांची पोटली ताच्या वोजेंत आसली; आनी तांणीं आनी तांच्या बापायन पयशांच्यो पोटल्यो पळयल्यो तेन्ना ते भियेले." },
    { type: "verse", num: 36, text: "आनी तांचो बापय याकोबान तांकां म्हणलें, 'तुमी म्हाका भुरग्यांबगर केलो; योसेफ ना, आनी शिमोन ना, आनी बिन्यामीनाक तुमी व्हरतात; ह्यो सगळ्यो गजाली म्हजेआड आसात.'" },
    { type: "verse", num: 37, text: "आनी रऊबेनान आपल्या बापायक म्हणलें, 'हांव ताका तुजेकडेन परत हाडिना जाल्यार म्हज्या दोन पुतांक मार; ताका म्हज्या हातांत दवर, आनी हांव ताका तुजेकडेन परत हाडतलों.'" },
    { type: "verse", num: 38, text: "आनी ताणें म्हणलें, 'म्हजो पूत तुमचेकडेन देंवचो ना; कारण ताचो भाव मेलो, आनी तो एकलो उरलो; वाटेर ताका कांय विघ्न आयल्यार, तुमी म्हज्या पिकिल्ल्या केसांक दुखान थडग्याक धाडतलात.'" },
  ],
  "43": [
    { type: "section", text: "दुसरे फावट ईजिप्ताक" },
    { type: "verse", num: 1, text: "आनी देसांत दुकळ कठीण आसलो." },
    { type: "verse", num: 2, text: "आनी ईजिप्तांतल्यान हाडिल्लें धान्य तांणीं खावन सोपयलें तेन्ना, तांच्या बापायन तांकां म्हणलें, 'परत वचात आनी आमकां थोडें अन्न विकत घेयात.'" },
    { type: "verse", num: 3, text: "आनी यहूदान ताका सांगलें, 'त्या मनशान आमकां कडक सांगलें, तुमचो भाव तुमचेकडेन ना जाल्यार तुमी म्हजें तोंड पळोवचे ना.'" },
    { type: "verse", num: 4, text: "'तूं आमच्या भावाक आमचेकडेन धाडतलो जाल्यार, आमी देंवतले आनी तुका अन्न विकत घेतले.'" },
    { type: "verse", num: 5, text: "'पूण तूं ताका धाडिना जाल्यार, आमी देंवचे ना; कारण त्या मनशान आमकां म्हणलें, तुमचो भाव तुमचेकडेन ना जाल्यार तुमी म्हजें तोंड पळोवचे ना.'" },
    { type: "verse", num: 6, text: "आनी इस्राएलान म्हणलें, 'तुमकां अजून एक भाव आसा म्हूण त्या मनशाक सांगून तुमी म्हजेकडेन कित्याक वायट केलें?'" },
    { type: "verse", num: 7, text: "आनी तांणीं म्हणलें, 'त्या मनशान आमची आनी आमच्या नात्यागोत्याची खबर विचारली, तुमचो बापय अजून जिवो आसा? तुमकां अजून एक भाव आसा? आनी आमी ह्या उतरांप्रमाणें ताका सांगलें; तो आमच्या भावाक हाडात म्हणतलो म्हूण आमकां कशें कळटलें?'" },
    { type: "verse", num: 8, text: "आनी यहूदान आपल्या बापाय इस्राएलाक म्हणलें, 'भुरग्याक म्हजेकडेन धाड, आनी आमी उठून वतले; म्हणचे आमी जगूया आनी मरचीं ना, आमी आनी तूंय आनी आमचीं भुरगींय.'" },
    { type: "verse", num: 9, text: "'हांव ताची जबाबदारी घेतां; म्हज्या हातांतल्यान ताचो हिसोब; हांव ताका तुजेकडेन परत हाडिना जाल्यार आनी तुजेमुखार दवरिना जाल्यार, तुजेमुखार सदांकाळ हांव दोशी आसतलों.'" },
    { type: "verse", num: 10, text: "'कारण आमी उसार केल्ली नासली जाल्यार, खात्रीन आतांमेरेन आमी दोन फावट परत येतले आसले.'" },
    { type: "verse", num: 11, text: "आनी तांचो बापय इस्राएलान तांकां म्हणलें, 'तशें जावंक जाय जाल्यार, हें करात: देसांतल्या उत्तम फळांतलें तुमच्या वोज्यांत दवरात, आनी त्या मनशाक दान व्हरात — थोडो बाम, आनी थोडो मध, मसाले आनी गंधरस, पिस्ता आनी बदाम.'" },
    { type: "verse", num: 12, text: "'आनी दुपट पयशे तुमच्या हातांत घेयात; आनी तुमच्या वोज्यांच्या तोंडांत परत आयिल्ले पयशे तुमच्या हातांत परत व्हरात; कदाचीत ती चूक जाल्या.'" },
    { type: "verse", num: 13, text: "'तुमच्या भावाक घेयात आनी उठून त्या मनशाकडेन परत वचात.'" },
    { type: "verse", num: 14, text: "'आनी सर्वशक्तिमान देव त्या मनशामुखार तुमचेर दया करूंदी, म्हणचे तुमचो दुसरो भाव आनी बिन्यामीन ताणें तुमकां परत धाडचो. आनी हांव भुरग्यांबगर जावंक जाय जाल्यार, जावं.'" },
    { type: "verse", num: 15, text: "आनी त्या मनशांनी तें दान आनी दुपट पयशे तांच्या हातांत घेतले, आनी बिन्यामीनाक घेतलो; आनी उठून ईजिप्ताक देंवले आनी योसेफामुखार उबे रावले." },
    { type: "verse", num: 16, text: "आनी योसेफान बिन्यामीनाक तांचेकडेन पळयलो तेन्ना, आपल्या घराच्या कारभाऱ्याक म्हणलें, 'ह्या मनशांक घरा व्हर, आनी जनावर मार आनी तयार कर; कारण हे मनीस दनपारां म्हजेकडेन जेवतले.'" },
    { type: "verse", num: 17, text: "आनी त्या मनशान योसेफान सांगिल्लेप्रमाणें केलें; आनी त्या मनशान ह्या मनशांक योसेफाच्या घरांत व्हरलें." },
    { type: "verse", num: 18, text: "आनी ते मनीस योसेफाच्या घरांत व्हरले तेन्ना भियेले, आनी म्हणाले, 'पयल्या फावट आमच्या वोज्यांत परत आयिल्ल्या पयशांक लागून आमकां भितर हाडलां; आमचेर तुटून पडपाक आनी आमकां गुलाम करपाक आनी आमचीं गाडवां घेवपाक.'" },
    { type: "verse", num: 19, text: "आनी ते योसेफाच्या घराच्या कारभाऱ्यालागीं गेले, आनी घराच्या दारांत ताचेकडेन उलयले," },
    { type: "verse", num: 20, text: "आनी म्हणाले, 'म्हज्या धन्या, आमी खरेंच पयल्या फावट अन्न विकत घेवपाक देंविल्लीं.'" },
    { type: "verse", num: 21, text: "'आनी आमी धर्मशाळेंत पाविल्लीं तेन्ना आमी आमच्यो वोजो उगत्यो केल्यो, आनी पळय, दरेकल्याचे पयशे ताच्या वोजेच्या तोंडांत आसले, आमचे पुराय पयशे; आनी आमी ते आमच्या हातांत परत हाडलात.'" },
    { type: "verse", num: 22, text: "'आनी अन्न विकत घेवपाक हेर पयशेय आमी आमच्या हातांत हाडलात; आमच्या वोज्यांत पयशे कोणें घालें तें आमकां कळना.'" },
    { type: "verse", num: 23, text: "आनी ताणें म्हणलें, 'तुमकां शांती; भियेनाकात; तुमच्या देवान आनी तुमच्या बापायच्या देवान तुमच्या वोज्यांत तुमकां भांडवल दिलां; तुमचे पयशे म्हजेकडेन आयले.' आनी ताणें शिमोनाक तांचेकडेन भायर हाडलो." },
    { type: "verse", num: 24, text: "आनी त्या मनशान ह्या मनशांक योसेफाच्या घरांत हाडलें, आनी तांकां उदक दिलें, आनी तांणीं आपले पांय धुले; आनी तांच्या गाडवांक चारो दिलो." },
    { type: "verse", num: 25, text: "आनी योसेफ दनपारां येतलो म्हूण तांणीं दान तयार केलें; कारण ते थंय जेवतले म्हूण तांणीं आयकिल्लें." },
    { type: "verse", num: 26, text: "आनी योसेफ घरा आयलो तेन्ना, तांणीं ताका घरांत आपणेकडेन आशिल्लें दान दिलें, आनी भुंयेमेरेन ताका नमन केलें." },
    { type: "verse", num: 27, text: "आनी ताणें तांकां बरे आसात काय म्हूण विचारलें, आनी म्हणलें, 'तुमचो म्हातारो बापय, ज्याचेविशीं तुमी सांगलें, तो बरो आसा? तो अजून जिवो आसा?'" },
    { type: "verse", num: 28, text: "आनी तांणीं म्हणलें, 'तुजो चाकर आमचो बापय बरो आसा, तो अजून जिवो आसा.' आनी तांणीं नमन करून मान बागयली." },
    { type: "verse", num: 29, text: "आनी ताणें दोळे उकलले आनी आपल्या भावा बिन्यामीनाक, आपल्या आवयच्या पुताक, पळयलो, आनी म्हणलें, 'तुमी सांगिल्लो तुमचो सगळ्यांत ल्हान भाव हो?' आनी म्हणलें, 'देव तुजेर कुर्पा करूं, म्हज्या पुता.'" },
    { type: "verse", num: 30, text: "आनी योसेफान बेगीन भायर गेलो; कारण ताचें काळीज आपल्या भावाक लागून पिगळलें; आनी ताका रडपाक येतालें; आनी तो आपल्या कुडांत गेलो आनी थंय रडलो." },
    { type: "verse", num: 31, text: "आनी ताणें तोंड धुलें, आनी भायर आयलो, आनी आपणाक सांबाळलो, आनी म्हणलें, 'जेवण वाडात.'" },
    { type: "verse", num: 32, text: "आनी ताका वेगळें वाडलें, आनी तांकां वेगळें, आनी ताचेकडेन जेवपी ईजिप्ती मनशांक वेगळें; कारण ईजिप्ती मनीस हेब्रींकडेन जेवपाक शकनात; कारण तें ईजिप्ती लोकांक घृणेचें." },
    { type: "verse", num: 33, text: "आनी ते ताचेमुखार बसले, ज्येश्ट ताच्या ज्येश्टपणाप्रमाणें, आनी ल्हान ताच्या ल्हानपणाप्रमाणें; आनी ते मनीस एकामेकांक अजापान पळयताले." },
    { type: "verse", num: 34, text: "आनी ताणें आपल्या मुखावयल्या वाट्यांतल्यान तांकां वाटे दिले; पूण बिन्यामीनाचो वाटो सगळ्यांच्या वाट्यापरस पांच वांट्यांनी चड आसलो. आनी ते ताचेकडेन पियेले आनी खुशाल जाले." },
  ],
  "44": [
    { type: "section", text: "रुप्याचो प्याला" },
    { type: "verse", num: 1, text: "आनी ताणें आपल्या घराच्या कारभाऱ्याक आज्ञा दिली, 'ह्या मनशांच्यो वोजो ते व्हरपाक शकतात तितल्या अन्नान भर, आनी दरेकल्याचे पयशे ताच्या वोजेच्या तोंडांत दवर.'" },
    { type: "verse", num: 2, text: "'आनी म्हजो प्याला, रुप्याचो प्याला, सगळ्यांत ल्हानाच्या वोजेच्या तोंडांत दवर, ताच्या धान्याच्या पयशांसयत.' आनी ताणें योसेफान सांगिल्लेप्रमाणें केलें." },
    { type: "verse", num: 3, text: "सकाळ जाली तेन्ना, ह्या मनशांक तांच्या गाडवांसयत धाडले." },
    { type: "verse", num: 4, text: "ते शाराभायर गेले, अजून लांब गेले नात, तेन्ना योसेफान आपल्या कारभाऱ्याक म्हणलें, 'उठ, त्या मनशांफाटल्यान लाग; आनी तांकां पावतलो तेन्ना तांकां म्हण, बऱ्याक तुमी कित्याक वायटान परत दिलें?'" },
    { type: "verse", num: 5, text: "'हो तो प्याला न्हय, ज्यांतल्यान म्हजो धनी पियेता आनी ज्याच्यान तो शकून पळयता? तुमी वायट केलें.'" },
    { type: "verse", num: 6, text: "आनी तो तांकां पावलो, आनी हीं उतरां तांकां उलयलो." },
    { type: "verse", num: 7, text: "आनी तांणीं ताका म्हणलें, 'म्हजो धनी अशीं उतरां कित्याक उलयता? तुज्या चाकरांनी असली गजाल कधींच केल्ली ना.'" },
    { type: "verse", num: 8, text: "'पळय, जे पयशे आमकां आमच्या वोज्यांच्या तोंडांत मेळ्ळे ते आमी कनान देसांतल्यान तुका परत हाडलें; तेन्ना तुज्या धन्याच्या घरांतल्यान रुपें वा भांगर आमी कशे चोरतले?'" },
    { type: "verse", num: 9, text: "'तुज्या चाकरांमदल्या ज्या कोणाकडेन तो मेळटलो तो मरूं; आनी आमीय म्हज्या धन्याचे गुलाम जातले.'" },
    { type: "verse", num: 10, text: "आनी ताणें म्हणलें, 'आतां तुमच्या उतरांप्रमाणें जांव; ज्याचेकडेन तो मेळटलो तो म्हजो गुलाम जातलो; आनी तुमी निर्दोश आसतलात.'" },
    { type: "verse", num: 11, text: "तेन्ना तांणीं दरेकल्यान बेगीन आपली वोजी भुंयेर देंवयली, आनी दरेकल्यान आपली वोजी उगती केली." },
    { type: "verse", num: 12, text: "आनी ताणें सोदलें, ज्येश्टापसून सुरू करून सगळ्यांत ल्हानामेरेन; आनी प्याला बिन्यामीनाच्या वोजेंत मेळ्ळो." },
    { type: "verse", num: 13, text: "तेन्ना तांणीं आपलीं वस्त्रां फाडलीं, आनी दरेकल्यान आपल्या गाडवाचेर लाद चडयली, आनी शारांत परतले." },
    { type: "verse", num: 14, text: "आनी यहूदा आनी ताचे भाव योसेफाच्या घरांत आयले; आनी तो अजून थंय आसलो; आनी ते ताचेमुखार भुंयेर पडले." },
    { type: "verse", num: 15, text: "आनी योसेफान तांकां म्हणलें, 'तुमी कसलें कृत्य केलें? म्हजेसारको मनीस शकून पळोवपाक शकता म्हूण तुमकां कळना?'" },
    { type: "verse", num: 16, text: "आनी यहूदान म्हणलें, 'आमी म्हज्या धन्याक कितें सांगूया? कितें उलोवया? कशें आमचें निर्दोशपण दाखोवया? देवान तुज्या चाकरांचो अपराध सोदून काडलो; पळय, आमी म्हज्या धन्याचे गुलाम, आमी आनी ज्याचेकडेन प्याला मेळ्ळो तोय.'" },
    { type: "verse", num: 17, text: "आनी ताणें म्हणलें, 'असली गजाल करप म्हजेपसून पयस; ज्याच्या हातांत प्याला मेळ्ळो तो म्हजो गुलाम जातलो; आनी तुमी शांतीन आपल्या बापायकडेन वयर वचात.'" },
    { type: "verse", num: 18, text: "तेन्ना यहूदा ताचेलागीं गेलो आनी म्हणलें, 'म्हज्या धन्या, तुजो चाकर म्हज्या धन्याच्या कानांत एक उतर सांगूंदी, आनी तुजो राग तुज्या चाकराचेर पेटूं नाका; कारण तूं फारोसारको आसा.'" },
    { type: "verse", num: 19, text: "'म्हज्या धन्यान आपल्या चाकरांक विचारलें, तुमकां बापय वा भाव आसा?'" },
    { type: "verse", num: 20, text: "'आनी आमी म्हज्या धन्याक म्हणलें, आमकां म्हातारो बापय आसा, आनी ताच्या म्हातारपणाचो एक ल्हान भुरगो; आनी ताचो भाव मेलो, आनी ताच्या आवयचो तो एकलो उरलो, आनी ताचो बापय ताचेर मोग करता.'" },
    { type: "verse", num: 21, text: "'आनी तूं तुज्या चाकरांक म्हणलो, ताका म्हजेकडेन हाडात, म्हणचे हांव ताचेर दोळो दवरतलों.'" },
    { type: "verse", num: 22, text: "'आनी आमी म्हज्या धन्याक म्हणलें, भुरगो आपल्या बापायक सोडपाक शकना; ताणें आपल्या बापायक सोडल्यार बापय मरतलो.'" },
    { type: "verse", num: 23, text: "'आनी तूं तुज्या चाकरांक म्हणलो, तुमचो सगळ्यांत ल्हान भाव तुमचेकडेन देंविना जाल्यार, तुमी म्हजें तोंड आनीक पळोवचे ना.'" },
    { type: "verse", num: 24, text: "'आनी आमी तुज्या चाकरा म्हज्या बापायकडेन वयर गेले तेन्ना, आमी ताका म्हज्या धन्याचीं उतरां सांगलीं.'" },
    { type: "verse", num: 25, text: "'आनी आमच्या बापायन म्हणलें, परत वचात आनी आमकां थोडें अन्न विकत घेयात.'" },
    { type: "verse", num: 26, text: "'आनी आमी म्हणलें, आमकां देंवपाक जायना; आमचो सगळ्यांत ल्हान भाव आमचेकडेन आसत जाल्यार आमी देंवतले; कारण आमचो सगळ्यांत ल्हान भाव आमचेकडेन ना जाल्यार त्या मनशाचें तोंड आमकां पळोवपाक मेळचें ना.'" },
    { type: "verse", num: 27, text: "'आनी तुज्या चाकरा म्हज्या बापायन आमकां म्हणलें, म्हज्या बायलेन म्हाका दोन पूत जल्मयले म्हूण तुमकां कळटा.'" },
    { type: "verse", num: 28, text: "'आनी एकलो म्हजेकडल्यान गेलो, आनी हांवें म्हणलें, खात्रीन ताका फाडून उडयलो; आनी आतांमेरेन हांवें ताका पळोवंक ना.'" },
    { type: "verse", num: 29, text: "'आनी हाकाय तुमी म्हजेकडल्यान व्हरतात, आनी ताका कांय विघ्न आयल्यार, तुमी म्हज्या पिकिल्ल्या केसांक दुखान थडग्याक धाडतलात.'" },
    { type: "verse", num: 30, text: "'आतां हांव तुज्या चाकरा म्हज्या बापायकडेन वतलों, आनी भुरगो आमचेकडेन ना — ताचो जीव भुरग्याच्या जिवाक बांदिल्लो —'" },
    { type: "verse", num: 31, text: "'ताणें पळयतलो भुरगो ना, आनी तो मरतलो; आनी तुजे चाकर तुज्या चाकरा आमच्या बापायच्या पिकिल्ल्या केसांक दुखान थडग्याक धाडतले.'" },
    { type: "verse", num: 32, text: "'कारण तुज्या चाकरान म्हज्या बापायकडेन भुरग्याची जबाबदारी घेतल्या: हांव ताका तुजेकडेन परत हाडिना जाल्यार, म्हज्या बापायमुखार सदांकाळ हांव दोशी आसतलों.'" },
    { type: "verse", num: 33, text: "'आतां म्हजो धनी, भुरग्याच्या सुवातेर तुजो चाकर म्हज्या धन्याचो गुलाम जावन रावूंदी; आनी भुरग्याक ताच्या भावांकडेन वयर वचूंदी.'" },
    { type: "verse", num: 34, text: "'कारण भुरगो म्हजेकडेन ना आसताना हांव म्हज्या बापायकडेन कशें वचूं? म्हज्या बापायचेर येतलें वायट पळोवपाक म्हाका जायना.'" },
  ],
  "45": [
    { type: "section", text: "योसेफान आपणाक वळखयलो" },
    { type: "verse", num: 1, text: "तेन्ना योसेफाक आपणाक आपल्यालागीं उब्या आशिल्ल्या सगळ्यांमुखार सांबाळपाक जालें ना; आनी ताणें बोबाटलें, 'सगळ्यांक म्हजेकडल्यान भायर धाडात.' आनी योसेफान आपल्या भावांक आपूण वळखयतना ताचेकडेन कोणूच उबो नासलो." },
    { type: "verse", num: 2, text: "आनी तो व्हडल्यान रडलो; आनी ईजिप्ती लोकांनी आयकलें, आनी फारोच्या घराणें आयकलें." },
    { type: "verse", num: 3, text: "आनी योसेफान आपल्या भावांक म्हणलें, 'हांव योसेफ; म्हजो बापय अजून जिवो आसा?' आनी ताचे भाव ताका जाप दिवपाक शकले नात; कारण ते ताचेमुखार गोंदळ्ळे." },
    { type: "verse", num: 4, text: "आनी योसेफान आपल्या भावांक म्हणलें, 'म्हजेलागीं या.' आनी ते ताचेलागीं गेले. आनी ताणें म्हणलें, 'हांव तुमचो भाव योसेफ, ज्याक तुमी ईजिप्ताक विकलो.'" },
    { type: "verse", num: 5, text: "'आतां तुमी दुख्खी जायनाकात, आनी तुमी म्हाका हांगा विकलो म्हूण तुमकां राग येवंक फावना; कारण जिवाची राखण करपाक देवान म्हाका तुमचेमुखार धाडलो.'" },
    { type: "verse", num: 6, text: "'कारण दोन वर्सां देसांत दुकळ आसा; आनी अजून पांच वर्सां नांगरप ना आनी कापणी ना.'" },
    { type: "verse", num: 7, text: "'आनी पृथ्वीचेर तुमकां वंश उरोवपाक आनी व्हड सुटकेन तुमचे जीव वाचोवपाक देवान म्हाका तुमचेमुखार धाडलो.'" },
    { type: "verse", num: 8, text: "'तर आतां, तुमी न्हय पूण देवान म्हाका हांगा धाडलो; आनी ताणें म्हाका फारोक बापय केलो, आनी ताच्या सगळ्या घराचो धनी, आनी सगळ्या ईजिप्त देसाचो अधिकारी.'" },
    { type: "verse", num: 9, text: "'बेगीन म्हज्या बापायकडेन वयर वचात आनी ताका म्हणात, तुजो पूत योसेफ अशें म्हणता: देवान म्हाका सगळ्या ईजिप्ताचो धनी केलो; म्हजेकडेन देंव, उसार करूं नाका.'" },
    { type: "verse", num: 10, text: "'आनी तूं गोशेन प्रांतांत रावतलो, आनी म्हजेलागीं आसतलो, तूं, तुजे पूत, तुज्या पुतांचे पूत, तुजीं मेंढरां, तुजीं गोरवां, आनी तुजेकडेन जें कितें आसा तें सगळें.'" },
    { type: "verse", num: 11, text: "'आनी थंय हांव तुजी पोसणूक करतलों; कारण अजून पांच वर्सां दुकळ आसतलो; नाजाल्यार तूं आनी तुजें घराणें आनी तुजेकडेन जें कितें आसा तें सगळें गरीब जातलें.'" },
    { type: "verse", num: 12, text: "'आनी पळय, तुमच्या दोळ्यांक आनी म्हज्या भावा बिन्यामीनाच्या दोळ्यांक दिसता, म्हजें तोंड तुमचेकडेन उलयता.'" },
    { type: "verse", num: 13, text: "'आनी ईजिप्तांत म्हजी सगळी व्हडवीक आनी तुमी पळयिल्लें सगळें म्हज्या बापायक सांगात; आनी बेगीन म्हज्या बापायक हांगा देंवयात.'" },
    { type: "verse", num: 14, text: "आनी तो आपल्या भावा बिन्यामीनाच्या गळ्याक पडलो आनी रडलो; आनी बिन्यामीनय ताच्या गळ्याक पडून रडलो." },
    { type: "verse", num: 15, text: "आनी ताणें आपल्या सगळ्या भावांक उमो दिलो आनी तांचेकडेन रडलो; आनी त्या उपरांत ताचे भाव ताचेकडेन उलयले." },
    { type: "verse", num: 16, text: "आनी फारोच्या घराण्यांत खबर पावली, योसेफाचे भाव आयलात म्हूण; आनी फारोच्या आनी ताच्या चाकरांच्या दोळ्यांत तें बरें दिसलें." },
    { type: "verse", num: 17, text: "आनी फारोन योसेफाक म्हणलें, 'तुज्या भावांक सांग, हें करात: तुमच्या जनावरांचेर लाद चडयात, आनी कनान देसांत वचात.'" },
    { type: "verse", num: 18, text: "'आनी तुमच्या बापायक आनी तुमच्या घराण्यांक घेवन म्हजेकडेन या; आनी हांव तुमकां ईजिप्त देसांतलें बरें दितलों, आनी तुमी देसांतली वसू खातलात.'" },
    { type: "verse", num: 19, text: "'आनी तुका आज्ञा आसा; हें करात: तुमच्या भुरग्यांक आनी तुमच्या बायलांक व्हरपाक ईजिप्त देसांतल्यान गाडयो घेयात, आनी तुमच्या बापायक हाडात आनी या.'" },
    { type: "verse", num: 20, text: "'आनी तुमच्या सामानाची चिंता करिनाकात; कारण सगळ्या ईजिप्त देसांतलें बरें तुमचें.'" },
    { type: "verse", num: 21, text: "आनी इस्राएलाच्या पुतांनी तशें केलें; आनी योसेफान फारोच्या आज्ञेप्रमाणें तांकां गाडयो दिल्यो, आनी तांकां वाटेक लागून खाणावळ दिली." },
    { type: "verse", num: 22, text: "तांच्यांतल्या दरेकल्याक ताणें बदलपाचीं वस्त्रां दिलीं; पूण बिन्यामीनाक तीनशें रुपयें आनी पांच बदलपाचीं वस्त्रां दिलीं." },
    { type: "verse", num: 23, text: "आनी आपल्या बापायक ताणें अशें धाडलें: ईजिप्तांतलें बरें भरिल्ले धा गाडव, आनी धान्य आनी भाकर आनी वाटेक लागून बापायक खाणावळ भरिल्ल्यो धा गाडवीणी." },
    { type: "verse", num: 24, text: "अशें ताणें आपल्या भावांक धाडले, आनी ते गेले; आनी ताणें तांकां म्हणलें, 'वाटेर झगडूं नाकात.'" },
    { type: "verse", num: 25, text: "आनी ते ईजिप्तांतल्यान वयर गेले, आनी कनान देसांत आपल्या बापाय याकोबाकडेन पावले." },
    { type: "verse", num: 26, text: "आनी ताका सांगलें, 'योसेफ अजून जिवो आसा, आनी तो सगळ्या ईजिप्त देसाचेर अधिकारी आसा.' आनी ताचें काळीज थंड जालें, कारण ताणें तांचेर विश्वास दवरलो ना." },
    { type: "verse", num: 27, text: "आनी योसेफान तांकां सांगिल्लीं सगळीं उतरां तांणीं ताका सांगलीं; आनी ताणें ताका व्हरपाक योसेफान धाडिल्ल्यो गाडयो पळयल्यो तेन्ना, तांच्या बापाय याकोबाचो आत्मो जिवो जालो." },
    { type: "verse", num: 28, text: "आनी इस्राएलान म्हणलें, 'पुरो; म्हजो पूत योसेफ अजून जिवो आसा; हांव मरपापयलीं वचून ताका पळयतलों.'" },
  ],
  "46": [
    { type: "section", text: "याकोब ईजिप्ताक गेलो" },
    { type: "verse", num: 1, text: "आनी इस्राएल आपलेकडेन जें कितें आसलें तें सगळें घेवन वाटेक लागलो, आनी बेर-शेबाक पावलो, आनी आपल्या बापाय इसाकाच्या देवाक बली दिल्यो." },
    { type: "verse", num: 2, text: "आनी देवान रातीच्या दर्शनांत इस्राएलाक उलयलो आनी म्हणलें, 'याकोब, याकोब.' आनी ताणें म्हणलें, 'हांव हांगा आसां.'" },
    { type: "verse", num: 3, text: "आनी ताणें म्हणलें, 'हांव देव, तुज्या बापायचो देव; ईजिप्ताक देंवपाक भियेंव नाका; कारण हांव थंय तुका एक व्हड राश्ट्र करतलों.'" },
    { type: "verse", num: 4, text: "'हांव तुजेकडेन ईजिप्ताक देंवतलों, आनी हांव खात्रीन तुका वयर परत हाडतलों; आनी योसेफ आपलो हात तुज्या दोळ्यांचेर दवरतलो.'" },
    { type: "verse", num: 5, text: "आनी याकोब बेर-शेबांतल्यान उठलो; आनी इस्राएलाच्या पुतांनी आपल्या बापाय याकोबाक, आनी आपलीं भुरगीं, आनी आपल्यो बायलो, फारोन ताका व्हरपाक धाडिल्ल्या गाडयांनी व्हरलो." },
    { type: "verse", num: 6, text: "आनी तांणीं आपलीं गोरवां आनी कनान देसांत जोडिल्ली संपत्ती घेतली, आनी ईजिप्ताक आयले, याकोब आनी ताची सगळी संतत." },
    { type: "verse", num: 7, text: "ताचे पूत, आनी ताच्या पुतांचे पूत, ताच्यो धुवो, आनी ताच्या पुतांच्यो धुवो, आनी ताची सगळी संतत ताणें आपणेकडेन ईजिप्ताक हाडली." },
    { type: "verse", num: 8, text: "आनी ईजिप्ताक आयिल्ल्या इस्राएलाच्या पुतांचीं नांवां हीं, याकोब आनी ताचे पूत: याकोबाचो ज्येश्ट पूत रऊबेन." },
    { type: "verse", num: 9, text: "आनी रऊबेनाचे पूत: हनोख, पल्लू, हेस्रोन आनी कर्मी." },
    { type: "verse", num: 10, text: "आनी शिमोनाचे पूत: यमुएल, यामीन, ओहद, याखीन, सोहर आनी कनानी बायलेचो पूत शाऊल." },
    { type: "verse", num: 11, text: "आनी लेवीचे पूत: गेर्शोन, कहात आनी मरारी." },
    { type: "verse", num: 12, text: "आनी यहूदाचे पूत: एर, ओनान, शेला, पेरेस आनी जेरह; पूण एर आनी ओनान कनान देसांत मेले. आनी पेरेसाचे पूत हेस्रोन आनी हामूल." },
    { type: "verse", num: 13, text: "आनी इस्साखाराचे पूत: तोला, पुव्वा, योब आनी शिम्रोन." },
    { type: "verse", num: 14, text: "आनी जबुलोनाचे पूत: सेरेद, एलोन आनी याहलेएल." },
    { type: "verse", num: 15, text: "हे लेआचे पूत, जे तिणें पद्दन-अरामांत याकोबाक जल्मयले, आनी ताची धूव दीना; ताचे पूत आनी ताच्यो धुवो सगळे मेळून तेतीस." },
    { type: "verse", num: 16, text: "आनी गादाचे पूत: सिफ्योन, हग्गी, शूनी, एस्बोन, एरी, अरोदी आनी अरेली." },
    { type: "verse", num: 17, text: "आनी आशेराचे पूत: यिम्ना, यिश्वा, यिश्वी, बरीआ आनी तांची भयण सेरह. आनी बरीआचे पूत: हेबेर आनी मल्कीएल." },
    { type: "verse", num: 18, text: "हे जिल्पाचे पूत, जी लाबानान आपल्या धुवे लेआक दिल्ली; आनी हे तिणें याकोबाक जल्मयले, सोळा जीव." },
    { type: "verse", num: 19, text: "याकोबाच्या बायलेच्या राखेलाचे पूत: योसेफ आनी बिन्यामीन." },
    { type: "verse", num: 20, text: "आनी ईजिप्त देसांत योसेफाक मनश्शे आनी एफ्रायीम जल्मले, जे ओनाचो याजक पोतीफेराची धूव आसनत हिणें ताका जल्मयले." },
    { type: "verse", num: 21, text: "आनी बिन्यामीनाचे पूत: बेला, बेकेर, अश्बेल, गेरा, नामान, एही, रोश, मुप्पीम, हुप्पीम आनी अर्द." },
    { type: "verse", num: 22, text: "हे राखेलाचे पूत, जे तिणें याकोबाक जल्मयले; सगळे मेळून चवदा जीव." },
    { type: "verse", num: 23, text: "आनी दानाचे पूत: हूशीम." },
    { type: "verse", num: 24, text: "आनी नफ्तालीचे पूत: याहसेएल, गूनी, येसेर आनी शिल्लेम." },
    { type: "verse", num: 25, text: "हे बिल्हाचे पूत, जी लाबानान आपल्या धुवे राखेलाक दिल्ली; आनी हे तिणें याकोबाक जल्मयले; सगळे मेळून सात जीव." },
    { type: "verse", num: 26, text: "याकोबाच्या कुशींतल्यान आयिल्ले सगळे जीव जे ईजिप्ताक आयले, याकोबाच्या सुनांक सोडून, सगळे मेळून सासट जीव." },
    { type: "verse", num: 27, text: "आनी ईजिप्तांत योसेफाक जल्मिल्ले पूत दोन; याकोबाच्या घराण्यांतले जे ईजिप्ताक आयले ते सगळे मेळून सत्तर जीव." },
    { type: "verse", num: 28, text: "आनी ताणें यहूदाक आपल्यामुखार योसेफाकडेन गोशेनाक वाट दाखोवपाक धाडलो; आनी ते गोशेन प्रांतांत पावले." },
    { type: "verse", num: 29, text: "आनी योसेफान आपलो रथ तयार केलो, आनी आपल्या बापाय इस्राएलाक गोशेनांत मेळपाक वयर गेलो; आनी ताका पळयतच ताच्या गळ्याक पडलो, आनी ताच्या गळ्याक बरोच वेळ रडलो." },
    { type: "verse", num: 30, text: "आनी इस्राएलान योसेफाक म्हणलें, 'आतां म्हाका मरूंदी, कारण हांवें तुजें तोंड पळयलें, तूं अजून जिवो आसा.'" },
    { type: "verse", num: 31, text: "आनी योसेफान आपल्या भावांक आनी आपल्या बापायच्या घराण्याक म्हणलें, 'हांव वयर वचून फारोक सांगतलों, म्हजे भाव आनी म्हज्या बापायचें घराणें, जे कनान देसांत आसले, ते म्हजेकडेन आयलात.'" },
    { type: "verse", num: 32, text: "'आनी ते मनीस गोरवां चरोवपी, कारण ते गुराखी; आनी तांणीं आपलीं मेंढरां आनी गोरवां आनी तांचेकडेन जें कितें आसा तें हाडलां.'" },
    { type: "verse", num: 33, text: "'आनी फारो तुमकां आपयतलो आनी म्हणतलो, तुमचें काम कितें?'" },
    { type: "verse", num: 34, text: "'तेन्ना तुमी म्हणात, तुजे चाकर ल्हानपणापसून आतांमेरेन गुराखी, आमी आनी आमचे पूर्वज दोगूय; म्हणचे तुमी गोशेन प्रांतांत रावतलात; कारण सगळे गोरवां चरोवपी ईजिप्ती लोकांक घृणेचे.'" },
  ],
  "47": [
    { type: "section", text: "याकोब ईजिप्तांत" },
    { type: "verse", num: 1, text: "तेन्ना योसेफ फारोकडेन गेलो आनी ताका सांगलें, 'म्हजो बापय आनी म्हजे भाव, तांचीं मेंढरां आनी गोरवां आनी तांचेकडेन जें कितें आसा तें सगळें घेवन कनान देसांतल्यान आयलात; आनी पळय, ते गोशेन प्रांतांत आसात.'" },
    { type: "verse", num: 2, text: "आनी आपल्या भावांमदल्या पांच जणांक घेवन फारोमुखार दवरलें." },
    { type: "verse", num: 3, text: "आनी फारोन ताच्या भावांक म्हणलें, 'तुमचें काम कितें?' आनी तांणीं फारोक म्हणलें, 'तुजे चाकर गुराखी, आमी आनी आमचे पूर्वज दोगूय.'" },
    { type: "verse", num: 4, text: "आनी तांणीं फारोक म्हणलें, 'देसांत परदेशी जावन रावपाक आमी आयलात; कारण कनान देसांत दुकळ कठीण आसा, आनी तुज्या चाकरांच्या मेंढरांक चरपाक चारो ना; आतां तुजे चाकर गोशेन प्रांतांत रावूंदीत.'" },
    { type: "verse", num: 5, text: "आनी फारोन योसेफाक उलयलो आनी म्हणलें, 'तुजो बापय आनी तुजे भाव तुजेकडेन आयलात.'" },
    { type: "verse", num: 6, text: "'ईजिप्त देस तुजेमुखार आसा; देसांतल्या बऱ्या सुवातेर तुज्या बापायक आनी तुज्या भावांक रावय; ते गोशेन प्रांतांत रावूंदीत; आनी तांचेमदीं तांक आशिल्ले मनीस आसात म्हूण तुका कळटा जाल्यार, तांकां म्हज्या गोरवांचेर मुखेली कर.'" },
    { type: "verse", num: 7, text: "आनी योसेफान आपल्या बापाय याकोबाक भितर हाडलो आनी फारोमुखार दवरलो; आनी याकोबान फारोक आशीर्वाद दिलो." },
    { type: "verse", num: 8, text: "आनी फारोन याकोबाक म्हणलें, 'तुज्या जिविताचीं वर्सां किती?' " },
    { type: "verse", num: 9, text: "आनी याकोबान फारोक म्हणलें, 'म्हज्या परदेशी वसतीच्या दिसांचीं वर्सां एकशें तीस; म्हज्या जिविताचे दीस थोडे आनी वायट जाले, आनी म्हज्या पूर्वजांच्या परदेशी वसतीच्या दिसांच्या वर्सांमेरेन पावले नात.'" },
    { type: "verse", num: 10, text: "आनी याकोबान फारोक आशीर्वाद दिलो, आनी फारोमुखार भायर गेलो." },
    { type: "verse", num: 11, text: "आनी योसेफान आपल्या बापायक आनी आपल्या भावांक ईजिप्त देसांत रावय केलें, आनी तांकां देसांतल्या बऱ्या सुवातेर, रामसेस प्रांतांत, फारोन आज्ञा दिल्लेप्रमाणें जमीन दिली." },
    { type: "verse", num: 12, text: "आनी योसेफान आपल्या बापायक आनी आपल्या भावांक आनी आपल्या बापायच्या सगळ्या घराण्याक, तांच्या भुरग्यांप्रमाणें, अन्नान पोसलें." },
    { type: "verse", num: 13, text: "आनी सगळ्या देसांत अन्न नासलें; कारण दुकळ खूब कठीण आसलो; आनी ईजिप्त देस आनी कनान देस दुकळान सुकले." },
    { type: "verse", num: 14, text: "आनी ईजिप्त देसांत आनी कनान देसांत आशिल्ले सगळे पयशे योसेफान जमा केले, ते विकत घेताल्या धान्यांक; आनी योसेफान ते पयशे फारोच्या घरांत हाडले." },
    { type: "verse", num: 15, text: "आनी ईजिप्त देसांत आनी कनान देसांत पयशे सोपले तेन्ना, सगळे ईजिप्ती योसेफाकडेन आयले आनी म्हणाले, 'आमकां अन्न दी; आमचे पयशे सोपलात म्हूण तुजेमुखार आमी कित्याक मरूं?'" },
    { type: "verse", num: 16, text: "आनी योसेफान म्हणलें, 'तुमचीं गोरवां दियात; आनी तुमचे पयशे सोपलात जाल्यार तुमच्या गोरवांक हांव तुमकां अन्न दितलों.'" },
    { type: "verse", num: 17, text: "आनी तांणीं आपलीं गोरवां योसेफाकडेन हाडलीं; आनी योसेफान तांकां घोडे, मेंढरां, गोरवां आनी गाडवां दिल्ल्यांक अन्न दिलें; आनी त्या वर्सा तांच्या सगळ्या गोरवांक लागून तांकां अन्नान पोसलें." },
    { type: "verse", num: 18, text: "आनी तें वर्स सोपलें, आनी दुसऱ्या वर्सा ते ताचेकडेन आयले आनी ताका म्हणाले, 'म्हज्या धन्यापसून आमी लिपोवपाक शकनात, आमचे पयशे सोपलात; आनी गोरवांचे कळप म्हज्या धन्याचे; म्हज्या धन्यामुखार आमचीं शरीरां आनी आमच्यो जमनी सोडून कांयच उरलें ना.'" },
    { type: "verse", num: 19, text: "'तुज्या दोळ्यांमुखार आमी कित्याक मरूं, आमी आनी आमची जमीन दोनूय? आमकां आनी आमची जमीन अन्नाक विकत घे; आनी आमी आनी आमची जमीन फारोचे गुलाम जातले; आनी बियो दी, म्हणचे आमी जगूया आनी मरचीं ना, आनी जमीन ओसाड जावची ना.'" },
    { type: "verse", num: 20, text: "आनी योसेफान ईजिप्तांतली सगळी जमीन फारोक विकत घेतली; कारण दुकळ तांचेर कठीण जाल्लो, ईजिप्ती दरेकल्यान आपलें शेत विकलें; आनी जमीन फारोची जाली." },
    { type: "verse", num: 21, text: "आनी लोकांक ताणें ईजिप्ताच्या एका शेवटापसून दुसऱ्या शेवटामेरेन शारांनी हालयलें." },
    { type: "verse", num: 22, text: "फकत याजकांची जमीन ताणें विकत घेतली ना; कारण याजकांक फारोकडल्यान वांटो आसलो, आनी फारोन तांकां दिल्ल्या वांट्याचेर ते जगताले; देखून तांणीं आपली जमीन विकली ना." },
    { type: "verse", num: 23, text: "तेन्ना योसेफान लोकांक म्हणलें, 'पळय, आज हांवें तुमकां आनी तुमची जमीन फारोक विकत घेतल्या; पळय, तुमकां बियो, जमनीत पेरात.'" },
    { type: "verse", num: 24, text: "'आनी कापणीच्या वेळार, पांचवो वांटो तुमी फारोक दितलात, आनी चार वांटे तुमचे आसतले, शेतांत बियांक, आनी तुमच्या खाणावळीक, आनी तुमच्या घरांतल्यांक, आनी तुमच्या भुरग्यांक खावपाक.'" },
    { type: "verse", num: 25, text: "आनी तांणीं म्हणलें, 'तूं आमचे जीव वाचयले; म्हज्या धन्याच्या दोळ्यांत आमकां कुर्पा मेळूंदी, आनी आमी फारोचे गुलाम जातले.'" },
    { type: "verse", num: 26, text: "आनी योसेफान ईजिप्ताच्या जमनीविशीं कायदो केलो, आज मेरेन, पांचवो वांटो फारोचो; फकत याजकांची जमीन फारोची जाली ना." },
    { type: "verse", num: 27, text: "आनी इस्राएल ईजिप्त देसांत, गोशेन प्रांतांत रावलो; आनी तांणीं ताचेंत जमीन घेतली, आनी फळां दिलीं आनी खूब वाडले." },
    { type: "verse", num: 28, text: "आनी याकोब ईजिप्त देसांत सतरा वर्सां जगलो; अशें याकोबाच्या जिविताचीं वर्सां एकशें सत्तेचाळीस जालीं." },
    { type: "verse", num: 29, text: "आनी इस्राएलाचो मरपाचो वेळ लागीं आयलो; आनी ताणें आपल्या पुता योसेफाक आपयलो आनी ताका म्हणलें, 'म्हज्या दोळ्यांत तुका कुर्पा मेळ्ळ्या जाल्यार, तुजो हात म्हज्या मांडयेपंदा दवर, आनी म्हजेर दया आनी सत्य कर; म्हाका ईजिप्तांत पुरूं नाका.'" },
    { type: "verse", num: 30, text: "'पूण हांव म्हज्या पूर्वजांकडेन निदतलों तेन्ना, म्हाका ईजिप्तांतल्यान व्हर आनी तांच्या थडग्यांत पूर.' आनी ताणें म्हणलें, 'तूं सांगता तशें हांव करतलों.'" },
    { type: "verse", num: 31, text: "आनी ताणें म्हणलें, 'म्हाका शपत घाल.' आनी ताणें ताका शपत घाली. आनी इस्राएलान खाटीच्या तकलेलागीं नमन केलें." },
  ],
  "48": [
    { type: "section", text: "याकोबान योसेफाच्या पुतांक आशीर्वाद दिलो" },
    { type: "verse", num: 1, text: "आनी ह्या गजालींउपरांत, कोणेतरी योसेफाक सांगलें, 'पळय, तुजो बापय दुयेंत आसा.' आनी ताणें आपले दोन पूत मनश्शे आनी एफ्रायीम आपणेकडेन घेतले." },
    { type: "verse", num: 2, text: "आनी याकोबाक सांगलें, 'पळय, तुजो पूत योसेफ तुजेकडेन येता.' आनी इस्राएलान आपणाक बळ दिलें आनी खाटीचेर बसलो." },
    { type: "verse", num: 3, text: "आनी याकोबान योसेफाक म्हणलें, 'सर्वशक्तिमान देव कनान देसांतल्या लूजांत म्हाका दिसलो, आनी म्हाका आशीर्वाद दिलो.'" },
    { type: "verse", num: 4, text: "'आनी म्हाका म्हणलें, पळय, हांव तुका फळां दितलों आनी तुका वाडयतलों, आनी तुजेपसून लोकांचो समुदाय करतलों, आनी हो देस तुज्या उपरांत तुज्या संततीक सदांकाळ दितलों.'" },
    { type: "verse", num: 5, text: "'आनी आतां तुजे दोन पूत, जे ईजिप्त देसांत हांव तुजेकडेन येवपापयलीं तुका जल्मले, ते म्हजे; एफ्रायीम आनी मनश्शे रऊबेन आनी शिमोनासारके म्हजे जातले.'" },
    { type: "verse", num: 6, text: "'आनी तांचे उपरांत तुका जल्मतलीं तुजीं भुरगीं तुजीं जातलीं; तांचो वांटो तांच्या भावांच्या नांवान आसतलो.'" },
    { type: "verse", num: 7, text: "'आनी हांव पद्दन-अरामांतल्यान येताना, कनान देसांत एफ्रातेक पावपाक अजून थोडी वाट आसताना राखेल म्हजेलागीं मेली; आनी हांवें तिका एफ्राताच्या, म्हणल्यार बेथलेहेमाच्या वाटेर पुरली.'" },
    { type: "verse", num: 8, text: "आनी इस्राएलान योसेफाच्या पुतांक पळयलें आनी म्हणलें, 'हे कोण?'" },
    { type: "verse", num: 9, text: "आनी योसेफान आपल्या बापायक म्हणलें, 'हे म्हजे पूत, जे देवान म्हाका हांगा दिलात.' आनी ताणें म्हणलें, 'तांकां म्हजेकडेन हाड, म्हणचे हांव तांकां आशीर्वाद दितलों.'" },
    { type: "verse", num: 10, text: "आनी इस्राएलाचे दोळे म्हातारपणान जड जाल्ले, ताका पळोवपाक जायनासलें. आनी ताणें तांकां ताचेलागीं हाडलें; आनी ताणें तांकां उमो दिलो आनी तांकां वेंगेंत घेतलें." },
    { type: "verse", num: 11, text: "आनी इस्राएलान योसेफाक म्हणलें, 'तुजें तोंड पळोवपाक मेळटलें म्हूण हांवें चिंतिल्लें ना; आनी पळय, देवान म्हाका तुजी संततय दाखयल्या.'" },
    { type: "verse", num: 12, text: "आनी योसेफान तांकां ताच्या दिंबयांमदल्यान काडलें, आनी भुंयेमेरेन तोंडार नमन केलें." },
    { type: "verse", num: 13, text: "आनी योसेफान तांकां दोगांयक घेतलें, एफ्रायीमाक आपल्या उज्व्या हातान इस्राएलाच्या दाव्या हाताक, आनी मनश्शेक आपल्या दाव्या हातान इस्राएलाच्या उज्व्या हाताक, आनी तांकां ताचेलागीं हाडलें." },
    { type: "verse", num: 14, text: "आनी इस्राएलान आपलो उजवो हात लांब केलो, आनी एफ्रायीमाच्या तकलेर दवरलो, तो ल्हान आसलो; आनी आपलो दावो हात मनश्शेच्या तकलेर दवरलो, आपले हात जाणून बदलून; कारण मनश्शे ज्येश्ट आसलो." },
    { type: "verse", num: 15, text: "आनी ताणें योसेफाक आशीर्वाद दिलो आनी म्हणलें, 'देव ज्याचेमुखार म्हजे पूर्वज अब्राहाम आनी इसाक चलले, देव जाणें म्हजो सगळो जीवभर आज मेरेन पोसलो,'" },
    { type: "verse", num: 16, text: "'दूत जाणें म्हाका सगळ्या वायटापसून सोडयलो, ह्या भुरग्यांक आशीर्वाद दिवं; आनी तांचेर म्हजें नांव आनी म्हज्या पूर्वजां अब्राहाम आनी इसाक हांचें नांव आसूं; आनी ते पृथ्वीचेर खूब वाडूंत.'" },
    { type: "verse", num: 17, text: "आनी ताच्या बापायन आपलो उजवो हात एफ्रायीमाच्या तकलेर दवरलो तें योसेफान पळयलें तेन्ना ताका वायट दिसलें; आनी ताणें आपल्या बापायचो हात एफ्रायीमाच्या तकलेवयल्यान मनश्शेच्या तकलेर दवरपाक ताचो हात धरलो." },
    { type: "verse", num: 18, text: "आनी योसेफान आपल्या बापायक म्हणलें, 'अशें न्हय, म्हज्या बापा; कारण हो ज्येश्ट; तुजो उजवो हात ताच्या तकलेर दवर.'" },
    { type: "verse", num: 19, text: "पूण ताच्या बापायन न्हय केलें, आनी म्हणलें, 'म्हाका कळटा, म्हज्या पुता, म्हाका कळटा; तोय एक लोक जातलो, आनी तोय व्हड जातलो; पूण ताचो ल्हान भाव ताचेपरस व्हड जातलो, आनी ताची संतत राश्ट्रांचो समुदाय जातलो.'" },
    { type: "verse", num: 20, text: "आनी त्या दिसा ताणें तांकां आशीर्वाद दिलो आनी म्हणलें, 'तुजेवरवीं इस्राएल आशीर्वाद दितलो, म्हणटलो: देव तुका एफ्रायीम आनी मनश्शेसारको करूं.' अशें ताणें एफ्रायीमाक मनश्शेमुखार दवरलो." },
    { type: "verse", num: 21, text: "आनी इस्राएलान योसेफाक म्हणलें, 'पळय, हांव मरतां; पूण देव तुमचेकडेन आसतलो, आनी तुमकां तुमच्या पूर्वजांच्या देसांत परत व्हरतलो.'" },
    { type: "verse", num: 22, text: "'आनी हांव तुका तुज्या भावांपरस एक वांटो चड दिता, जो हांवें अमोऱ्यांकडल्यान म्हज्या तरवारीन आनी म्हज्या धनुखान घेतलो.'" },
  ],
  "49": [
    { type: "section", text: "याकोबान आपल्या पुतांक आशीर्वाद दिलो" },
    { type: "verse", num: 1, text: "आनी याकोबान आपल्या पुतांक आपयलें आनी म्हणलें, 'एकठांय जायात, म्हणचे फुडल्या दिसांनी तुमकां कितें घडटलें तें हांव तुमकां सांगतलों.'" },
    { type: "verse", num: 2, text: "'जमा जायात आनी आयकात, याकोबाच्या पुतांनो; आनी तुमच्या बापाय इस्राएलाचें आयकात.'" },
    { type: "verse", num: 3, text: "'रऊबेन, तूं म्हजो ज्येश्ट, म्हजी तांक आनी म्हज्या शक्तीचें पयलें फळ, मानांत श्रेश्ट आनी बळांत श्रेश्ट.'" },
    { type: "verse", num: 4, text: "'उदकासारको अस्थिर, तूं श्रेश्ट आसचो ना; कारण तूं तुज्या बापायच्या खाटीचेर चडलो; तेन्ना तूं ताका बिगडायलें — म्हज्या खाटीचेर चडलो.'" },
    { type: "verse", num: 5, text: "'शिमोन आनी लेवी भाव; तांचीं हत्यारां हिंसेचीं.'" },
    { type: "verse", num: 6, text: "'म्हज्या जिवा, तांच्या मसलतींत भितर वचूं नाका; म्हज्या मानया, तांच्या सभेंत भरसूं नाका; कारण तांच्या रागान तांणीं मनीस मारले, आनी तांच्या मर्जेन बैलांचे शिरे कापले.'" },
    { type: "verse", num: 7, text: "'तांचो राग शापित, कारण तो कठीण; आनी तांचो क्रोध, कारण तो कडक. हांव तांकां याकोबांत वांटतलों, आनी इस्राएलांत पसरयतलों.'" },
    { type: "section", text: "यहूदाक आशीर्वाद" },
    { type: "verse", num: 8, text: "'यहूदा, तुजे भाव तुजी स्तुती करतले; तुजो हात तुज्या दुस्मानांच्या गळ्याचेर आसतलो; तुज्या बापायचे पूत तुजेमुखार नमतले.'" },
    { type: "verse", num: 9, text: "'यहूदा सिंहाचो पिलो; म्हज्या पुता, तूं शिकारीपसून वयर चडलो; तो बसलो, सिंहासारको निदलो, आनी सिंहीणीसारको; कोण ताका उठयतलो?'" },
    { type: "verse", num: 10, text: "'यहूदापसून राजदंड वचचो ना, आनी ताच्या पांयांमदल्यान आज्ञादंड वचचो ना, शिलो येमेरेन; आनी लोक ताचे आज्ञेक मानतले.'" },
    { type: "verse", num: 11, text: "'तो आपलो गाडवो द्राक्षवेलाक बांदता, आनी आपल्या गाडवीणीचो पिलो उत्तम द्राक्षवेलाक; तो आपलीं वस्त्रां दाक्यांत धुता, आनी आपलो अंगरखो द्राक्षाच्या रगतांत.'" },
    { type: "verse", num: 12, text: "'ताचे दोळे दाक्यांपरस तांबडे, आनी ताचे दांत दुदापरस धवे.'" },
    { type: "verse", num: 13, text: "'जबुलोन दर्याच्या देगेर रावतलो; आनी तो तारवांचो बंदर जातलो; आनी ताची शीम सीदोनामेरेन पावतली.'" },
    { type: "verse", num: 14, text: "'इस्साखार हाडांचो गाडव, दोन वोज्यांमदीं निदिल्लो.'" },
    { type: "verse", num: 15, text: "'आनी ताणें पळयलें विसव बरो, आनी देस रम्य; आनी ताणें वोजी व्हरपाक आपलो खांदो बागयलो, आनी वेठबिगारीचो गुलाम जालो.'" },
    { type: "verse", num: 16, text: "'दान आपल्या लोकांचो न्याय करतलो, इस्राएलाच्या वंशांतल्या एकासारको.'" },
    { type: "verse", num: 17, text: "'दान वाटेर सोरोप जातलो, पांयवाटेर नागीण, जी घोड्याच्या तोपांक चावता, म्हणचे ताचो स्वार फाटल्यान पडता.'" },
    { type: "verse", num: 18, text: "'सर्वेस्परा, तुज्या सुटकेची हांव वाट पळयतां.'" },
    { type: "verse", num: 19, text: "'गादाचेर सैन्य तुटून पडटलें; पूण तो तांच्या तोपांचेर तुटून पडटलो.'" },
    { type: "verse", num: 20, text: "'आशेराचें अन्न मोटें आसतलें, आनी तो राजाचें सुख दितलो.'" },
    { type: "verse", num: 21, text: "'नफ्ताली सोडिल्ली सारणी; तो सोबीत उतरां उलयता.'" },
    { type: "verse", num: 22, text: "'योसेफ फळां दिवपी फांदो, झऱ्यालागीं फळां दिवपी फांदो; ताचे फांदे वणतीवयल्यान वतात.'" },
    { type: "verse", num: 23, text: "'बाणवाल्यांनी ताका खूब त्रासिलो, आनी ताचेर बाण मारले, आनी ताचो द्वेश केलो.'" },
    { type: "verse", num: 24, text: "'पूण ताचो धनुखो खंबीर उरलो, आनी ताच्या हातांचे बाहू याकोबाच्या बळिश्ट देवाच्या हातांनी बळकट जाले; थंयसून इस्राएलाचो गोरवांचो मेंढरांचो राखणार, फातर येता.'" },
    { type: "verse", num: 25, text: "'तुज्या बापायच्या देवापसून — तो तुका आदार करतलो — आनी सर्वशक्तिमानापसून — तो तुका वयल्या ससर्गाचे आशीर्वाद, सकयल आशिल्ल्या खोलाचे आशीर्वाद, कुशींचे आनी गर्भाचे आशीर्वाद दितलो.'" },
    { type: "verse", num: 26, text: "'तुज्या बापायचे आशीर्वाद सनातन दोंगरांपरस उंच, चिरंतन टेकड्यांच्या मोलापरस व्हड; ते योसेफाच्या तकलेचेर, आपल्या भावांमदल्या राजकुमाराच्या माथ्याचेर आसूंदीत.'" },
    { type: "verse", num: 27, text: "'बिन्यामीन फाडपी लांडगो; सकाळीं तो शिकार खातलो, आनी सांजच्यान तो लूट वांटतलो.'" },
    { type: "verse", num: 28, text: "हे सगळे इस्राएलाचे बारा वंश; आनी हें ताच्या बापायन तांकां सांगिल्लें, तेन्ना ताणें तांकां आशीर्वाद दिलो; दरेकल्याक ताच्या आशीर्वादाप्रमाणें ताणें आशीर्वाद दिलो." },
    { type: "section", text: "याकोबाचो मरण" },
    { type: "verse", num: 29, text: "आनी ताणें तांकां आज्ञा दिली आनी म्हणलें, 'हांव म्हज्या लोकांक मेळपाक वतां; म्हाका हित्ती एफ्रोनाच्या शेतांतल्या गुंफेंत म्हज्या पूर्वजांलागीं पुरात.'" },
    { type: "verse", num: 30, text: "'कनान देसांतल्या मम्रेमुखार मकपेलाच्या शेतांतल्या गुंफेंत, जी अब्राहामान थडग्यासाठीं ती जमीन हित्ती एफ्रोनाकडल्यान विकत घेतली.'" },
    { type: "verse", num: 31, text: "'थंय अब्राहाम आनी ताची बायल सारा पुरले; थंय इसाक आनी ताची बायल रिबका पुरले; आनी थंय हांवें लेआक पुरली.'" },
    { type: "verse", num: 32, text: "'शेत आनी ताचेंतली गुंफा हेताच्या पुतांकडल्यान विकत घेतिल्ली.'" },
    { type: "verse", num: 33, text: "आनी याकोबान आपल्या पुतांक आज्ञा दिवन सोपयली, आनी आपले पांय खाटीचेर ओडून घेतले, आनी प्राण सोडलो, आनी आपल्या लोकांक मेळ्ळो." },
  ],
  "50": [
    { type: "section", text: "याकोबाचें अंत्यसंस्कार" },
    { type: "verse", num: 1, text: "आनी योसेफ आपल्या बापायच्या तोंडार पडलो, आनी ताचेर रडलो, आनी ताका उमो दिलो." },
    { type: "verse", num: 2, text: "आनी योसेफान आपल्या चाकरांक, वैद्यांक, आपल्या बापायक सुगंधी करपाक आज्ञा दिली; आनी वैद्यांनी इस्राएलाक सुगंधी केलो." },
    { type: "verse", num: 3, text: "आनी ताका चाळीस दीस लागले; कारण सुगंधी करपाक तितलेच दीस लागताले; आनी ईजिप्ती लोकांनी ताका सत्तर दीस शोक केलो." },
    { type: "verse", num: 4, text: "आनी ताचो शोक सोपलो तेन्ना, योसेफान फारोच्या घराण्याक उलयलो, 'म्हज्या दोळ्यांत तुमकां कुर्पा मेळ्ळ्या जाल्यार, फारोच्या कानांत सांगात:'" },
    { type: "verse", num: 5, text: "'म्हज्या बापायन म्हाका शपत घाली आनी म्हणलें, पळय, हांव मरतां; कनान देसांत हांवें आपल्याक खणिल्ल्या थडग्यांत म्हाका पूर. आतां म्हाका वयर वचूंदी आनी म्हज्या बापायक पुरूंदी, आनी हांव परत येतलों.'" },
    { type: "verse", num: 6, text: "आनी फारोन म्हणलें, 'वयर वच आनी तुज्या बापायन तुका शपत घालिल्लेप्रमाणें ताका पूर.'" },
    { type: "verse", num: 7, text: "आनी योसेफ आपल्या बापायक पुरपाक वयर गेलो; आनी ताचेकडेन फारोचे सगळे चाकर गेले, ताच्या घराचे वडील, आनी ईजिप्त देसाचे सगळे वडील," },
    { type: "verse", num: 8, text: "आनी योसेफाचें सगळें घराणें, आनी ताचे भाव, आनी ताच्या बापायचें घराणें; फकत तांचीं भुरगीं, तांचीं मेंढरां आनी गोरवां तांणीं गोशेन प्रांतांत दवरलीं." },
    { type: "verse", num: 9, text: "आनी रथ आनी घोडेस्वार ताचेकडेन वयर गेले; आनी तो खूब व्हड जमो आसलो." },
    { type: "verse", num: 10, text: "आनी ते यॉर्दन पलतडच्या आताद खळ्यार पावले, आनी थंय ते खूब व्हड शोकान रडले; आनी ताणें आपल्या बापायक सात दीस शोक केलो." },
    { type: "verse", num: 11, text: "आनी देसांतल्या रहिवाशांनी, कनानींनी, आताद खळ्यार शोक पळयलो तेन्ना म्हणाले, 'ईजिप्ती लोकांचो हो व्हड शोक.' देखून ताचें नांव आबेल-मिस्रयीम दवरलें, जें यॉर्दन पलतडीं आसा." },
    { type: "verse", num: 12, text: "आनी ताच्या पुतांनी ताणें तांकां आज्ञा दिल्लेप्रमाणें केलें." },
    { type: "verse", num: 13, text: "ताच्या पुतांनी ताका कनान देसांत व्हरलो, आनी मम्रेमुखार मकपेलाच्या शेतांतल्या गुंफेंत पुरलो, जी अब्राहामान थडग्यासाठीं हित्ती एफ्रोनाकडल्यान विकत घेतिल्ली." },
    { type: "verse", num: 14, text: "आनी योसेफ आपल्या बापायक पुरिल्या उपरांत ईजिप्ताक परतलो, तो आनी ताचे भाव आनी ताच्या बापायक पुरपाक ताचेकडेन वयर गेल्ले सगळे." },
    { type: "section", text: "योसेफान आपल्या भावांक भरवसो दिलो" },
    { type: "verse", num: 15, text: "आनी योसेफाच्या भावांनी पळयलें तांचो बापय मेलो, आनी म्हणाले, 'कदाचीत योसेफ आमकां द्वेश करतलो, आनी आमी ताका केल्लें सगळें वायट खात्रीन आमकां परत दितलो.'" },
    { type: "verse", num: 16, text: "आनी तांणीं योसेफाक निरोप धाडलो, 'तुज्या बापायन मरपापयलीं आज्ञा दिली:'" },
    { type: "verse", num: 17, text: "'योसेफाक अशें सांगात: तुज्या भावांचो अपराध आनी तांचें पातक भोगस, कारण तांणीं तुका वायट केलें. आतां तुज्या बापायच्या देवाच्या चाकरांचो अपराध भोगस.' आनी योसेफ तांचीं उतरां आयकून रडलो." },
    { type: "verse", num: 18, text: "आनी ताचे भाव गेले आनी ताचेमुखार पडले आनी म्हणाले, 'पळय, आमी तुजे गुलाम.'" },
    { type: "verse", num: 19, text: "आनी योसेफान तांकां म्हणलें, 'भियेनाकात; कारण हांव देवाच्या सुवातेर आसां?' " },
    { type: "verse", num: 20, text: "'तुमी म्हजेआड वायट चिंतलें; पूण देवान तें बऱ्याक चिंतलें, आज आसा तशें जायते लोक जिवे उरोवपाक.'" },
    { type: "verse", num: 21, text: "'आतां भियेनाकात; हांव तुमकां आनी तुमच्या भुरग्यांक पोसतलों.' आनी ताणें तांकां भुजयलें आनी तांच्या काळजांक उतरां उलयलो." },
    { type: "section", text: "योसेफाचो मरण" },
    { type: "verse", num: 22, text: "आनी योसेफ ईजिप्तांत रावलो, तो आनी ताच्या बापायचें घराणें; आनी योसेफ एकशें धा वर्सां जगलो." },
    { type: "verse", num: 23, text: "आनी योसेफान एफ्रायीमाच्या भुरग्यांक तिसऱ्या पिळगेमेरेन पळयलें; आनी मनश्शेच्या पुता माखीराचीं भुरगींय योसेफाच्या दिंबयांचेर जल्मलीं." },
    { type: "verse", num: 24, text: "आनी योसेफान आपल्या भावांक म्हणलें, 'हांव मरतां; पूण देव खात्रीन तुमची भेट घेतलो, आनी तुमकां ह्या देसांतल्यान अब्राहाम, इसाक आनी याकोबाक शपत घालिल्ल्या देसांत व्हरतलो.'" },
    { type: "verse", num: 25, text: "आनी योसेफान इस्राएलाच्या पुतांक शपत घाली आनी म्हणलें, 'देव खात्रीन तुमची भेट घेतलो; आनी तुमी म्हजीं हाडां हांगासून वयर व्हरात.'" },
    { type: "verse", num: 26, text: "अशें योसेफ एकशें धा वर्सांचो आसताना मेलो; आनी ताका सुगंधी केलो, आनी ईजिप्तांत पेटयेंत दवरलो." },
  ],
};
